-- Poems batch 181
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('b42089cd-dfee-4122-8508-6e831b9fbf51','次韵斯遠和答昌甫讀謫仙詩  其三','韓淲','宋','宋诗','song-poetry','','[]','矯首靈山南，遠目水溪東。',72,'全唐诗/poet.song.176000.json','["矯首靈山南，遠目水溪東。", "溪山春正濃，勝事還當窮。", "佳人天一方，欲見無由逢。", "倚樓與下榻，二士騰高風。", "安得兩鳬舄，或杖一枝筇。", "遊戲相徵逐，老我百歲中。"]'),
('c51fd2f4-2d13-447d-b12d-a39daf512de5','讀韋蘇州詩呈申之兼示八姪直之','韓淲','宋','宋诗','song-poetry','','[]','結髮遊上國，煌煌開吳京。',84,'全唐诗/poet.song.176000.json','["結髮遊上國，煌煌開吳京。", "州檄易湖海，所至塵慮嬰。", "焉知二十載，潦倒還重經。", "親黨勞行役，朋來展交情。", "登臨共翔集，離闊獨怔營。", "暑氣曉猶斂，堤水散新萍。", "得理景無違，安時事逾輕。"]'),
('a6a24afd-6431-4def-93ab-03c34747bf1a','五思  其一','韓淲','宋','宋诗','song-poetry','','[]','我思列岫亭，秋光滿靈山。',72,'全唐诗/poet.song.176000.json','["我思列岫亭，秋光滿靈山。", "地高出林蕩，下視城邑間。", "有時坐終日，鄰僧亦往還。", "屋頭木蓊蓊，砌下菊斑斑。", "放此麋鹿心，鍊彼冰雪顔。", "今日復何日，驅馳未能閑。"]'),
('06aa35a0-cc19-4396-a1d6-5b68ece9f57e','五思  其二','韓淲','宋','宋诗','song-poetry','','[]','我思南澗水，秋雨漲白蘋。',72,'全唐诗/poet.song.176000.json','["我思南澗水，秋雨漲白蘋。", "但見禽鳥啼，少值城市人。", "倚杖獨照影，幽懷寄閑身。", "潺潺瀉塵舊，汩汩來清新。", "濯纓江濱漁，洗耳潁陽真。", "長安多飛埃，乃復在茲辰。"]'),
('dc48f2e1-e885-4bad-9c19-763372ab5fa5','五思  其三','韓淲','宋','宋诗','song-poetry','','[]','我思靈井幽，山圍路高遠。',72,'全唐诗/poet.song.176000.json','["我思靈井幽，山圍路高遠。", "青山四面合，風聲自迴返。", "時携一尊酒，坐石至昏晚。", "嵐光發深竇，翠色明絕巘。", "荒寒集鷳鷓，淵澄見鱨鰋。", "年來事寸祿，捫心愧嵇阮。"]'),
('fa0f329f-8ff9-4c85-a7a1-7aa989e6a90c','五思  其四','韓淲','宋','宋诗','song-poetry','','[]','我思玉溪流，松山日涵碧。',72,'全唐诗/poet.song.176000.json','["我思玉溪流，松山日涵碧。", "舟人相上下，檣竿倚沙石。", "出門無百步，飯飽時散策。", "波寒逼衣屨，空翠潤巾幗。", "道上逢漁樵，庵前唯道釋。", "此趣久已成，何因甘役役。"]'),
('202afc29-3653-457f-8041-70fb953d9e97','五思  其五','韓淲','宋','宋诗','song-poetry','','[]','我思鶴山路，田間望青蒼。',72,'全唐诗/poet.song.176000.json','["我思鶴山路，田間望青蒼。", "忽到絕壁下，春風散林芳。", "氣煖石色潤，崖穴如蜂房。", "想像仙人來，宜有隠者藏。", "泉鳴萬丈淵，雲遶千仞崗。", "老矣當結茅，無爲戀周行。"]'),
('f864d806-2b8b-4ca8-b098-dd721869e4a0','滕黄梅遺鮑參軍集','韓淲','宋','宋诗','song-poetry','','[]','商秋散驚飈，嘉客木蘭舟。',48,'全唐诗/poet.song.176000.json','["商秋散驚飈，嘉客木蘭舟。", "停橈以遵渚，意邈語綢繆。", "遺我鮑照詩，遐歎睇前修。", "徂年易爲急，憫默涇渭流。"]'),
('20d1c332-4058-471a-865c-7ae9e3e58617','閑借雲笈七籤','韓淲','宋','宋诗','song-poetry','','[]','一從寇謙之，祖尚張道陵。',96,'全唐诗/poet.song.176000.json','["一從寇謙之，祖尚張道陵。", "湮蕪五千言，莊列亦不明。", "荒哉神仙家，方伎劉向評。", "存想與爐竈，後世徒營營。", "吾從雲笈書，七籤豈其情。", "山閒焚妙香，君房天禧經。", "叩齒理玉池，天風韵流鈴。", "玉歷眇延康，塵劫無足驚。"]'),
('9b44b4d8-9d1a-4c5c-a3ad-f9bc889bb302','自庫中歸翻書有感','韓淲','宋','宋诗','song-poetry','','[]','身形厭老大，急以書自娛。',48,'全唐诗/poet.song.176000.json','["身形厭老大，急以書自娛。", "經史隨手翻，於我皆不虛。", "彼人骨已朽，今人復何如。", "百年皆强營，聖賢豈非疎。"]'),
('e9b3d0c6-f14a-42da-87fe-d55ef60b1b2e','章撫幹詩編','韓淲','宋','宋诗','song-poetry','','[]','詩道古所重，詩篇今不難。',120,'全唐诗/poet.song.176000.json','["詩道古所重，詩篇今不難。", "寂寥建安來，尚有李杜壇。", "齊梁小兒體，往往不足觀。", "君侯賢關秀，磊落夜光寒。", "簸弄豪俠窟，洗滌儒腐酸。", "連編忽墮前，惘然失悲歡。", "金華三洞高，東流五百灘。", "乃能收拾之，盡歸一毫端。", "惜我保社人，未同把檀欒。", "揮絃送飛鴻，悠悠發清彈。"]'),
('7a45bfb0-abd5-45e4-a68d-1f1c67abdd90','書林','韓淲','宋','宋诗','song-poetry','','[]','盧仝五千卷，鄴侯三萬軸。',168,'全唐诗/poet.song.176000.json','["盧仝五千卷，鄴侯三萬軸。", "二人書雖多，顛倒俱在腹。", "吾當思其然，豈肯汎然讀。", "李侯真名家，玉川惟破屋。", "至今數唐賢，未易可追逐。", "誰謂柯山西，魏氏追望族。", "衣冠照樓觀，再世新卜築。", "中有簡編地，仍復種修竹。", "斯遠吾所敬，作記不碌碌。", "發揮書林趣，足以濯心目。", "偉哉父子間，抱負如韞櫝。", "要當大所施，致主錫民福。", "想見翻經時，一下十行速。", "先得我心同，聞韶心忘肉。"]'),
('2815b02d-cdf0-4626-97d0-7c96bbf0a72b','黄子功云入吳曬書因以詒之','韓淲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','吾人聚集地，常刺俗子眼。',96,'全唐诗/poet.song.176000.json','["吾人聚集地，常刺俗子眼。", "過豈彼之是，亦乃此之簡。", "君行往西湖，曬書理碑版。", "必入鵷鷺羣，百事當一莞。", "所抱才志高，天衢復何赧。", "勿謂舍瑟希，異乎三子撰。", "清風炫崇桃，遽爾疎酒盞。", "其與物爲春，至道嫌擇揀。"]'),
('c5739e42-23d6-4c5a-9a6c-d2ef962ab59b','夜過霞山看趙百醉詩刻及諸名勝跋語  其一','韓淲','宋','宋诗','song-poetry','','[]','撫我百醉詩，把此一盃酒。',48,'全唐诗/poet.song.176000.json','["撫我百醉詩，把此一盃酒。", "水南撼霜飈，山月復在牖。", "禪家話三三，伯主約九九。", "得友良獨難，呻吟倍搔首。"]'),
('d9675cf7-a60c-4708-acfe-e1bfd1202087','夜過霞山看趙百醉詩刻及諸名勝跋語  其二','韓淲','宋','宋诗','song-poetry','','[]','鐘聲殷空山，燈影照隻字。',48,'全唐诗/poet.song.176000.json','["鐘聲殷空山，燈影照隻字。", "區中無妙心，天外有能事。", "消長以隆替，昏旦而寤寐。", "白夫阮籍眼，擁矣謝安鼻。"]'),
('e30fc6a4-ba22-4086-bff9-eee4b426fd2f','題趙四行卷','韓淲','宋','宋诗','song-poetry','','[]','淡泊梅都官，苦硬孟東野。',48,'全唐诗/poet.song.176000.json','["淡泊梅都官，苦硬孟東野。", "韓歐舒而明，徐呂平而雅。", "健闊到應劉，高深望屈賈。", "章泉有斯人，身寄玉山下。"]'),
('cd788e36-6afc-4d8b-8a65-7820a46a4c20','近從校書得太玄今又得蜀本歐陽文','韓淲','宋','宋诗','song-poetry','','[]','本朝二百年，古文盛歐陽。',144,'全唐诗/poet.song.176000.json','["本朝二百年，古文盛歐陽。", "平生幾討論，皓首誦山房。", "誰知落宦網，不暇相携將。", "旦旦藥市遊，夜夜隘巷藏。", "黄沙撲几席，細塵污衣裳。", "欲從人乞之，囁嚅但徬徨。", "珍重李校書，愛我窮詞章。", "假借復取贈，轉覺厚意長。", "聊窮述作心，軻愈參翺翔。", "向來太玄經，遺我喜若狂。", "晝夜測中養，至今迷三方。", "二書或有盡，盛德胡能忘。"]'),
('360f0f66-9846-4dfa-a683-f39b7785fc09','僧窗觀斯遠諸公詩','韓淲','宋','宋诗','song-poetry','','[]','春風起春雪，山路寒陰陰。',48,'全唐诗/poet.song.176000.json','["春風起春雪，山路寒陰陰。", "梅花豈不開，立行尋我吟。", "同來者誰歟，林泉潔煩襟。", "摩挲僧窗題，悠悠故人心。"]'),
('597626a2-6065-4375-a9c6-f4119fa882e1','題梅溪橘閣詞','韓淲','宋','宋诗','song-poetry','','[]','霜葉柳塘風，烟蘂梅溪渡。',48,'全唐诗/poet.song.176000.json','["霜葉柳塘風，烟蘂梅溪渡。", "茅店問村醪，未許空歸去。", "倚杖小裴回，寫我吟邊句。", "醉眼復何之，落日孤鴻處。"]'),
('345a9bfc-6c5f-4f9f-996f-07e3afa75cb0','晁十哥出舊藏書畫','韓淲','宋','宋诗','song-poetry','','[]','因過竹院酒，共看竹院書。',96,'全唐诗/poet.song.176000.json','["因過竹院酒，共看竹院書。", "坐中半北客，南渡百年餘。", "葉大梔子肥，橘樹正扶疎。", "雲雷送風雨，微凉入衣裾。", "談諧各鋒起，才氣色敷腴。", "道古不如今，抱德或若愚。", "洗琖勿促迫，開襟且須臾。", "達人要領會，興逸奚可辜。"]'),
('974ecae1-9520-49d1-a89e-abe95b0eadb5','題趙希遠小景','韓淲','宋','宋诗','song-poetry','','[]','春風吹綠樹，占斷江頭路。',48,'全唐诗/poet.song.176000.json','["春風吹綠樹，占斷江頭路。", "水煖浴鴛鴦，汀沙澹吞吐。", "斷取置轉庵，又作筆下句。", "長安紅塵中，相對得幽趣。"]'),
('2900946d-f35d-446f-87ab-31c039405801','紀夢','韓淲','宋','宋诗','song-poetry','','[]','秋深夜自清，揚揚夢初成。',96,'全唐诗/poet.song.176000.json','["秋深夜自清，揚揚夢初成。", "短衣山麓間，羽客爭將迎。", "同行得佳伴，意氣還相傾。", "或有設食者，窗几皆虛明。", "恍然忽已覺，此身微官縈。", "只今閒且散，心胡爲未平。", "尚復带孥累，徒羨高舉輕。", "方外多高人，簞瓢思遠征。"]'),
('def725ea-face-4e08-9325-a1d71cece8de','懷古  其一','韓淲','宋','宋诗','song-poetry','','[]','近城人語雜，深山人語少。',48,'全唐诗/poet.song.176000.json','["近城人語雜，深山人語少。", "重露滴烟嵐，野水見魚鳥。", "稻粱豐稔外，耕鑿願溫飽。", "所以桃源人，不與外人道。"]'),
('78661f84-c645-41f3-8137-3415f15b46e9','懷古  其二','韓淲','宋','宋诗','song-poetry','','[]','少壯既奚爲，老矣復難强。',48,'全唐诗/poet.song.176000.json','["少壯既奚爲，老矣復難强。", "紫芝未必仙，采之亦可餉。", "耆耄八九十，道可無俯仰。", "所以商山人，辭漢寧獨往。"]'),
('03df037d-7bb4-4811-bed3-c3dbbf13ad8d','玉山村民斲石爲硯仲至以詩來索次韵','韓淲','宋','宋诗','song-poetry','','[]','誰歟賦奇詩，索我玉山研。',96,'全唐诗/poet.song.176000.json','["誰歟賦奇詩，索我玉山研。", "産石斲未久，所落荒野縣。", "如公筆陣高，豈足供法戰。", "聊堪用鷄毛，滴水共貧賤。", "市價亦不爭，百錢可營繕。", "包提偶到吳，取誚畏俗諺。", "胡爲而好此，感歎殊戀戀。", "徒咏絕妙詞，舊事記黄絹。"]'),
('e9e6debe-9cf1-4f2a-b7b8-e28533059b4d','次韵喻學士','韓淲','宋','宋诗','song-poetry','','[]','世味日以陋，莫能商古今。',120,'全唐诗/poet.song.176000.json','["世味日以陋，莫能商古今。", "伐異或黨同，嘈雜非正音。", "我生逢百罹，倍覺空苦心。", "堂堂玉泉家，源委非蹄涔。", "君尤挺特操，氣宇清且深。", "相逢清河橋，萬感成清斟。", "發揮所興寄，傾倒所譯尋。", "誰謂南渡久，而聞正始吟。", "黄華明露高，風迴雨垂陰。", "白髮生已多，只合同投簪。"]'),
('dfc0e2f4-09af-4bbe-8ce0-3281df50b0fe','次韵斯遠雨中','韓淲','宋','宋诗','song-poetry','','[]','尋幽我良久，步步生白雲。',96,'全唐诗/poet.song.176000.json','["尋幽我良久，步步生白雲。", "沿潭轉長畝，剝啄楓下門。", "人勝地逾佳，語到聲成文。", "紛乎彼城市，有耳胡用聞。", "夜雨發奇觀，簷溜迷幽芬。", "我爾本何事，今昔奚所分。", "擁爐挹名酒，撫几矚偉文。", "耿耿歲欲晚，姑從野梅論。"]'),
('d95e02bd-69fc-4048-8085-46e063de17f3','次韵鄭御带苦熱','韓淲','宋','宋诗','song-poetry','','[]','家山玉谿頭，薰風水流烟。',96,'全唐诗/poet.song.176000.json','["家山玉谿頭，薰風水流烟。", "小亭午夢餘，清耳晚樹蟬。", "本擬老林下，蕭散無窮年。", "豈知一左計，薄宦能幾錢。", "塵埃京轂底，僦舍萬井連。", "值此長夏熱，愈覺歸爲賢。", "故人忽念我，樂共湖山緣。", "昨夜復大雨，乘凉吟欲顛。"]'),
('425a8080-111c-40bc-8bf3-ed884a7ae85a','次韵昌甫  其一','韓淲','宋','宋诗','song-poetry','','[]','人物本如雲，八俊更三君。',120,'全唐诗/poet.song.176000.json','["人物本如雲，八俊更三君。", "山風吹夏籜，蒼雪落紛紛。", "專壑紫苔古，掩關青竹深。", "據高梧而瞑，新蟬助長吟。", "斸土燒萌茁，懲羹且一餐。", "竹新明眼句，持答愧琅玕。", "千歲支牀龜，團蒲紙帳爲。", "髮梳晨粥後，梅有隔窗枝。", "未臘靈山白，溪南只獨看。", "章泉兩峰雪，應更地爐寒。"]'),
('f29ee300-a7eb-4bb7-ae28-8329a69c3f8a','次韵昌甫  其二','韓淲','宋','宋诗','song-poetry','','[]','澗冷浮冰澌，深居坐堆灰。',120,'全唐诗/poet.song.176000.json','["澗冷浮冰澌，深居坐堆灰。", "紛然自積雪，懷哉復懷哉。", "兒女强解事，走蹈風雪裏。", "那知病骨酸，常日懶起止。", "幽憂底窮盡，抖擻時一撥。", "鴻飛聲冥冥，本是淡生活。", "山深已辟塵，雪中清人心。", "飛鳥絕尚可，空花翳陰陰。", "寒更數歷然，其如雪夜何。", "長言與短調，瑞峰清氣多。"]'),
('361703dc-84e5-4d5f-b74d-033b711e7c85','十日上饒次韻','韓淲','宋','宋诗','song-poetry','','[]','菊開即重陽，蝶愁何必論。',48,'全唐诗/poet.song.176000.json','["菊開即重陽，蝶愁何必論。", "今朝縣齋冷，松竹照清樽。", "雅致信無極，世俗慚不根。", "爲酬夜來吟，請從陶令言。"]'),
('0bb08472-6a6e-403e-b50f-a6da5014e7d7','次韵斯遠見懷','韓淲','宋','宋诗','song-poetry','','[]','一樹梅花發，窗前耿寒宵。',48,'全唐诗/poet.song.176000.json','["一樹梅花發，窗前耿寒宵。", "我舞影零亂，哦詩江動摇。", "田收粗可飯，歲暮豈無謠。", "山中烟霧合，水闊雪霜消。"]'),
('984db5a9-6148-4543-8d3b-7c5fb4a4dff6','次韵施仲益','韓淲','宋','宋诗','song-poetry','','[]','飯了尋茗事，一啜興未闌。',48,'全唐诗/poet.song.176000.json','["飯了尋茗事，一啜興未闌。", "更作建焙春，湯熟沉燎間。", "僧窗對詩人，與我溪澗閒。", "要是有餘味，雲輕鳥飛還。"]'),
('a2c6c9b5-a5c9-48a3-9e31-068224b49461','次韵','韓淲','宋','宋诗','song-poetry','','[]','交道棄如土，利害俱成風。',48,'全唐诗/poet.song.176000.json','["交道棄如土，利害俱成風。", "士夫無宿業，反不類賤工。", "平陸渺成江，千載生傑雄。", "阮籍未云達，黔婁安知窮。"]'),
('08136829-d5b3-435d-a357-910502c61887','十五日將入章泉上饒有句次韵','韓淲','宋','宋诗','song-poetry','','[]','上郭綿綿山，夾路悠悠水。',48,'全唐诗/poet.song.176000.json','["上郭綿綿山，夾路悠悠水。", "尋春問詩翁，興寄豈有已。", "持觴得茂宰，抵掌笑行止。", "坐中呼烏烏，酒酣徒熱耳。"]'),
('f7482005-5117-4484-a7c4-9f8298c7ff01','次韵景瑜  其一','韓淲','宋','宋诗','song-poetry','','[]','已是山中人，只問山中友。',48,'全唐诗/poet.song.176000.json','["已是山中人，只問山中友。", "水仙官梅花，霜濃盛開否。", "靈山閣之前，溪山堂之後。", "竹裏春山亭，冬深幾詩酒。"]'),
('3de1bba1-1c9a-4d13-a031-761189667db2','次韵景瑜  其二','韓淲','宋','宋诗','song-poetry','','[]','從昔秋風起，騷人感興同。',48,'全唐诗/poet.song.176000.json','["從昔秋風起，騷人感興同。", "霞收滕閣外，雲落楚臺中。", "寂寂無言說，紛紛有事功。", "漂流水南住，相望屋西東。"]'),
('ef2595ce-fc34-4035-be7d-3e87cc3b54e7','十三日次韵春伯','韓淲','宋','宋诗','song-poetry','','[]','忍浣城郭塵，來訪南豅友。',48,'全唐诗/poet.song.176000.json','["忍浣城郭塵，來訪南豅友。", "留連既聽雨，放浪亦市酒。", "誰知桂滿門，自覺香在手。", "秋思今如何，閑吟爲之久。"]'),
('a023a9e2-ae7f-433d-8576-43a10b343a25','施教授以詩送藥餌次韵謝之','韓淲','宋','宋诗','song-poetry','','[]','窮居寡所諧，懶顧形與影。',48,'全唐诗/poet.song.176000.json','["窮居寡所諧，懶顧形與影。", "誰歟藥石我，冉冉驚老景。", "開奩發珍劑，更以珠玉並。", "三歎得效方，因之倍脩省。"]'),
('d6bb3d48-fea3-4a47-9189-b814e542769c','次韵昌甫所寄因答施仲益且寄斯遠  其一','韓淲','宋','宋诗','song-poetry','','[]','平生所交友，豈曰不數人。',48,'全唐诗/poet.song.176000.json','["平生所交友，豈曰不數人。", "但恐莫我知，可疎不可親。", "人如李仲元，人如鄭子真。", "相望無百里，猶得奉清塵。"]'),
('1590d18f-7ef7-4ebc-be5c-5f5ee1c0efb4','次韵昌甫所寄因答施仲益且寄斯遠  其二','韓淲','宋','宋诗','song-poetry','','[]','三子者之撰，孰辨主與賓。',48,'全唐诗/poet.song.176000.json','["三子者之撰，孰辨主與賓。", "富貴非所惡，古道多賤貧。", "要是一世士，必有千載人。", "淵乎章泉水，高會聚荀陳。"]'),
('75771118-182e-4798-9ef1-3738854cc8ee','次韵昌甫所寄因答施仲益且寄斯遠  其三','韓淲','宋','宋诗','song-poetry','','[]','嘗看晉宋語，無忌酷似舅。',48,'全唐诗/poet.song.176000.json','["嘗看晉宋語，無忌酷似舅。", "焉如施與徐，共學乃師友。", "固應在同聲，亦何苦遺臭。", "我獨乏雅正，蓬心亂苗莠。"]'),
('0025d930-8c69-4221-8aa1-e6ccfad9a9e6','次韵  其一','韓淲','宋','宋诗','song-poetry','','[]','人梅兩相得，雪雲陰復開。',48,'全唐诗/poet.song.176000.json','["人梅兩相得，雪雲陰復開。", "此時對自足，朝夕爲誰催。", "逢花既攀折，尋香試徘徊。", "山意動詩興，優哉而悠哉。"]'),
('a3527a7d-a6e6-4dbc-81a3-ee4c5fac7442','次韵  其二','韓淲','宋','宋诗','song-poetry','','[]','留詩鍊字穩，讀者無此識。',48,'全唐诗/poet.song.176000.json','["留詩鍊字穩，讀者無此識。", "共看庭前桂，不改舊時碧。", "洗盞取酒來，飲盡莫留滴。", "醉後氣易平，長哦對泉石。"]'),
('8d0ef741-11d2-4f4b-9195-8993ad4e2f3f','次韵成季道中  其一','韓淲','宋','宋诗','song-poetry','','[]','蒼然山抱溪，遊子意何主。',48,'全唐诗/poet.song.176000.json','["蒼然山抱溪，遊子意何主。", "雪殘崖下日，風落泉上雨。", "嚴陵固莫及，玄英亦堪數。", "嵐靜白雲深，扁舟過汀渚。"]'),
('9a8a0b93-e8cd-46ac-9a19-14f3803d7297','次韵成季道中  其二','韓淲','宋','宋诗','song-poetry','','[]','乘流下東吳，耳目眩灘水。',48,'全唐诗/poet.song.176000.json','["乘流下東吳，耳目眩灘水。", "篷欹舟蕩兀，柁正纜迤邐。", "曉離林薄傍，晚著沙石裏。", "縮頭鵝鴈眠，時時忽驚起。"]'),
('1a7a21fa-fa15-4574-b50f-b115c539f349','二十七日置酒餞昌甫雪作次張上饒韵','韓淲','宋','宋诗','song-poetry','','[]','朅來固意愜，倏去誠願違。',48,'全唐诗/poet.song.176000.json','["朅來固意愜，倏去誠願違。", "敢云一語是，未省百事非。", "春雪遽落落，春花亦菲菲。", "舉手酬座人，酒美翁不歸。"]'),
('1b4ba031-2e37-4c8a-bd9b-73c435e54236','次韵吳推官獨遊南巖寺  其一','韓淲','宋','宋诗','song-poetry','','[]','獨遊有妙理，拓落空自知。',48,'全唐诗/poet.song.176000.json','["獨遊有妙理，拓落空自知。", "丘壑始晴日，澗溪輕暑時。", "胡牀看題字，佛屋思詠詩。", "宜非車馬喧，得以同襟期。"]'),
('e0eea851-1a49-4f16-95a2-621c0522a652','次韵吳推官獨遊南巖寺  其二','韓淲','宋','宋诗','song-poetry','','[]','叢深集幽鳥，荒翳無來人。',48,'全唐诗/poet.song.176000.json','["叢深集幽鳥，荒翳無來人。", "崖上滴乳泉，崖外棲緇塵。", "在此本如舊，相彼徒爭新。", "應當學金仙，永斷貪癡嗔。"]'),
('a6337aa0-e3cf-400d-85b2-9571ff828aa3','辛卿有言雨則清潤晴則清和昌甫因爲五字次韵呈之','韓淲','宋','宋诗','song-poetry','','[]','雅俗豈殊調，今古信一時。',96,'全唐诗/poet.song.176000.json','["雅俗豈殊調，今古信一時。", "晴雨草木長，摸索皆我詩。", "善來子趙子，身世忽若遺。", "顧瞻絕代人，乘閑有幽期。", "和潤見名理，處處清氣隨。", "坐卧泉亂鳴，孟夏凉侵肌。", "睡餘供茗事，禪榻鬢成絲。", "進退出處間，何心玩易羲。"]'),
('a3a0dae0-d6d6-44aa-addd-5c529e3cfbcd','再賦呈斯遠','韓淲','宋','宋诗','song-poetry','','[]','鵬鷃各相命，誰非逍遥遊。',72,'全唐诗/poet.song.176000.json','["鵬鷃各相命，誰非逍遥遊。", "何足控摶處，馮生一虛舟。", "老身縛微官，是氣空橫秋。", "歲月如斯夫，對君那得愁。", "嘯歌遡流光，更上大堤頭。", "好風從東來，孤懷眇難收。"]'),
('230e168c-afba-4d08-8e42-fdf6109df699','伯皋自永豐見過次韵','韓淲','宋','宋诗','song-poetry','','[]','薰風入家林，共坐滿窗綠。',120,'全唐诗/poet.song.176000.json','["薰風入家林，共坐滿窗綠。", "交遊情致深，景物歲月速。", "傷哉利名者，冰炭恣寒燠。", "既已隨頹波，一失不可復。", "較其心迹微，能異幾禽犢。", "吾儕事幽討，得興萬慮足。", "相羊山水間，處處堪悅目。", "君來叩蓬戶，離羣久居獨。", "道故驚變遷，憂時見翻覆。", "且聽歌聲長，前村正樵牧。"]'),
('255b8b5f-62ea-4296-b690-03622af1169f','次韵斯遠夜歸','韓淲','宋','宋诗','song-poetry','','[]','看梅集池舘，風雨中夜歸。',48,'全唐诗/poet.song.176000.json','["看梅集池舘，風雨中夜歸。", "當君扶輿際，是我尋夢時。", "山氣既巃嵸，晨光且熹微。", "倏來五字工，亟讀起披衣。"]'),
('fe82a304-b8e7-4025-8954-aee8dd8e249f','劉簿之婿游以詩來見且持昌甫書和韵答之','韓淲','宋','宋诗','song-poetry','','[]','空山落黄葉，天寒鴻雁鳴。',60,'全唐诗/poet.song.176000.json','["空山落黄葉，天寒鴻雁鳴。", "敲門袖詩來，一見喜且驚。", "清揚固不凡，雅意方流行。", "如天兩曜奔，如水百瀆傾。", "是中有妙寄，冰翁必能名。"]'),
('621c6c09-3c9b-45a5-a7d8-999ae19a4865','次昌甫韵','韓淲','宋','宋诗','song-poetry','','[]','人物曾幾何，歲月良不待。',48,'全唐诗/poet.song.176000.json','["人物曾幾何，歲月良不待。", "秋深動金石，夜久生竽籟。", "凉知神觀回，靜勝語嘿對。", "悠悠苔竹軒，語短莫能載。"]'),
('d6ffb4cf-7dd0-46de-86a4-b7fff4c78c43','次韵林教授見別','韓淲','宋','宋诗','song-poetry','','[]','老我成漫仕，世事馬牛風。',144,'全唐诗/poet.song.176000.json','["老我成漫仕，世事馬牛風。", "投身逐毫末，益愧多田翁。", "乘春欲東遊，肯問行李窮。", "溪干富桃李，花光眩晴空。", "停橈一舉首，壯氣猶如虹。", "靈山正崔嵬，半在返照中。", "行藏豈人定，忠誠本天通。", "但顧行未實，奚論報必豐。", "君詩多雋永，三年幾相從。", "山亭酌別酒，舟車復西東。", "餘情尚酬句，歲月雙鬢蓬。", "黄髮愛玉體，書來置郵筒。"]'),
('09892577-0ed0-40bd-90c3-b3d6c464c198','次韵林教授','韓淲','宋','宋诗','song-poetry','','[]','終朝雨清潤，坐嘯青林中。',72,'全唐诗/poet.song.176000.json','["終朝雨清潤，坐嘯青林中。", "戍樓千鼓傳，殷殷聞鼕鼕。", "敢爲城市遠，猶喜聲迹通。", "詩成賦幽憤，志豈終困窮。", "興言古達者，鹿門有龐翁。", "此話世莫知，因公悅心胸。"]'),
('c4970661-2ee0-49dc-8886-402d9de73f39','次韵昌甫仲春讀謫仙詩  其一','韓淲','宋','宋诗','song-poetry','','[]','年年最佳處，韶豔三春光。',72,'全唐诗/poet.song.176000.json','["年年最佳處，韶豔三春光。", "顧我憔悴人，豈不能自强。", "拂拭整春服，行歌發清商。", "山頭山花開，花底還舉觴。", "歡來爲之醉，身世忽若忘。", "笑指深林中，崇蘭有國香。"]'),
('9cf0c4e4-a464-478b-9273-0b405d4a28d6','次韵昌甫仲春讀謫仙詩  其二','韓淲','宋','宋诗','song-poetry','','[]','花嫩得雨開，花老得雨落。',48,'全唐诗/poet.song.176000.json','["花嫩得雨開，花老得雨落。", "開落須臾期，人生任相謔。", "紅花春融融，白花春漠漠。", "春色正可娛，逢花快盃酌。"]'),
('d2f69bb7-8266-4753-9901-f24ae6e92e36','次韵昌甫仲春讀謫仙詩  其三','韓淲','宋','宋诗','song-poetry','','[]','苔竹雨浪浪，章泉水涓涓。',48,'全唐诗/poet.song.176000.json','["苔竹雨浪浪，章泉水涓涓。", "是中春晴時，瑞峰生紫烟。", "幽人更真率，語客醉欲眠。", "既已外此身，庸知有愚賢。"]'),
('172efeed-b52b-4d43-83ed-f0d018e6acf7','正月五日讀東坡和斜川詩於霞山','韓淲','宋','宋诗','song-poetry','','[]','有酒勿憚飲，觸事醉則休。',120,'全唐诗/poet.song.176000.json','["有酒勿憚飲，觸事醉則休。", "風物既閑美，何爲不來遊。", "斜川眇千載，淵明豈常流。", "疏年記時日，依湍對魴鷗。", "偶然值隣曲，崎嶇想經丘。", "吾生亦老矣，懷古誰與儔。", "但笑勿悲鳴，百句無一酬。", "茲辰過霞山，又可絕口不。", "却怪和陶者，儋崖聖同憂。", "遥遥二子心，妙處未易求。"]'),
('7f33a668-67c5-47f4-b9fd-b2760fec1917','邵司法索詩','韓淲','宋','宋诗','song-poetry','','[]','榜巷曰陋巷，作齋爲茅齋。',48,'全唐诗/poet.song.176000.json','["榜巷曰陋巷，作齋爲茅齋。", "何愧安樂窩，其志安在哉。", "有子醉六經，有眼照九垓。", "應羨常山水，長從城下來。"]'),
('59565480-adeb-4075-93e4-f672dfd620a1','偶成','韓淲','宋','宋诗','song-poetry','','[]','閑多乏交遊，生晚欠知友。',96,'全唐诗/poet.song.176000.json','["閑多乏交遊，生晚欠知友。", "棲遲强逢迎，汩沒憚趨走。", "幾年荒野外，已覺安井臼。", "一旦朝市間，時亦泥盃酒。", "紛紛夸毗兒，落落窮獨叟。", "由來事簞瓢，豈是厭升斗。", "湖波風泛蓮，野岸日移柳。", "爲問吳山頭，何如楚溪口。"]'),
('d3bc1708-71a4-4718-ba9e-f0bae5cc9411','昌甫寄苦錐次韵','韓淲','宋','宋诗','song-poetry','','[]','回味有苦益，充腸宜苦錐。',96,'全唐诗/poet.song.176000.json','["回味有苦益，充腸宜苦錐。", "其實雖地出，其雅則天資。", "因思夏畦發，又見霜林吹。", "頼彼庶可食，此外何所爲。", "羶薌易爽口，鼎豆徒解頤。", "朝市安能羨，山林端足師。", "悠然自公詠，殷勤還我貽。", "咀嚼豈不樂，吟哦信非癡。"]'),
('42c7f263-7fba-4ec2-a725-3230eb31e535','次韵趙監倉','韓淲','宋','宋诗','song-poetry','','[]','是中能娛人，豈爲杯酒留。',48,'全唐诗/poet.song.176000.json','["是中能娛人，豈爲杯酒留。", "不知我何求，當復醉扶頭。", "翩翩佳公子，臨風仲宣樓。", "月滿乃如此，對君可言愁。"]'),
('24c70bb7-c045-4a0d-8d77-1a02e182cdfd','鄒道鄉送幼安赴澶倉','韓淲','宋','宋诗','song-poetry','','[]','人生本逆旅，行止良悠悠。',96,'全唐诗/poet.song.176000.json','["人生本逆旅，行止良悠悠。", "試看康莊上，轍跡多成溝。", "公子分閉戶，時來亦何由。", "載書曉遄邁，春令方如秋。", "河濱古城府，稅鞅聊優游。", "青雲捷徑在，坻庾非君優。", "臧孫故有後，嶄嶄承風流。", "胡爲重作惡，日暮猶登樓。"]'),
('5a56f0fd-3422-4d80-9805-727aa5e71f00','次韵王教授','韓淲','宋','宋诗','song-poetry','','[]','悠悠城下水，又與日平西。',72,'全唐诗/poet.song.176000.json','["悠悠城下水，又與日平西。", "漫移脚步高，忘却所歷低。", "奔忙小聚邑，乃有一大溪。", "欄干莫浪拍，事物久難齊。", "望舒生絕巘，我醉馬未嘶。", "停驂且莫上，狹路多塗泥。"]'),
('e00bd735-21c0-421d-928e-faa81de9b49d','月夜小集次韵鄭教授','韓淲','宋','宋诗','song-poetry','','[]','溪山有佳月，可以永今夕。',144,'全唐诗/poet.song.176000.json','["溪山有佳月，可以永今夕。", "驚心總悠悠，過眼紛籍籍。", "何爲秋向深，甚是老已逼。", "長謠陶一觴，懷抱所共席。", "披衣步良夜，奈此佳月何。", "太虛澹以闊，青景轉覺多。", "風微泛家山，露湛明庭樹。", "烏鵲無停棲，稀星片雲度。", "光冷秋氣肅，感時唯自驚。", "徘徊亦已久，不知更漏深。", "嫦娥在高高，傳聞殊恍惚。", "雙鶴快飛來，駕我探月窟。"]'),
('7f5116b4-f28a-463f-87f3-8006659499e1','有懷斯遠及施仲益次章丘韵','韓淲','宋','宋诗','song-poetry','','[]','後湖有徐舅，永豐有施甥。',72,'全唐诗/poet.song.176000.json','["後湖有徐舅，永豐有施甥。", "英英懷玉山，方來孰爭衡。", "世豈無甥舅，人豈無友生。", "二士真可人，得之於我榮。", "跖壽回也短，司命如不平。", "已乎係時數，感焉涕泗并。"]'),
('040c8b0c-3301-4429-a430-de294a47480b','次韵載叔','韓淲','宋','宋诗','song-poetry','','[]','南風吹歸船，便欲老林下。',72,'全唐诗/poet.song.176000.json','["南風吹歸船，便欲老林下。", "塵埃坐吳會，衮衮失晝夜。", "因行山寺高，忽見此粲者。", "長夏得襟期，樓居靜如畫。", "他年共回首，一段好佳話。", "誰知予懷深，萬事口不掛。"]'),
('3d534317-294e-4ce3-8a04-83491318701d','次韵成季  其一','韓淲','宋','宋诗','song-poetry','','[]','凉天有佳月，何須問盈虧。',108,'全唐诗/poet.song.176000.json','["凉天有佳月，何須問盈虧。", "彼美黄金花，亦自滿東籬。", "我歸南山秋，從此當樂之。", "開園整舊蹊，世事真若遺。", "迤邐得閑趣，款曲知情怡。", "鷗鷺或時下，可使機心疑。", "向來宦江海，自縛曾誰鞿。", "客來相勞苦，一觴聊共持。", "休去便當已，宜佩淵明詩。"]'),
('8a72420f-5cac-43e8-b9b3-2e8fd4b721cc','次韵成季  其二','韓淲','宋','宋诗','song-poetry','','[]','挈杖過前麓，凉風動吾巾。',108,'全唐诗/poet.song.176000.json','["挈杖過前麓，凉風動吾巾。", "指點昔所翫，示我同心人。", "徘徊路將夕，猶能望城闉。", "平沙映迴岸，黄葉迷青蘋。", "石逕亦可上，老眼俱爲新。", "危亭望更遠，左右還多筠。", "不覺夜氣合，沾灑雨脚勻。", "興盡篝火歸，隠約溪粼粼。", "是中著佳士，與俗隔幾塵。"]'),
('ed00269d-a698-454d-bb70-7ceacda83c42','次韵嚴丈併呈孟使君','韓淲','宋','宋诗','song-poetry','','[]','山城芳樹深，明月啼杜宇。',96,'全唐诗/poet.song.176000.json','["山城芳樹深，明月啼杜宇。", "客懷爲摇蕩，詩語亦覼縷。", "朅來新安江，頗覺民物古。", "故人作太守，善政尤可數。", "塵榻爲我下，更復多軟語。", "飄零曾幾何，乃此一杯醑。", "坐中嚴夫子，意氣欲掀舞。", "晤對心事閒，信矣良工苦。"]'),
('4c3bc72b-fe93-454a-8a6a-b071d7ea12de','次韵抱朴君同紫芝見過','韓淲','宋','宋诗','song-poetry','','[]','春來得新語，勝食齋房芝。',120,'全唐诗/poet.song.176000.json','["春來得新語，勝食齋房芝。", "舌本久已强，便覺此意隨。", "三嚥元和津，髣髴疑管窺。", "是事夫如何，今古誠一時。", "起搔種種髮，抖擻酬酢之。", "樓西萬山橫，其中真吾詩。", "試斷取一二，慘慘天四垂。", "誰云泌之水，而可以樂饑。", "但願且喫飯，底用談所知。", "彼哉長物爾，徒敗人佳思。"]'),
('157aca28-45bd-4f0d-921c-695618c999e6','嚴丈泰伯見貽古句次韵爲答','韓淲','宋','宋诗','song-poetry','','[]','意行無東西，偶成一段奇。',288,'全唐诗/poet.song.176000.json','["意行無東西，偶成一段奇。", "尋山得幽伴，遂爾相娛嬉。", "水涉漁梁窄，山循鳥道危。", "每慙衣上塵，素染已如淄。", "新安山水邦，寺屋多斷碑。", "摩挲青莓苔，往往識歲時。", "所貴眼界闊，豈畏足力疲。", "榜舟或扶輿，上下適其宜。", "弔古踐陳迹，懷賢理前規。", "呂侯讀書堂，遺祀留丰姿。", "恨生異代深，遐躅無由隨。", "寂寥付短篇，酩酊持屈巵。", "是日頗款曲，有時還切偲。", "雖云各笑語，卒復度禮儀。", "英英釣瀨仙，其學夙素知。", "譬彼巨淵藪，蟠伏豹與螭。", "一旦奮迅去，誰復維縶之。", "觀乎律調雅，益悼餘子卑。", "示我千百年，匪特用自怡。", "傳玩入鈴齋，使君亦伸眉。", "由來絕俗士，定有驚人詩。", "激烈薄層穹，豁達開晴曦。", "况同陟山顛，又已還水涯。", "物色既甚富，身世真若遺。"]'),
('2c710c73-6c94-4cb8-8636-557365d59454','次韵趙十','韓淲','宋','宋诗','song-poetry','','[]','風誼益零落，烏能論前修。',192,'全唐诗/poet.song.176000.json','["風誼益零落，烏能論前修。", "百年之江南，聲利日夜流。", "履道兄弟賢，幾時已交遊。", "東里大父行，宿昔契分投。", "偉乎竹隠高，俗但言句求。", "可不拜其廬，何以記綢繆。", "我衰尚三歎，微吟如殷憂。", "傳聞擔簦趨，梅黄雨初收。", "一襟清微風，步步紫翠浮。", "輿籃試息肩，茅店板橋頭。", "村酒勿浪醉，回驂當熟籌。", "所觀書研真，所奉窗几幽。", "豈比城府間，語嘿勞應酬。", "肥遯理事長，故家文獻優。", "林密山更深，尋壑好經丘。", "履道果再來，胥會誠良謀。"]'),
('a7ceda20-2117-4762-91c8-89cdbf743430','俞伯輝主簿同徐必大判院見過澗上納凉約鮑南仲教授小酌次韵南仲所賦兼懷林德久國錄陳敬甫學士','韓淲','宋','宋诗','song-poetry','','[]','嘉禾古名郡，機雲信奇士。',240,'全唐诗/poet.song.176000.json','["嘉禾古名郡，機雲信奇士。", "流風千載下，誰復數餘子。", "近年西疇仙，游戲在朝市。", "文章陳仲弓，合著蓬萊裏。", "俱嘗白鷗盟，恨別隔秋水。", "君侯乃其朋，訪我靈山底。", "一見欲傾盖，青眼照窗几。", "大抵交情深，不待早知己。", "學殖豈枝葉，詞林務根柢。", "堂堂郡賓客，千里爲之喜。", "顧言老場屋，眄焉每甚愧。", "衡門度長夏，風日忽清美。", "懷賢思晤言，泉石滿幽耳。", "固多長者轍，愛閑諒無幾。", "傳豅金閨路，剝啄快人意。", "雙谿南宮秀，留連今何似。", "要是同襟期，此道亦難爾。", "歡然君肯來，棋酒不能已。", "詰朝得新篇，誦歎有真味。", "載念平生親，髣髴夢中記。"]'),
('2d68cc67-353f-4a82-98cb-2ce5ffa6fa54','次韵昌甫同酌宋知軍家釀','韓淲','宋','宋诗','song-poetry','','[]','雅俗豈殊調，城郭山林分。',72,'全唐诗/poet.song.176000.json','["雅俗豈殊調，城郭山林分。", "知君心事寬，一笑鷄鶴羣。", "邂逅多□客，酒亦爲之醺。", "庾信哀江南，李白日暮雲。", "白頭幾青眼，吾人尚可云。", "夜闌擁鼻吟，天香桂紛紛。"]'),
('88fc2dc6-3162-4d48-a653-5885e3a0218a','次韵斯遠弄琴','韓淲','宋','宋诗','song-poetry','','[]','開門有詩來，殷若金石聲。',108,'全唐诗/poet.song.176000.json','["開門有詩來，殷若金石聲。", "虛堂坐以咏，澹與秋氣清。", "豈無如此句，豈有如此情。", "懷哉我所尚，求田乃歸耕。", "時乎發鳴彈，浩浩非營營。", "大音知者希，既和應且平。", "楓林月在戶，寒影膝上橫。", "想當三歎後，却手復起行。", "華髮老相看，百事皆已經。"]'),
('dc940c09-56b7-4f16-876f-3b088e28d67c','次韵信卿','韓淲','宋','宋诗','song-poetry','','[]','伊人學有源，疏汝導瀍澗。',216,'全唐诗/poet.song.176000.json','["伊人學有源，疏汝導瀍澗。", "相羊辟雍水，他年定名宦。", "談高如已仙，筆妙疑善幻。", "池龍駕車輦，天馬脫鞍襻。", "平生諸公間，抵掌肯譏訕。", "顧我方卑飛，藩籬趁尺鷃。", "相逢山水縣，不覺逼歲晏。", "時評道精粗，萬折歸一貫。", "更及羲文易，後世明憂患。", "行藏思鼎鐘，舒卷付藜莧。", "飄零朋舊交，俛仰親故盼。", "因知昔能賢，此趣亦俱慣。", "茫茫造化廣，局局天壤間。", "溪山偶登臨，古寺履危棧。", "老來身本閒，懶去情轉慢。", "詞場足金章，决科信須綰。", "霜天忍分手，惻愴涕空潸。", "夜坐把離杯，寒聲度鴻鴈。"]'),
('2d045a74-0cd2-4509-a168-861201e2ab23','雨中次韵黄守見貽','韓淲','宋','宋诗','song-poetry','','[]','新語忽墮前，曠然銷我憂。',48,'全唐诗/poet.song.176000.json','["新語忽墮前，曠然銷我憂。", "引紙爲答賦，摇毫與冥搜。", "貧病雨未止，荒凉水常流。", "鼓琴誰裹飯，能記子桑不。"]'),
('9bc9566e-bc07-4f4d-a92c-060846f17259','春伯邸樓次韵十哥所題','韓淲','宋','宋诗','song-poetry','','[]','樓陰入清湖，南風渡歌鼓。',48,'全唐诗/poet.song.176000.json','["樓陰入清湖，南風渡歌鼓。", "旅夢不自持，悠揚定何許。", "醒來疎雨過，兩目隘泥土。", "慮澹地亦偏，桐花映窗戶。"]'),
('5de86146-ff31-4848-b937-ea474e617110','德久寄所與文叔酬唱因次韵','韓淲','宋','宋诗','song-poetry','','[]','紅雲島上茶，一葉開槍旗。',96,'全唐诗/poet.song.176000.json','["紅雲島上茶，一葉開槍旗。", "到今清夢飛，正焙水芽時。", "世無桑苧翁，泉井空日滋。", "當年游其間，停鞭嘗午炊。", "想像修貢珍，清風可忘饑。", "故人持英蕩，豈不一賦之。", "應笑拾澗薪，白石煮作糜。", "臺高有揖客，更和別駕詩。"]'),
('ea55adf6-25f8-44ca-8cbd-72c21cc7a77b','致道注船場闕有詩次韵','韓淲','宋','宋诗','song-poetry','','[]','思老問形影，憂饑累身口。',84,'全唐诗/poet.song.176000.json','["思老問形影，憂饑累身口。", "人生誠可嗟，所食能幾糗。", "不過一飽爾，自苦較先後。", "爭馳分寸地，旁觀真欲嘔。", "如君賦解嘲，里耳果聽否。", "吾方卧窮巷，靜對小窗牖。", "應笑我所無，請視渠所有。"]'),
('27b6ca75-1240-43b8-bd31-11a824397fd8','次韵斯遠併柬成季  其一','韓淲','宋','宋诗','song-poetry','','[]','茫茫大塊中，返照孰真實。',72,'全唐诗/poet.song.176000.json','["茫茫大塊中，返照孰真實。", "閑乘此老身，到處輒止息。", "餘凉披拂間，露重葉已赤。", "人其謂我何，嗜彼烟火食。", "蓬萊幾清淺，底用弱水力。", "排雲斥剛風，塵世便可出。"]'),
('91eb9423-11a8-41db-8718-aeadab327a46','次韵斯遠併柬成季  其二','韓淲','宋','宋诗','song-poetry','','[]','午夜露氣冷，明月忽已低。',96,'全唐诗/poet.song.176000.json','["午夜露氣冷，明月忽已低。", "推窗此何時，蛩螿互悲凄。", "乃知南豅山，更有南豅溪。", "樵歌起老叟，牧笛吹童兒。", "百年漫戚欣，千載勞是非。", "口心忽相語，不閑尚奚爲。", "磊磊千枝松，洋洋萬頃陂。", "偃蹇衡茅下，匪懼寒與饑。"]'),
('9762e06f-33b9-4596-9b4b-8e8de7e601e8','次韵昌甫','韓淲','宋','宋诗','song-poetry','','[]','論交與誰語，忽厭來者衆。',144,'全唐诗/poet.song.176000.json','["論交與誰語，忽厭來者衆。", "山林恨不深，萬事祗一鬨。", "秋風吹衣裳，憀慄薄寒中。", "幽憂誦離騷，此意千載共。", "世豈無升沉，人自有輕重。", "匪惟物所移，即以勢之動。", "吁嗟奈若何，得句且吟諷。", "吾儕聚集地，絕倒頗閑縱。", "雖作三日留，尚覺歸倥傯。", "長歌固云哀，慟哭未爲痛。", "遷書並屈賈，班史傳王貢。", "甚矣孔仲尼，不復周公夢。"]'),
('40d29e19-54aa-4154-8467-488b61e87430','次韵吳推官','韓淲','宋','宋诗','song-poetry','','[]','水南見靈山，但可著兩眸。',48,'全唐诗/poet.song.176000.json','["水南見靈山，但可著兩眸。", "孰知九州外，自有大九州。", "放浪此身心，是事同浮漚。", "樂哉我重九，風雨簷溜收。"]'),
('e923a3f5-0cae-467c-900f-6a0bd0148eb3','次韵','韓淲','宋','宋诗','song-poetry','','[]','宴坐寂不動，筆硯亦當屏。',156,'全唐诗/poet.song.176000.json','["宴坐寂不動，筆硯亦當屏。", "空虛四壁懸，况此夏方永。", "世塗緣業多，荆棘萬蓬梗。", "痛掃終未除，中抱絕清冏。", "老身伸縮餘，妙處頗能領。", "時舒腰脚頑，那復弔形影。", "日長掩關卧，睡熟呼弗醒。", "客來曾幾何，間亦乏酒茗。", "富貴今金張，功名更鄧耿。", "有味是桑麻，肥遯義尤迥。", "朋從趙與尹，堂齊偶鄰並。", "歡言修敏家，俱可話閑靜。", "此趣人勿驚，吾詩聊自省。"]'),
('76028553-2bc2-4b3b-b828-4f2e6e651db7','分韵得晚字','韓淲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','三年西湖邊，薄宦良衮衮。',36,'全唐诗/poet.song.176000.json','["三年西湖邊，薄宦良衮衮。", "春風我欲歸，龍井不憚遠。", "結客試幽尋，山深恨來晚。"]'),
('c84a5ab8-fb51-4b00-accb-aa49c34f129b','初五日孔野雲同酌樓下取琴作白雲曲因和周倅所贈韵','韓淲','宋','宋诗','song-poetry','','[]','野雲彈白雲，聲寄徽外微。',96,'全唐诗/poet.song.176000.json','["野雲彈白雲，聲寄徽外微。", "胎仙舞三疊，生飛上華池。", "徽弄瞬息間，是豈箏阮資。", "孤桐本貞高，緩節調勿催。", "天心古樂見，畫出彌明師。", "志士不可聽，俗士不可窺。", "落佩倒冠者，因之得希夷。", "靈仙福地南，春風百草齊。"]'),
('7b9ac19c-486d-4322-ad85-d81e499d795a','莊賢良有園在境上作詩相示因和韵','韓淲','宋','宋诗','song-poetry','','[]','賀家池上園，自足了一世。',108,'全唐诗/poet.song.176000.json','["賀家池上園，自足了一世。", "是中風味佳，恨我未能至。", "縱橫十畝寬，想見去荒穢。", "藥苗與菜本，歲久必多置。", "人生閑最樂，奚苦事名第。", "軒裳果可得，不過多僕婢。", "爭如老山林，庶足遠朝市。", "能吟無自悲，逢酒便須醉。", "因公發長謠，休去轉覺易。"]'),
('51138828-c81c-4666-bfac-130351e042db','小酌餞耿運幹趙推官分韵復和韵  其一','韓淲','宋','宋诗','song-poetry','','[]','山林閑放身，幽意苦不愜。',48,'全唐诗/poet.song.176000.json','["山林閑放身，幽意苦不愜。", "因來我壺觴，且送爾官牒。", "池蓮紅未葩，園笋綠已葉。", "去住豈願違，人寰付塵劫。"]'),
('b1939389-82a1-4e75-b5a6-df7f9cf03ec4','小酌餞耿運幹趙推官分韵復和韵  其二','韓淲','宋','宋诗','song-poetry','','[]','痼疾已烟霞，藥石從美疢。',48,'全唐诗/poet.song.176000.json','["痼疾已烟霞，藥石從美疢。", "誰憐名宦遲，我覺幻化迅。", "興與山孤高，語带澗深潤。", "去去上下塘，應勞青眼瞬。"]'),
('5cf801ad-ac62-43b6-9f9c-160c89cdfe55','小酌餞耿運幹趙推官分韵復和韵  其三','韓淲','宋','宋诗','song-poetry','','[]','勿云杯酒闌，且認語笑密。',48,'全唐诗/poet.song.176000.json','["勿云杯酒闌，且認語笑密。", "婆娑真一老，跌宕忻六逸。", "交遊貴忘年，志意當惜日。", "舒而有鼎彜，卷而有篇帙。"]'),
('592ab96c-e084-4721-865e-f92cc98c6b11','半塘寺法華童子塔和石刻韵','韓淲','宋','宋诗','song-poetry','','[]','生公曾坐講，童子本來明。',48,'全唐诗/poet.song.176000.json','["生公曾坐講，童子本來明。", "寂寂春光晚，半塘流水清。", "身心爲淨土，千古話風鈴。", "禮塔四方靜，巡簷一片聲。"]'),
('46bb8699-b1fd-4cc3-8da2-2786300ad258','太守茶山周治中作大字分韵','韓淲','宋','宋诗','song-poetry','','[]','漫興詩酒裏，茶山復何爲。',60,'全唐诗/poet.song.176000.json','["漫興詩酒裏，茶山復何爲。", "使君領客來，達尊亦嘻嘻。", "別駕真不凡，咳唾墨淋漓。", "中間章泉叟，勝事徒自知。", "寄語桑苧茶，今是春早時。"]'),
('26e9177a-fb07-434f-8c6a-867a41909de3','九日周國正席間分韵','韓淲','宋','宋诗','song-poetry','','[]','我家南山陲，九日空自知。',84,'全唐诗/poet.song.176000.json','["我家南山陲，九日空自知。", "抱病起登臺，茱菊隨所宜。", "主稱時序嘉，領客相娛嬉。", "烟雲開遠村，城郭橫近溪。", "當年漉巾陶，何事獨遶籬。", "醒醉一笑爾，千古無庸悲。", "秋風緩摇落，揮杯且題詩。"]'),
('6d69b854-5adc-48d3-8351-51138e8e6773','夜醉處晦山臺明日和韵','韓淲','宋','宋诗','song-poetry','','[]','高臺梅先開，老意爲興起。',144,'全唐诗/poet.song.176000.json','["高臺梅先開，老意爲興起。", "何知寒事營，櫪驥志不已。", "下視城郭居，萊蕪欠耘鋤。", "嘈雜復嘈雜，百年狐兔墟。", "惄焉如調饑，山阿休采薇。", "怨耶其非邪，且問竹外枝。", "仲尼杖何感，能叩原壤脛。", "今我其息黥，舉身都是病。", "方來二三友，少敢話肝腸。", "縱云千日花，難著一夜霜。", "南渡誠草草，流落那忍道。", "吾人能幾家，向來有諸老。"]'),
('89649920-c411-439c-8fd4-e40beae73003','和韵趙十','韓淲','宋','宋诗','song-poetry','','[]','能爲博山遊，想度丁公嶺。',108,'全唐诗/poet.song.176000.json','["能爲博山遊，想度丁公嶺。", "風乎兩巖幽，泉石景逾靜。", "人誰無雅識，每每痼俗境。", "書傳所興起，更復史集訂。", "於其遊息間，趣味必雋永。", "如君英妙年，宦達在俄頃。", "因問知好修，何事不加省。", "里居得往還，時亦具果茗。", "詩來予和女，老意轉甦醒。"]'),
('bf561591-6f55-43b6-92dc-5ec71fab1905','和韵  其一','韓淲','宋','宋诗','song-poetry','','[]','一笑過浮梁，留連度隙光。',48,'全唐诗/poet.song.176000.json','["一笑過浮梁，留連度隙光。", "君當思大耐，我已老蒼筤。", "只恐心情短，須教興寄長。", "酒從詩自好，分韵記禪房。"]'),
('ff56fe95-1252-42df-9dde-cc62a6a84db1','和韵  其二','韓淲','宋','宋诗','song-poetry','','[]','酒亦關何事，片片流仙霞。',60,'全唐诗/poet.song.176000.json','["酒亦關何事，片片流仙霞。", "用之滌肺肝，相與成詩家。", "一酌且濡唇，再酌深到花。", "持杯兩相笑，吟哦入幽遐。", "筆落豈知醉，何者是生涯。"]'),
('dc306071-1d4a-4c8b-ab49-d972d5dbda09','和韵  其三','韓淲','宋','宋诗','song-poetry','','[]','人生本無情，掩苒受風竹。',60,'全唐诗/poet.song.176000.json','["人生本無情，掩苒受風竹。", "徒親筆硯勞，造作漫盈軸。", "賓親偶成集，禪榻不待速。", "清歡雖與同，極則豈見獨。", "坐中憎點頭，任彼屐滿屋。"]'),
('a5f599f7-c1c3-41c9-9c21-8f9a81808226','和凈字','韓淲','宋','宋诗','song-poetry','','[]','悠悠俱幻境，起滅要人認。',48,'全唐诗/poet.song.176000.json','["悠悠俱幻境，起滅要人認。", "相從一轉語，老嬾且求靜。", "禽鳥亦何情，草木有本性。", "底用詩自鳴，幽禪了真凈。"]'),
('42627a63-43e1-4257-a8ff-d5b0013cc48a','和宇字','韓淲','宋','宋诗','song-poetry','','[]','人家翠微深，林空響機杼。',48,'全唐诗/poet.song.176000.json','["人家翠微深，林空響機杼。", "烟收片月出，霜氣襲衡宇。", "追隨頼陶寫，領畧道情素。", "尋我澗谷中，更入春山去。"]'),
('a9bc9ade-1f3e-4dd0-aeef-bd90d91f3415','和天字','韓淲','宋','宋诗','song-poetry','','[]','歲晚營寒事，崢嶸窮臘前。',48,'全唐诗/poet.song.176000.json','["歲晚營寒事，崢嶸窮臘前。", "雲山一敗裘，百種不敢先。", "遊於物之初，更尚我所賢。", "彼哉野馬塵，從渠舞甕天。"]'),
('40c0353a-55dd-4d7f-a827-77a2c168d0c6','和清字','韓淲','宋','宋诗','song-poetry','','[]','心親相往來，豈計酒濁清。',48,'全唐诗/poet.song.176000.json','["心親相往來，豈計酒濁清。", "水南有茅屋，橋北是山城。", "煙霜忽雨晴，雲風催雪明。", "撫觥既已醉，回薄萬古情。"]'),
('36a7767f-faf8-4d84-bf15-afc614cd6a2b','和仲至贈蹈中韵','韓淲','宋','宋诗','song-poetry','','[]','人非不知我，知之欲何求。',132,'全唐诗/poet.song.176000.json','["人非不知我，知之欲何求。", "錢塘一都會，江湖水悠悠。", "豈無美少年，亦有杖白頭。", "吾儕出入地，汎乎不繫舟。", "急謀斗升爾，顔面那用羞。", "憶昔南渡來，衣冠幾春秋。", "世道遞升降，人物稀復稠。", "紆朱懷金者，信足樂輩儔。", "細思黏魚竿，家山本田疇。", "朔風吹眼眵，觸事風馬牛。", "且如詩中仙，可以追逐不。"]'),
('835217fd-f6d5-4b11-90da-6868cd8f0ee9','和昌甫','韓淲','宋','宋诗','song-poetry','','[]','相望隔異縣，但願加餐飯。',60,'全唐诗/poet.song.176000.json','["相望隔異縣，但願加餐飯。", "悠悠雞唱晨，寂寂鐘鳴晚。", "是中或欣佳，聊以寄頹嬾。", "有時得片言，經旬答寸簡。", "會當固窮齋，汲井爲洗琖。"]'),
('756cd55b-3934-479e-9403-00ecbbea5d41','和校官','韓淲','宋','宋诗','song-poetry','','[]','識賞調固佳，詠嘆心愈轉。',120,'全唐诗/poet.song.176000.json','["識賞調固佳，詠嘆心愈轉。", "載吟復載嘯，我亦爲之衍。", "至味寄和平，浮辭謝雕篆。", "因思交斷金，是必德勝璉。", "方來二三友，往往錢萬選。", "主人好事者，託興每不淺。", "坐令浣花翁，索酒望雲巘。", "淋漓顛倒間，感舊或未免。", "薰風吹壺觴，落日照盤饌。", "溝流水聲遠，慮淡物自遣。"]'),
('77843a87-383f-43d4-8bb2-91c52fb098c8','和伯輝去歲所寄兼懷曾君錫左司','韓淲','宋','宋诗','song-poetry','','[]','山扃竹林居，神情爲之凝。',132,'全唐诗/poet.song.176000.json','["山扃竹林居，神情爲之凝。", "泉仙墨妙揮，特令人眼明。", "是豈有心哉，亦匪不平鳴。", "其仙今如何，帝所振金聲。", "枕麯劉伯倫，潄石孫子荆。", "既言委陸沉，頗謂乃崢嶸。", "放身嘗一遊，面勢既經營。", "極知天下士，不但同年生。", "襟期兩嘉尚，歲月有餘情。", "我亦老賓客，祇欲身中清。", "槁項禿髮矣，空吟澤畔行。"]'),
('792bcf5c-ddcd-419e-969b-d6cfcaed2d90','和元立使君起字','韓淲','宋','宋诗','song-poetry','','[]','敢爲蚍蜉憾，謾作蒹葭倚。',48,'全唐诗/poet.song.176000.json','["敢爲蚍蜉憾，謾作蒹葭倚。", "荒唐北溟魚，怪誕南柯蟻。", "朗吟韵已分，更酌盞可洗。", "揮手問黄山，夜半笙鶴起。"]'),
('d5560982-dd30-491a-ada4-829fdf8a33bf','和尹一韵','韓淲','宋','宋诗','song-poetry','','[]','何處尋吾詩，梅橫修竹色。',48,'全唐诗/poet.song.176000.json','["何處尋吾詩，梅橫修竹色。", "搔頭入混茫，揮手謝偪側。", "陶然漫飲趣，卓矣要筆力。", "冰溪最高地，不可不造極。"]'),
('a10d052f-dd86-4b67-a55a-fa9bc7a4063a','古鬲次韵成季','韓淲','宋','宋诗','song-poetry','','[]','俗物敗人意，淺陋欲曷澣。',132,'全唐诗/poet.song.176000.json','["俗物敗人意，淺陋欲曷澣。", "吾行半天下，綿邈歲月嬾。", "空空持一身，貿貿著兩眼。", "心知瑚璉珍，黄流在中瓚。", "良玉豈易逢，金鑄得亦罕。", "孰謂山之幽，因仍對茶椀。", "彼鬲乃爾奇，奚待識者斷。", "蕩掃盆盎空，儼雅古風滿。", "文篆異代遠，姑以耳目限。", "天大寰海波，窺測笑蠡管。", "傳觀用燎沉，留連爲之款。"]'),
('b7c2e70f-3537-4c3d-a5e5-4cb4c2a8e7e6','子任處晦子潜各分韵於杰上人房','韓淲','宋','宋诗','song-poetry','','[]','雲房見山僧，心中與之然。',36,'全唐诗/poet.song.176000.json','["雲房見山僧，心中與之然。", "朋來二三子，亦與同醉眠。", "是事夫如何，未許醒者傳。"]'),
('bf63a0c1-347f-44bc-9a10-9bdc8d9607de','休上人寄鮑侍郎誦之因借其韵','韓淲','宋','宋诗','song-poetry','','[]','傳芭兮擷英，隕葉兮槁莖。',48,'全唐诗/poet.song.176000.json','["傳芭兮擷英，隕葉兮槁莖。", "美人天一方，失勢名不榮。", "暑風自南至，凉月向西生。", "良圖彌用勵，意氣人命傾。"]'),
('4c4509b0-85ce-4c84-a98b-6604faf01bb8','爲寺僧分韵得禪字','韓淲','宋','宋诗','song-poetry','','[]','車馬何方來，花溪響林泉。',48,'全唐诗/poet.song.176000.json','["車馬何方來，花溪響林泉。", "晏叟送遺民，自然吟其天。", "顧我粥飯僧，豈了文字禪。", "且爲作餠供，晴軒少回旋。"]'),
('702c57ec-f201-4e57-b00a-5f2109d731fe','正月廿七日和林祕書賀雪日所賦','韓淲','宋','宋诗','song-poetry','','[]','麤官居隘巷，聽雪補蒲團。',96,'全唐诗/poet.song.176000.json','["麤官居隘巷，聽雪補蒲團。", "坐久吻悲鳴，俄而想天關。", "其誰劍佩履，正爾於清班。", "飄飄蓬萊仙，地位尤高寒。", "表瑞祈豐登，蓋爲稼穡艱。", "步趨夔龍後，心寄陶柳間。", "塵凡如我儂，尚許窺一斑。", "人和則氣和，穹昊初匪慳。"]'),
('63afa226-0295-445d-b9b6-d97e9937e417','分韵得屏字','韓淲','宋','宋诗','song-poetry','','[]','雨聲心自醒，山色眼中青。',48,'全唐诗/poet.song.176000.json','["雨聲心自醒，山色眼中青。", "雌霓殷殘照，雄風寫疎星。", "捉筆賦磊磈，行盃笑零丁。", "坐久屢更僕，一任僵觸屏。"]'),
('b607bf22-6260-4edc-ae7e-49f436a74a45','同昌甫坐雪觀看權巽中詩因和其雪句','韓淲','宋','宋诗','song-poetry','','[]','雪中來雪觀，談妙非波旬。',84,'全唐诗/poet.song.176000.json','["雪中來雪觀，談妙非波旬。", "山僧亦攝衣，兩手揖座人。", "似以眼諭心，謂言在茲辰。", "况復章泉翁，蒼華岸烏巾。", "知我所居近，喜我與寺隣。", "共翻瘦權詩，一條綺麗塵。", "是事夫如何，歲寒梅自春。"]'),
('a010971e-f785-4f9c-a524-f7719bedd917','趙倅古句見寄和答','韓淲','宋','宋诗','song-poetry','','[]','出門非有礙，何地著老身。',108,'全唐诗/poet.song.176000.json','["出門非有礙，何地著老身。", "幸哉倚樓仙，乃不嫌我真。", "時時寫興來，憂道不憂貧。", "較彼肉食鄙，未知隔幾塵。", "浩蕩如白鷗，信矣誰能馴。", "餘干相國家，世代常有人。", "上饒監郡尊，尚許閒者親。", "更語春山君，扶藜整紗巾。", "詩情復如何，柰此寂寞濱。"]'),
('35792a64-e935-48fb-b5a7-2ff5c2c15396','微祿弟有微祿養閒靜之嘲因足成篇','韓淲','宋','宋诗','song-poetry','','[]','微祿養閒靜，冉冉驚老境。',48,'全唐诗/poet.song.176000.json','["微祿養閒靜，冉冉驚老境。", "誰知歲月速，復此霜露冷。", "齒髮墮江湖，家世本箕潁。", "無效彭澤翁，茫然弔形影。"]'),
('93c6183c-c1df-4293-be0c-a00d7b469376','和江文通擬休上人詩韵','韓淲','宋','宋诗','song-poetry','','[]','日夕北風起，叩角何悲哉。',84,'全唐诗/poet.song.176000.json','["日夕北風起，叩角何悲哉。", "所思不可見，只有飛雪來。", "林聲方凄冽，溪光正徘徊。", "短衣挽莫前，匣鏡那忍開。", "空對翠屏晚，寒雲遶南臺。", "茶竈熅宿火，禪龕拂新埃。", "江東憶李白，今古同此懷。"]'),
('213256a9-a24f-4e0e-a0dc-343516670008','乙上人郡請住鵝湖不往','韓淲','宋','宋诗','song-poetry','','[]','爲人不爲人，衆聖已推出。',96,'全唐诗/poet.song.176000.json','["爲人不爲人，衆聖已推出。", "稻麻竹葦蔗，處處祗教律。", "偉哉棒喝邊，密中之秘密。", "拈花既成果，如雲而見日。", "鵝湖大義禪，法身尚巖室。", "喚回鐘鼓醒，都在一楖栗。", "我今非勸請，亦豈弄吟筆。", "稽首大德尊，身口意無逸。"]'),
('eb42e08c-96d8-44ea-abee-bbaef29aae86','凈慈西堂簡敬叟','韓淲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西菩無道潜，西林無義銛。',96,'全唐诗/poet.song.176000.json','["西菩無道潜，西林無義銛。", "兩山錢塘湖，魚鳥空毫纖。", "咄哉簡敬叟，老醜復何有。", "火燄裏翻身，冷地裏合口。", "誰謂天地大，而今歲月淹。", "冬寒倍冽冽，夏暑常炎炎。", "衆生難化度，少病少魔否。", "引領而望汝，平荷蔭堤柳。"]'),
('f132ab13-ac1c-4e33-9312-2605b0717561','諸葛解元家分韵','韓淲','宋','宋诗','song-poetry','','[]','溪橫葛陂水，上有稚川宅。',48,'全唐诗/poet.song.176000.json','["溪橫葛陂水，上有稚川宅。", "歡言一壺酒，未覺千歲隔。", "詩經茱菊節，人語風雨夕。", "雅俗調本殊，奚止相什百。"]'),
('6058af92-3c1b-4b9f-8e4f-801e450d9438','有懷連長老和韵劉推官','韓淲','宋','宋诗','song-poetry','','[]','周賓既已往，舊話三十年。',60,'全唐诗/poet.song.176000.json','["周賓既已往，舊話三十年。", "清哉卓庵地，龕燈照雲泉。", "故友獨此翁，老大窮當堅。", "一身鹿覆蕉，百計蟻磨旋。", "詩來起我思，山澤龐眉僊。"]'),
('f65215ee-ffb8-4fca-a398-57c49acf321c','元默書來作溪翁亭成且索詩因寄四章  其一','韓淲','宋','宋诗','song-poetry','','[]','潛山之水兮流幽幽，溪翁何在兮流不休。',41,'全唐诗/poet.song.176000.json','["潛山之水兮流幽幽，溪翁何在兮流不休。", "昔之隠於此地兮將何求，後世之人兮因築亭以遨遊。"]'),
('f7c3c2c3-9ad3-4955-8c7f-28602202d318','元默書來作溪翁亭成且索詩因寄四章  其二','韓淲','宋','宋诗','song-poetry','','[]','潛山之水兮聲潺潺，溪翁何在兮聲可觀。',41,'全唐诗/poet.song.176000.json','["潛山之水兮聲潺潺，溪翁何在兮聲可觀。", "昔之隠於此地兮應甚安，後世之人兮因名亭以考槃。"]'),
('c7c011f1-32a6-45bf-a991-011b7926e2d5','元默書來作溪翁亭成且索詩因寄四章  其三','韓淲','宋','宋诗','song-poetry','','[]','潛山之水兮波渙渙，溪翁何在兮波可玩。',41,'全唐诗/poet.song.176000.json','["潛山之水兮波渙渙，溪翁何在兮波可玩。", "昔之隠於此地兮信無患，後世之人兮因登亭以蕭散。"]'),
('2f049cdd-c21f-4c04-9090-0f7136463576','元默書來作溪翁亭成且索詩因寄四章  其四','韓淲','宋','宋诗','song-poetry','','[]','潛山之水兮源遠遠，溪翁何在兮源不見。',41,'全唐诗/poet.song.176000.json','["潛山之水兮源遠遠，溪翁何在兮源不見。", "昔之隠於此地兮自無怨，後世之人兮因茲亭以繾綣。"]'),
('a1183ba2-709c-4ef5-98a2-048a5f255164','春風歌','韓淲','宋','宋诗','song-poetry','','[]','歌春風，柳條微綠杏花紅。',60,'全唐诗/poet.song.176000.json','["歌春風，柳條微綠杏花紅。", "小園曲逕草茸茸，蝴蝶高下飛遊蜂。", "澗邊流水鳴琤琮，斜日正在林影中。", "遊人醉倒歡意融，夢魂飛入東華宮。"]'),
('fa856b34-28b4-43ad-a3e9-f3032509521f','太白襄陽歌圖','韓淲','宋','宋诗','song-poetry','','[]','謫仙非詩畫非畫，山簡襄陽別有話。',64,'全唐诗/poet.song.176000.json','["謫仙非詩畫非畫，山簡襄陽別有話。", "空令江左作圖看，竹院留藏我悲咤。", "傳聞邊頭腥甲兵，峴首依前漢水清。", "隻輪不返邊塵掃，莫負當年力士鐺。"]'),
('a25e0e2b-851f-4f20-af94-bc148dcc47f8','詠陶弘景','韓淲','宋','宋诗','song-poetry','','[]','山中宰相陶隠居，所注本草將何如。',128,'全唐诗/poet.song.176000.json','["山中宰相陶隠居，所注本草將何如。", "更題真誥作神遇，佳夢是實寧非虛。", "人生形神爲幹軀，心欲造設氣乘除。", "瞬息變幻爭奪途，入山何難可躊躇。", "玉波流煙照林廬，嵐影爽氣歸衣袪。", "晏起早卧食息餘，三景九道回八區。", "一再傳其坐忘歟，俛仰今昔多憂虞。", "榮名中人天機淺，言與不言養恬愉。"]'),
('a9147ac8-c1af-4ff4-975c-f4939dd648e2','昌甫題西洛遺民詩卷并所書杜句','韓淲','宋','宋诗','song-poetry','','[]','東里感興西洛詩，其年憂國初南來。',112,'全唐诗/poet.song.176000.json','["東里感興西洛詩，其年憂國初南來。", "後人玩之可忘疲，甚矣世變非吾衰。", "長言短句筆墨古，顛倒妙處誰能窺。", "雨凉梅熟樽酒地，舊人家藏欣見之。", "其間亦錄杜陵老，牋闊軸大何爾爲。", "要知真識未易見，我乃徵逐於茲時。", "瀟湘莫結遺民悲，信誠空歎晏叟癡。"]'),
('3019591e-945d-4b27-b6d2-0ddcacf64a47','書姜白石昔遊詩後','韓淲','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u8861\u5c71", "\u6d1e\u5ead\u6e56"]','平生未踏洞庭野，亦不曾登南嶽峰。',220,'全唐诗/poet.song.176000.json','["平生未踏洞庭野，亦不曾登南嶽峰。", "因君談舊遊，恍如常相從。", "江淮歷歷轉湘浦，裘馬意氣傳邊烽。", "吾嘗汎大江，祇見匡廬松。", "乘風醉卧帆影底，高浪直濺嵐光濃。", "日暮泊船時，是時方嚴冬。", "雪花壓船船背重，纜摇舵鼓聲如鐘。", "當年意淺語不到，無句可寫波濤舂。", "君詩乃如許，景物不易供。", "盡歸一毫端，狀出三飛龍。", "人間勝處貴著眼，雖有此興無由逢。", "錢唐山水亦自好，奈何薄宦難從容。", "南高北高一千丈，潮頭日夜鳴靈蹤。", "應有隠者爲識賞，青鞋布襪扶杖筇。", "君無詫彼我愧此，急還詩卷心徒忪。"]'),
('adc90fd7-a8ba-45e4-88ff-756b19dfe8f7','陸丈劍南詩斯遠約各賦一首','韓淲','宋','宋诗','song-poetry','','[]','鏡湖湖上涼風起，楓葉蘆花照窗几。',160,'全唐诗/poet.song.176000.json','["鏡湖湖上涼風起，楓葉蘆花照窗几。", "筆牀茶竈連酒壺，炯然目光動秋水。", "平生北固與西江，贏得蚍蜉事訾毀。", "青城山嘴散關頭，豈是甘心放豪侈。", "歸來玉階僅方寸，兩路又出將使指。", "幾回詔節去徘徊，慍色何曾爲三已。", "桐廬瀟灑非小壘，更向南宮擅詞美。", "軒渠肯受塵鞅羈，漢庭公卿未知己。", "我閒訪友於溪居，三嘆共讀公之書。", "清詩句句律有餘，愛而不見今何如。"]'),
('badeeb66-1353-4f46-8945-f2a7d4d9970c','趙將示及吳推官詩','韓淲','宋','宋诗','song-poetry','','[]','玉溪蓮幕哦詩聲，聲和水南松竹清。',64,'全唐诗/poet.song.176000.json','["玉溪蓮幕哦詩聲，聲和水南松竹清。", "眼中孰不有言句，句到極則何能聽。", "衡茅吹寒日惆悵，倚樓公子猶相訪。", "袖裏新篇乃若人，春風翡翠蘭苕上。"]'),
('643db80c-3ad6-4a71-a591-f012cf81ae2a','元夕夜坐觀黄庭經','韓淲','宋','宋诗','song-poetry','','[]','虛簷湧月垂小窗，屋外有山流澗江。',128,'全唐诗/poet.song.176000.json','["虛簷湧月垂小窗，屋外有山流澗江。", "夜氣少定百念降，膝席引手挑油缸。", "靜取黄庭誦琅琅，爐煙噴結柏子香。", "上元仙官朝紫皇，九關洞開鳳鸞翔。", "清輝影導胎禽雙，前昂後低幡節幢。", "塵間如帑正紛厖，眇然駢羅萬家邦。", "形軀已經幾星霜，回思淡薄天人糧。", "却滅百邪致欣昌，收聲藏神味差長。"]'),
('d3761aac-fdef-40b3-9513-4b0a0d74e2fb','上饒出示仲至遺畫','韓淲','宋','宋诗','song-poetry','','[]','我識睡翁尤更早，翁今死矣我已老。',64,'全唐诗/poet.song.176000.json','["我識睡翁尤更早，翁今死矣我已老。", "寥寥故家鄆東平，麗澤淵源有深抱。", "睡翁又號曰粟齋，餘事書帖亦可懷。", "摩挲展轉心眼開，此道於人何有哉。"]'),
('ac28cdab-920a-442c-84e9-00c36c18bfd8','張果老小刻','韓淲','宋','宋诗','song-poetry','','[]','張果老馿兒，開元天寶時。',42,'全唐诗/poet.song.176000.json','["張果老馿兒，開元天寶時。", "三郎非仙才，此老戲之如小兒。", "異代想像空好奇，莫解莫說且莫知。"]'),
('4cdc5325-8c6f-49ba-82d7-ec7c8f9d3251','寫捕魚雪圖軸','韓淲','宋','宋诗','song-poetry','','[]','前村後村雪糢糊，漁家敗屋臨江湖。',64,'全唐诗/poet.song.176000.json','["前村後村雪糢糊，漁家敗屋臨江湖。", "綸收網結閉門坐，樹籬草岸炊煙孤。", "波停水凍魚不食，平者爲沙高者石。", "可惜都無一句吟，筆幻生綃定誰識。"]'),
('4b9e158c-601f-4d11-a83c-b1c4d2531989','馬圖云韓幹筆','韓淲','宋','宋诗','song-poetry','','[]','韓幹畫肉不畫骨，騣尾蕭騷倏超忽。',64,'全唐诗/poet.song.176000.json','["韓幹畫肉不畫骨，騣尾蕭騷倏超忽。", "世間凡馬徒區區，筆底丹青色尤勃。", "風塵澒洞心力短，世代推遷辭氣訥。", "鷹鶩相呼可奈何，金粟堆前龍蕩窟。"]'),
('0e7e123c-55c5-4cc7-b5f8-276af5eba3a2','成趣園','韓淲','宋','宋诗','song-poetry','','[]','徐子筆端妙天下，成趣園成記如畫。',128,'全唐诗/poet.song.176000.json','["徐子筆端妙天下，成趣園成記如畫。", "丹青寫就未必工，裝點鋪模誠可詫。", "試問園中今幾春，主人種花花正新。", "高帝子孫氣象偉，等閒卜築冰溪濱。", "道南推託借誰住，只爲記中多好句。", "幾回相與酒盃空，梅月柳風吹杏雨。", "淵明此趣非偶然，請君醉中知其天。", "我閑杖屨猶翩翩，莫教俗事來眼前。"]'),
('5152ce1d-0289-47b0-8a6c-d9f5899cb771','二日陳主簿山園','韓淲','宋','宋诗','song-poetry','','[]','芳尋梅山上春浦，夾道繁花何用許。',64,'全唐诗/poet.song.176000.json','["芳尋梅山上春浦，夾道繁花何用許。", "晴風暮日藹微宇，佳處留連因語語。", "夫君易學誠可數，盤折崛峍非媚嫵。", "叫閽歸來心獨苦，酒飲我時無道古。"]'),
('69bfeecb-3698-4cdc-95d2-7ac4b7b8b0e8','松棚','韓淲','宋','宋诗','song-poetry','','[]','去年一旱暍欲死，猶幸春來能忍饑。',128,'全唐诗/poet.song.176000.json','["去年一旱暍欲死，猶幸春來能忍饑。", "長夏因仍作涼計，中庭始架青松枝。", "門前催租急非緩，國中遺誥安若危。", "貧無輸官尚自可，忠欲輸君今已遲。", "風來蕭蕭悲益甚，日遠茫茫愁不知。", "誰謂身閒得放逸，家國一體人弗思。", "雲開空山久闕雨，蟬噪古木還迎曦。", "松枝松枝綠差差，吾忍坐卧來樂斯。"]'),
('8dc8684e-7138-453d-97eb-5ea9ae88d575','登曬簑臺','韓淲','宋','宋诗','song-poetry','','[]','半村臺上看曬簑，風日清美奈翁何。',64,'全唐诗/poet.song.176000.json','["半村臺上看曬簑，風日清美奈翁何。", "山空無雲江不波，老來漁釣閒婆娑。", "門前車馬誰經過，取濁酒飲健句哦。", "我雖不言興已多，却因此翁思老坡。"]'),
('0c91d922-a20c-49bb-b7bd-47959b3ff5ed','題潘舍人小月巖','韓淲','宋','宋诗','song-poetry','','[]','山石漠漠明寒煙，望中一見心凄然。',64,'全唐诗/poet.song.176000.json','["山石漠漠明寒煙，望中一見心凄然。", "平生玉斧修未圓，幾年只在靈溪邊。", "長安人家雜塵土，驚怪轉庵能斷取。", "知君詩眼留萬古，不待四更看月吐。"]'),
('c5240562-1662-4e68-b06f-2ebdcbc3e525','寒綠張堯臣以道之居','韓淲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雪窗有第名寒綠，墜緒旁搜善能續。',64,'全唐诗/poet.song.176000.json','["雪窗有第名寒綠，墜緒旁搜善能續。", "人間此味甘如飴，采擷行吟應自足。", "肯羨西湖多厦屋，只爲南湖生杞菊。", "春風閒煮折脚鐺，不信從前祇蘇陸。"]'),
('b81982a2-26c7-4a43-af33-5145095ad2ab','伯皋索題真益齋語蓋以後山詩爲名','韓淲','宋','宋诗','song-poetry','','[]','彭城居士意甚遠，彼自丹青金石苑。',64,'全唐诗/poet.song.176000.json','["彭城居士意甚遠，彼自丹青金石苑。", "平生心力漫收斂，眼所到處聊排遣。", "伯皋伯皋真有益，此語令我長太息。", "南渡草草今百年，笑倒米家書畫船。"]'),
('dd1b5050-3dd9-47bb-b087-39ce6d3c660b','銅官富覽亭','韓淲','宋','宋诗','song-poetry','','[]','暮天不盡山明滅，文物從容兩奇絕。',64,'全唐诗/poet.song.176000.json','["暮天不盡山明滅，文物從容兩奇絕。", "射江返照魚舸輕，隔岸人家炊煙發。", "依依柳色草青青，一曲風前韵清越。", "醉歸飛夢遶庭皋，樂處十年待君說。"]'),
('71060fb7-48c0-4f10-b88c-47d02022f5d7','山翁亭','韓淲','宋','宋诗','song-poetry','','[]','東山高處山翁亭，羣峰巉絕環障屏。',64,'全唐诗/poet.song.176000.json','["東山高處山翁亭，羣峰巉絕環障屏。", "遠者紫翠近者青，天淡淡兮風泠泠。", "人間紛如凡骨腥，我欲飛仙跨雲軿。", "問翁何在遊帝庭，寒氣倏然驚酒醒。"]'),
('4b1973c0-c5a9-4e6b-874b-3bacd1402991','走筆戲詠散庵','韓淲','宋','宋诗','song-poetry','','[]','結庵名散將何爲，心散意散空自知。',64,'全唐诗/poet.song.176000.json','["結庵名散將何爲，心散意散空自知。", "等閒收拾到窗戶，草木亦覺風披披。", "浮世徒爾相拘束，達人大觀歲月速。", "有時散蕩吟一詩，詩與此庵無盡期。"]'),
('20fe48e2-d3e5-49ca-b0af-bdf186bef792','題野翁亭','韓淲','宋','宋诗','song-poetry','','[]','岝崿峰前野翁亭，溪聲常在山常清。',64,'全唐诗/poet.song.176000.json','["岝崿峰前野翁亭，溪聲常在山常清。", "我來尚想坡仙靈，刁令遺事猶芳馨。", "寒煙濃淡晚雨零，主人醉客客未醒。", "他時此地誰重經，俛仰今昔俱忘形。"]'),
('a58a232a-107c-4a9b-9f5a-167165ce0e9f','招真巖','韓淲','宋','宋诗','song-poetry','','[]','蒼崖松聲風泠泠，心高太虛望青冥。',96,'全唐诗/poet.song.176000.json','["蒼崖松聲風泠泠，心高太虛望青冥。", "幽尋王君集山靈，古井方池誰招真。", "金沙嶺頭淨無塵，呼吸風光聚精神。", "開合陰陽三尸驚，逍遥吟哦黄庭經。", "青蕊琳琅潛玄英，扶摇三光駕雲駢。", "羽衣翩躚上圓清，我輩豈是區中人。"]'),
('cae1db83-8707-4cc9-891c-4d81c1037255','草堂','韓淲','宋','宋诗','song-poetry','','[]','杜陵柟樹草堂前，至今物色歸吟邊。',64,'全唐诗/poet.song.176000.json','["杜陵柟樹草堂前，至今物色歸吟邊。", "玉溪清泚太霞仙，我亦見之誰謂然。", "書窗明明有公子，坐對新詩發瓊蘂。", "春雲靄空風過耳，爲作匾名識其美。"]'),
('49a6d40a-9973-4b42-a381-00e6edd6738c','赭亭山白雲寺','韓淲','宋','宋诗','song-poetry','','[]','風霜高潔天意寒，捫蘿石壁不作難。',64,'全唐诗/poet.song.176000.json','["風霜高潔天意寒，捫蘿石壁不作難。", "躋攀古寺地陡寬，中有定僧瑣玄關。", "靜聽鳥聲人意閑，六塵掃除法觀還。", "驀地整履還下山，世緣禪機無兩般。"]'),
('36629800-0bfd-4528-a960-c521270eb569','海南思南豅正花欲過趙閣亦倦','韓淲','宋','宋诗','song-poetry','','[]','春遊花時海棠醉，夾道排空轉佳麗。',128,'全唐诗/poet.song.176000.json','["春遊花時海棠醉，夾道排空轉佳麗。", "燕支豐頰嬌未醒，翡翠輕鬟愁欲墜。", "牡丹風裏晚煙明，薔薇露邊初日媚。", "山豅深靜自成家，池閣幽閑誰近市。", "是中人物多情致，賸擬芳尋爲出計。", "路塵獨怯過城闍，遠水孤舟那得至。", "芳菲易歇興終闌，識賞難同吟且寄。", "蹊間桃李豈無言，草木何知吾亦戲。"]'),
('1c63ad2e-bea3-4ffd-beb0-d137b67ebdd5','魚莊午睡','韓淲','宋','宋诗','song-poetry','','[]','魚莊借榻眠春風，湖吹晚煙波拍空。',64,'全唐诗/poet.song.176000.json','["魚莊借榻眠春風，湖吹晚煙波拍空。", "是中祇可飲醇酎，摩挲醉眼花能紅。", "兩峰高高浴鳬亂，杜若汀前楊柳岸。", "相逢君嬾我更閑，不用長歌白石爛。"]'),
('0b94d6a8-2f5b-478b-9cbb-031eccac8149','歸舟過東流丘簿清足軒','韓淲','宋','宋诗','song-poetry','','[]','倚船江頭看修竹，誰家有軒號清足。',64,'全唐诗/poet.song.176000.json','["倚船江頭看修竹，誰家有軒號清足。", "敲門應喜故人來，一飯從容可無肉。", "春風桃李徒紛紛，獨抱勁節惟此君。", "自公退食且嘯咏，他日得時能拂雲。"]'),
('429443eb-209e-4bda-8766-1248b3964623','曉步','韓淲','宋','宋诗','song-poetry','','[]','家在溪南山下住，清曉西風生杖屨。',64,'全唐诗/poet.song.176000.json','["家在溪南山下住，清曉西風生杖屨。", "鄰翁相見笑相呼，春雪滿甌香似霧。", "屋頭種竹池養蓮，林深古井多寒泉。", "坐談不覺天已暮，秋入斷霞孤鶩邊。"]'),
('8268029b-974d-4bc5-bf50-38221700dc23','曉起','韓淲','宋','宋诗','song-poetry','','[]','煙雲未收天未明，眼頭依依带疎星。',64,'全唐诗/poet.song.176000.json','["煙雲未收天未明，眼頭依依带疎星。", "行人道路貪起程，戍樓鼕鼕殺五更。", "青山漸出一溪綠，溪面橫舟山有屋。", "紅光扶日升暘谷，且聽吾歌紫芝曲。"]'),
('5a755a38-91b8-4cd9-b4aa-4e95680951d6','北窗夜卧納凉','韓淲','宋','宋诗','song-poetry','','[]','暮煙和角带疎鐘，修竹軒窗一枕風。',64,'全唐诗/poet.song.176000.json','["暮煙和角带疎鐘，修竹軒窗一枕風。", "月淡天高雲弄影，紗幮如水半曛中。", "夜深便覺涼無暑，庭戶惟聞草蟲語。", "參橫斗轉已三更，露氣襲人欲輕舉。"]'),
('5b71c121-39c7-4d44-93ae-77a96c59d0bd','同周兄南仲遊滄浪','韓淲','宋','宋诗','song-poetry','','[]','滄浪之居蘇子美，滄浪之水僅清泚。',128,'全唐诗/poet.song.176000.json','["滄浪之居蘇子美，滄浪之水僅清泚。", "闔廬城中今何年，宛轉依稀無乃是。", "石鑿鑿兮岸靡靡，紫荇浮煙復雲委。", "林空鳴禽時感耳，我亦爲渠聊步屣。", "千古萬古一長史，非網打盡那得爾。", "清風明月誰匪閑，同遊之者子周子。", "青春已深炫桃李，寒食清明數日裏。", "滄浪之水不可比，滄浪之歌不可擬。"]'),
('fe2189dc-ba57-495e-819b-f4f393f84e66','文叔折柬誇其夜宿湖心午登南屏石洞納凉','韓淲','宋','宋诗','song-poetry','','[]','落殘明月照湖心，小艇揚波荷氣深。',96,'全唐诗/poet.song.176000.json','["落殘明月照湖心，小艇揚波荷氣深。", "誰能一枕華胥夢，占得其清無暑侵。", "長飈撼石應真洞，淨慈高絕南山陰。", "齋盂茗椀復宴坐，了義不必開禪林。", "老身執熱困塵屋，偪塞嘈雜蹏足音。", "櫟庵受用乃如此，斫額望之聊自吟。"]'),
('c0f69516-9741-4e46-b530-bb020d3ec014','趙十同飲','韓淲','宋','宋诗','song-poetry','','[]','君家兄弟非他人，與爾同寓冰溪濱。',64,'全唐诗/poet.song.176000.json','["君家兄弟非他人，與爾同寓冰溪濱。", "醉吟浪宕只這是，天地混沌疑非真。", "琢得一句兩句出，未必魂魄無精神。", "知我罪我春秋經，王覇隆替俱埃塵。"]'),
('fb8b2a48-bbf2-4c62-ad90-7e0e8101c507','昨日過沈兄無隠邂逅楊溥子亦來溥子携酒就無隠飲余酒行頗虐病不勝焉席間先逸作詩道謝意','韓淲','宋','宋诗','song-poetry','','[]','落葉紛委山路榛，飯餘試作捫腹行。',144,'全唐诗/poet.song.176000.json','["落葉紛委山路榛，飯餘試作捫腹行。", "人家有竹不可款，負郭乃得席作門。", "座中邂逅執戟孫，携尊更約重論文。", "青橙紫蟹亦俱設，愧謝子意因余勤。", "諸公飲量江海吞，我病忽苦頭岑岑。", "不如淵明醉遣客，乃效灌夫觴貴人。", "懸知事急起排闥，君更追路仍挽襟。", "吾曹相從貴真率，如此可畏還可欽。", "扶牀走筆道不敏，祗恐匹馬來三軍。"]'),
('31fa3799-3c70-4bac-ab2f-7e6e86ed8d05','入城晁尹二家少留','韓淲','宋','宋诗','song-poetry','','[]','我扶敗輿過溪北，城郭雖喧有書屋。',64,'全唐诗/poet.song.176000.json','["我扶敗輿過溪北，城郭雖喧有書屋。", "霜雲忽暗疑雪天，坐穩瓶梅蠟香撲。", "何許心情說餞歲，漫寫詩吟驚易俗。", "百年王謝幾人家，目斷蒼茫聽爆竹。"]'),
('a5b4666a-25dd-469b-87e5-70bfc314aae4','春浦門外看梅因飲宋氏小軒','韓淲','宋','宋诗','song-poetry','','[]','春晴晚步春浦門，小飲醉入梅花村。',64,'全唐诗/poet.song.176000.json','["春晴晚步春浦門，小飲醉入梅花村。", "繁香吹雪數十樹，青山遠近疎籬園。", "誰家水竹明窗軒，老我清坐俱忘言。", "須臾煙月光吐吞，歸哉樓角橫黄昏。"]'),
('70cf060e-def6-45dc-b30d-8414c79043fa','山間南圃海棠花開','韓淲','宋','宋诗','song-poetry','','[]','舍前舍後海棠紅，碧軒宛宛連霞宮。',64,'全唐诗/poet.song.176000.json','["舍前舍後海棠紅，碧軒宛宛連霞宮。", "浮光弄景雖带雨，睡思醉貌空臨風。", "雷輕霧暗時過前，無處告訴杜老顛。", "溪山深密春晝寂，花撲一澗飛來泉。"]'),
('79b5af09-eec1-4f4c-b261-77de3e0d6545','梅枝','韓淲','宋','宋诗','song-poetry','','[]','今年未見梅花好，竹外溪頭春自早。',64,'全唐诗/poet.song.176000.json','["今年未見梅花好，竹外溪頭春自早。", "滿瓶夭嬌送香來，照坐淋漓拚醉倒。", "瓊林飛出蒼精龍，朔雪未下風滿空。", "笑指蓬萊清淺水，連雲瑣斷最高峰。"]'),
('4cd07f32-1735-487c-b26e-59908f319e55','謝昌甫茶且囑同往來諸友飲之','韓淲','宋','宋诗','song-poetry','','[]','山翁包題抵書信，盥掌剝封乃茶茗。',64,'全唐诗/poet.song.176000.json','["山翁包題抵書信，盥掌剝封乃茶茗。", "更看健句團筆陣，得之足以忘食寢。", "清風兩腋何敢辜，常日諸人當聚飲。", "陸子泉頭活火煎，一啜須令各蘇醒。"]'),
('c353caef-d374-466c-8f15-45ac09e92b24','昌甫寄酒蛤辣螺新蟹皆山味所久無','韓淲','宋','宋诗','song-poetry','','[]','蛤蜊因酒得天全，踞無龜殻吾非仙。',96,'全唐诗/poet.song.176000.json','["蛤蜊因酒得天全，踞無龜殻吾非仙。", "六跪二螯猶回旋，左手急持思拍船。", "螺之辣者真海鮮，每或酌侑能醒然。", "竹隠君其詩中權，知我托落醉欲眠。", "走送三物寸簡傳，青燈山牖瓶梅邊。", "食之既矣吟一篇，比耶興耶今何年。"]'),
('f12b9881-e121-4fd6-a319-d23ebad832bd','昌甫寄栗','韓淲','宋','宋诗','song-poetry','','[]','整整斜斜一書尺，磊磊落落滿包栗。',64,'全唐诗/poet.song.176000.json','["整整斜斜一書尺，磊磊落落滿包栗。", "霜風朝來吹我急，且向葉爐煨煮喫。", "高人知我老無力，跧伏寒溪少出入。", "慇勤題裹墨猶濕，雨峰高哉翠雲滴。"]'),
('7b6fad6f-b730-44d3-b186-288a7472d62e','謝黄子耕惠紙被時在錢塘乍冷無衾窘甚','韓淲','宋','宋诗','song-poetry','','[]','西江寒籐濯清冰，擣成楮衾起霜稜。',160,'全唐诗/poet.song.176000.json','["西江寒籐濯清冰，擣成楮衾起霜稜。", "朱門鼎食笑弗顧，只有蕙帳眠山僧。", "精緻不數氈毯厚，潔淨未必綾錦能。", "禦冬氣清神煜煜，煖老體輕夢騰騰。", "幽人玩之喜欲舞，可與飲水同曲肱。", "江夏無雙知此意，又見寒來祇布被。", "吳山客舍久窮愁，帝城貴家誰顧視。", "急呼大兒開篋箱，取以贈吾真雅遺。", "拂拭牀間時自思，展轉枕邊誠有愧。", "當如此衾堅且白，身外輕肥皆棄置。"]'),
('939e68c2-d72a-4eab-884a-1317a768c010','尹子潛送蕨','韓淲','宋','宋诗','song-poetry','','[]','老來爲腹不爲目，薄飯盤蔬亦云足。',128,'全唐诗/poet.song.176000.json','["老來爲腹不爲目，薄飯盤蔬亦云足。", "成年準擬薇蕨甜，那計人間有粱肉。", "二月三月春已深，靈山土肥皆去尋。", "長莖短朿挂蘿檐，出市不直三數金。", "隨流揚波淨挼洗，芼以薑鹽付鐺耳。", "生柴带葉旋抽添，糟莩曠沈時染指。", "晨光破甑炊浮浮，稻香菜軟吾何憂。", "人可以食鮮知味，請聽以氣專致柔。"]'),
('0aa35e63-f040-4ff7-8431-5db7acd4282f','送十瓜十梅易十竹於鄭一','韓淲','宋','宋诗','song-poetry','','[]','十瓜十梅得十竹，君應笑我喜可掬。',64,'全唐诗/poet.song.176000.json','["十瓜十梅得十竹，君應笑我喜可掬。", "芳華春育豈凡同，苦節冬藏惟勁獨。", "取才要記自高臺，著實能忘本深谷。", "寄謝悠悠莫驚嗤，草木無情山澗綠。"]'),
('cac060cb-8467-49d2-8264-ba63a58f3a02','昌甫送松溪茶蓋云得之晁丈','韓淲','宋','宋诗','song-poetry','','[]','章泉寄我松溪茶，北苑雙井未足誇。',144,'全唐诗/poet.song.176000.json','["章泉寄我松溪茶，北苑雙井未足誇。", "蓋以人勝茶亦勝，况復二老文章家。", "松溪主人未識面，每鄉往之而咨嗟。", "想見讀書坐清晝，薰風兩鬢生霜華。", "趙晁婣睦久同志，近知往詣情愈嘉。", "慇懃包裹得此茗，歸來奚忍自啜耶。", "憐我於晁頗臭味，一旦拜此忻無涯。", "亟呼童奴取活水，烹煎試起瓊玉花。", "不但愛此瓊玉花，茶因人勝無以加。"]'),
('ed5056b1-71a5-45b3-8847-eccf29393079','人身','韓淲','宋','宋诗','song-poetry','','[]','人身一飽百不憂，行住坐卧本何求。',64,'全唐诗/poet.song.176000.json','["人身一飽百不憂，行住坐卧本何求。", "冷煖大冬與大夏，盛衰三春及三秋。", "蒼蒼雲山緩曳杖，茫茫煙水輕拏舟。", "喜怒哀樂在中節，生兮若浮死若休。"]'),
('3ff3ea55-ee90-4855-82b3-944b0ef991cb','初九日夜坐','韓淲','宋','宋诗','song-poetry','','[]','去冬十月已飛雪，於潛滿縣層冰結。',192,'全唐诗/poet.song.176000.json','["去冬十月已飛雪，於潛滿縣層冰結。", "空齋老樹號朔風，客枕欲僵衾楮裂。", "主人猶有酒澆愁，旦起相呼相煖熱。", "坐中劉郎氣最高，抵掌歌詩雜言說。", "流光不覺小至近，澗路摧頹門半閉。", "兩年心事夜如何，窗撼山林聲又別。", "牀頭兒啼衣尚單，竈下婢苦柴未爇。", "麤官寸祿闕既遠，故舊尺書音更絕。", "薄田舂米雨不來，欲釀一杯無麯糵。", "蕭然默數長短更，惟恐寒氣吹燈滅。", "明當一水瀉清泠，會見四山高嵽嵲。", "重陰定自六出花，悵望同雲記捫舌。"]'),
('d4a32c07-b3bf-4f72-be11-134bba5ee540','重午','韓淲','宋','宋诗','song-poetry','','[]','鬢花臂絲盤艾虎，佳人競云作重午。',64,'全唐诗/poet.song.176000.json','["鬢花臂絲盤艾虎，佳人競云作重午。", "菖蒲細縷來泛巵，快意酒行何用數。", "忽憶當年楚三閭，他愁我樂意何如。", "不識好惡類如此，世間俗物爭奈渠。"]'),
('2c46ecb1-7053-480c-8e0a-13466a48c08e','五日','韓淲','宋','宋诗','song-poetry','','[]','去年沙坑作重午，城下今年著船鼓。',64,'全唐诗/poet.song.176000.json','["去年沙坑作重午，城下今年著船鼓。", "過溪沿澗逢交遊，挈榼留杯失賓主。", "宣和曾带御書符，荆楚誰言長命縷。", "老因唐律爲沉吟，山隠輕雷催晚雨。"]'),
('857d04f4-8ffa-4ad0-8203-e1af1d9bc17c','十二月十二日雪','韓淲','宋','宋诗','song-poetry','','[]','欲雪既雪復未雪，短衣數挽從百結。',64,'全唐诗/poet.song.176000.json','["欲雪既雪復未雪，短衣數挽從百結。", "橫溪過澗起輕冰，舉首長歌時叫絕。", "莽莽歲寒殘臘月，梅花前村後村發。", "橋頭獨釣任漁翁，千山萬徑不可滅。"]'),
('b5e29a0a-c34e-4b9e-bbbe-7093d7da9a69','二十九日大雨','韓淲','宋','宋诗','song-poetry','','[]','錢塘禱雨上天竺，大士往來燒寶香。',64,'全唐诗/poet.song.176000.json','["錢塘禱雨上天竺，大士往來燒寶香。", "支郡神祠亦照答，自鳴山出氣蒼茫。", "風投襟袖带衣寬，短髮重搔爲整冠。", "待得成霖三日後，出門沿澗看清湍。"]'),
('85a3e1de-eed5-4d30-b654-ae4df57035d6','風雨','韓淲','宋','宋诗','song-poetry','','[]','風雨如晦雞既鳴，茅茨疎濕迷山楹。',64,'全唐诗/poet.song.176000.json','["風雨如晦雞既鳴，茅茨疎濕迷山楹。", "披衣不知所如往，爐存宿熅猶熒熒。", "水流花謝青春深，前村解橋隔孤城。", "庾郎鮭菜當用情，瓶粟更付折脚鐺。"]'),
('de4f8754-b02d-4ff5-adb7-846a8fa10595','十九日','韓淲','宋','宋诗','song-poetry','','[]','吹鼓打笛農禱雨，都道小禾遲者乾。',64,'全唐诗/poet.song.176000.json','["吹鼓打笛農禱雨，都道小禾遲者乾。", "高邙之田已如此，低漥晚稻難更看。", "官司只怕放苗頭，田里豈但餬口憂。", "政在養民舜之政，損下益上非所求。"]'),
('dc2d7eb7-368c-4bbf-8a29-9d23ff35c65e','霜寒','韓淲','宋','宋诗','song-poetry','','[]','沍寒日日霜如雪，地土縮高磚石裂。',144,'全唐诗/poet.song.176000.json','["沍寒日日霜如雪，地土縮高磚石裂。", "板橋積厚滑難乾，林葉有同裝玉屑。", "朝來負暄殊不暖，過午欲晡冰更結。", "無風亦覺氣酸然，只是水邊梅影別。", "一冬既雷仍既雨，僅可得晴霜未絕。", "家貧無人去拾柴，白屋何由生煖熱。", "且擁敗絮莫出門，欲賦江梅詩轉拙。", "細思雨霜豈常霜，須見陽和變時節。", "待他春色到人間，定自忘之都弗說。"]'),
('babf34cf-8f2a-4587-96f9-c5bdfb8b57b0','七日大雪浙江亭訪希之','韓淲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','江波沄沄山雪盛，寒霧不收潮風勁。',64,'全唐诗/poet.song.176000.json','["江波沄沄山雪盛，寒霧不收潮風勁。", "詩人與我把一杯，信道東南此爲勝。", "隔望遥知是剡中，坐看飄洒歸空濛。", "回首紛華車馬外，西湖雖好此無雄。"]'),
('3fe1959c-6b6a-4733-a770-229f4bda185a','十五日夜月蝕聞差中舍正言監測清臺','韓淲','宋','宋诗','song-poetry','','[]','慶元三年中元日，是夜更餘驚月蝕。',64,'全唐诗/poet.song.176000.json','["慶元三年中元日，是夜更餘驚月蝕。", "須知穢巷亦喧呼，見說清臺正推測。", "昏昏已作赤朱紅，閃閃猶成墨漆黑。", "磨刀急斬蝦蟇精，天眼光明無變色。"]'),
('c1b12977-91b5-4c75-8482-0ed0e59e2210','月溪清汎','韓淲','宋','宋诗','song-poetry','','[]','不奈江渾復林熱，長夏逃虛徒散髮。',160,'全唐诗/poet.song.176000.json','["不奈江渾復林熱，長夏逃虛徒散髮。", "扁舟何許可追涼，安得佳人弄明月。", "尋常浪飲苦匆匆，邂逅一遊多汩汩。", "日復日矣心轉癡，牽强而來終勃窣。", "琴堂有仙真好奇，簿書堆裏清興發。", "我雖老倦亦軒然，相與聽歌忘病暍。", "中流滉瀁已蒼茫，下瀨回沿應蕩淈。", "山高影翻棲鶻巢，潭澄光射鳴鼉窟。", "須臾斗柄插銀潢，常娥俯濯淩波襪。", "快呼天風駕雲濤，弱水三萬倏超忽。"]'),
('06c088d0-4b7b-4f0a-bbd8-cea7cfb4db73','和壁間林文節公韵','韓淲','宋','宋诗','song-poetry','','[]','浴溪橋上山岝崿，直下流波寒未涸。',64,'全唐诗/poet.song.176000.json','["浴溪橋上山岝崿，直下流波寒未涸。", "只宜墨客寄幽閒，不許行人動離索。", "草木黄落已變衰，晚風吹霜白雲歸。", "清暉如斯耿獨立，何處翩翩鷗鷺飛。"]'),
('4cddd4a1-50a7-4a3e-98d7-178f2ea0e5f3','和周次公','韓淲','宋','宋诗','song-poetry','','[]','坐卧一榻殊執熱，到手清言解煩結。',96,'全唐诗/poet.song.176000.json','["坐卧一榻殊執熱，到手清言解煩結。", "是誰所作疑彈丸，定自不凡如玉潔。", "昨夕之夕飲固多，今日之日調則別。", "山園空瑣楚臺風，水路猶思剡溪雪。", "須知野老本憂深，何事騷人更愁絕。", "題輿倒載真世賢，伯仁可與智者說。"]'),
('26cbedf4-3f33-4046-ab6d-ed46bc5201c8','二十一日同昌甫鎮頭和森桂時齋之句','韓淲','宋','宋诗','song-poetry','','[]','齋樓之名散菴立，時哉時哉貴翔集。',64,'全唐诗/poet.song.176000.json','["齋樓之名散菴立，時哉時哉貴翔集。", "訓行處仁要領會，德成勝非由所習。", "眼高四海遠者遠，知效一官急者急。", "工夫當思寸陰競，淵源不可短綆汲。"]'),
('5de19fc2-ea24-4a51-b2da-3fb82a74c2c6','昌甫以詩謝履常見過因和韵','韓淲','宋','宋诗','song-poetry','','[]','萬事新傳燈落燼，底許深長并淺近。',112,'全唐诗/poet.song.176000.json','["萬事新傳燈落燼，底許深長并淺近。", "山空歲暮風雪振，縱得過從渾莫省。", "符銅節蕩元整整，東上西來晨復暝。", "章泉之居儘虛靜，世既相忘心孰競。", "失喜故人來問訊，且擁寒爐話吾勝。", "留連雞黍夜初定，清旦重言意無盡。", "意無盡矣我何知，歎者歎而哂者哂。"]'),
('9b539a65-8e7a-46bc-8b4f-b46b340bb6b9','王幹以詩寄和答','韓淲','宋','宋诗','song-poetry','','[]','福唐荔子冬生花，青榕深深多釋家。',64,'全唐诗/poet.song.176000.json','["福唐荔子冬生花，青榕深深多釋家。", "海山會府亦繁富，官自貨鹽常造茶。", "民以不冤刑獄折，無歲無人無一節。", "同僚鬭牛應暖熱，中酒過廳不可說。"]'),
('c44370f9-4575-4dbd-ada2-f2897b6c1138','次韵徐斯遠曉梁看日出','韓淲','宋','宋诗','song-poetry','','[]','曉山亂眼青如濕，夜氣猶存煙四羃。',64,'全唐诗/poet.song.176000.json','["曉山亂眼青如濕，夜氣猶存煙四羃。", "不知炎熱著何許，但起陰風催日出。", "含暉倒影殊蒼涼，翻手塵埃復俱失。", "高丘望女歌正長，展轉歌之肯倉卒。"]'),
('72167ab4-ca36-4579-9fbd-7d4b1ee14164','次韵昌甫仲春讀謫仙詩','韓淲','宋','宋诗','song-poetry','','[]','淵明太事多，汲汲泥詩酒。',52,'全唐诗/poet.song.176000.json','["淵明太事多，汲汲泥詩酒。", "子雲良自苦，載醪竟何有。", "芭尊太玄八十一，統集飲酒二十首。", "我貴知我希，却掃且緘口。"]'),
('9d12adb9-8a41-4ee7-8ed7-25fe3acbdf02','次韵','韓淲','宋','宋诗','song-poetry','','[]','不須酒畔狂吟裏，夢破寒亭自驚起。',96,'全唐诗/poet.song.176000.json','["不須酒畔狂吟裏，夢破寒亭自驚起。", "一梢孤月带霜華，靈山漫澈冰溪水。", "塵勞空度幾星霜，畫手猶能眼界香。", "午夜城頭吹畫角，綠毛么鳳墮其旁。", "不怕花前不我知，只愁花後少人思。", "如今紙上閒言語，未抵依稀落墨時。"]'),
('157bb5a9-c257-4b86-9073-e54cfd2b6ce2','趙履道同宿南豅梅大放次其韵','韓淲','宋','宋诗','song-poetry','','[]','老身居山復入山，隨山夾路溪彌漫。',96,'全唐诗/poet.song.176000.json','["老身居山復入山，隨山夾路溪彌漫。", "南豅深處作幽夢，我輩白鷗盟勿寒。", "梅花乘春既宜飲，綠毛么鳳非人寰。", "坐中長少偶然集，白雲清氣生簷間。", "醉酣低摘仍高攀，興來物會殊未闌。", "悠悠不但惜此爾，要留佳話他年看。"]'),
('ea2e0d2d-66d5-46c2-990b-fbc923e0cc60','次韵希之','韓淲','宋','宋诗','song-poetry','','[]','滄溟吐吞江水地，風塵萬里一危亭。',112,'全唐诗/poet.song.176000.json','["滄溟吐吞江水地，風塵萬里一危亭。", "自憐雪裏心眼在，憑軒盡日空詩成。", "波流不鳴雲不斷，冷氣暗逼黄熒熒。", "銷凝還如未開鑿，渾沌無際天難名。", "相從共飲豈易適，太息歲晚初何營。", "尺梭已覺魚尾健，數字更喜鴻翼輕。", "吾儕天窮且天放，酒肆人間誰長卿。"]'),
('3b4704fb-05b3-44f9-a3a0-87236e271b1b','次韵建倅德久林秘書寄貢餘','韓淲','宋','宋诗','song-poetry','','[]','鐵獅峰前鳳山陽，泉甘土肥靈草香。',130,'全唐诗/poet.song.176000.json','["鐵獅峰前鳳山陽，泉甘土肥靈草香。", "丁蔡好事作土貢，到今題裹歸朝綱。", "密雲壽圭脫寶胯，鎖鑰銀白羅帕黄。", "春風玉食睿思殿，歲歲屬望天一方。", "恩沾臣鄰講讀處，賜啜更覺昭回光。", "龍鳳大團小團耳，且如頭茶安得嘗。", "餘珍踵例及守漕，屬幙亦得酬官忙。", "平分風月石渠老，分餉乃欲顛倒搜我腸。"]'),
('a8c7a5ca-d2df-4f03-a779-7ba5914eb4d2','沿檄澗上將回呈元立','韓淲','宋','宋诗','song-poetry','','[]','一夜西風入南澗，便作秋聲無畔岸。',64,'全唐诗/poet.song.176000.json','["一夜西風入南澗，便作秋聲無畔岸。", "蕭蕭涼氣夢初回，不奈離愁送遊宦。", "人生義命當樂天，倒睨鍾鼎初悠然。", "明發分手莫惆悵，他年看我棲林泉。"]'),
('9202c0d0-0130-421c-98af-646e6226288c','次韵昌甫斯遠落花行','韓淲','宋','宋诗','song-poetry','','[]','風力作狂無所止，花片摇空當未已。',96,'全唐诗/poet.song.176000.json','["風力作狂無所止，花片摇空當未已。", "諦視深尋孰與比，梅葉梨梢孕青子。", "春紅正復可憐爾，三分前塵一分水。", "相將柔桑著筐篚，寒食北邙泣新鬼。", "繁陰匝地人醉起，哀江南兮臨結綺。", "底用留情來賦此，夏衣飄飄欲輕體。"]'),
('16bb0388-5b90-46b6-979b-05c069b98fcf','斯遠作冷語甚佳以其富貴神仙中致非畸人山澤所宜戲次韵柬之','韓淲','宋','宋诗','song-poetry','','[]','飛流作枕山作屏，采薇散髮神氣寧。',128,'全唐诗/poet.song.176000.json','["飛流作枕山作屏，采薇散髮神氣寧。", "巖扉無人晝長扃，幾回午夢驚獨醒。", "水邊石上草自馨，嵐光近散遠以凝。", "長飆撼樹時靜聽，灑然塵銷天籟清。", "幽禽刷羽飛來輕，泉源舞荇聲泠泠。", "殷雷收暑甘雨零，碧落乍空鸛且鳴。", "閑身無用心太平，試琢新語朱絃聲。", "世俗所爲吾不應，因君詩來如飲冰。"]'),
('9230b6da-163d-4d61-87fc-f99ddbd2cc79','次韵斯遠月夜','韓淲','宋','宋诗','song-poetry','','[]','懷哉望望山囿中，月來老樹高玲瓏。',64,'全唐诗/poet.song.176000.json','["懷哉望望山囿中，月來老樹高玲瓏。", "起行久之坐嘆息，祗合輕舉隨飛龍。", "露華滴葉相下上，河影摇空更清亮。", "長庚如晝夜何其，寒氣襲人不可向。"]'),
('aaf503d4-7d00-40f0-8a7c-7e4ec35dee4f','寄葉解元','韓淲','宋','宋诗','song-poetry','','[]','醉中曾寫雪色壁，非此主人無此客。',64,'全唐诗/poet.song.176000.json','["醉中曾寫雪色壁，非此主人無此客。", "夜寒煙雨池閣深，秉燭看梅忘墮幘。", "春來相望鵝湖邊，桃花滿地松拂天。", "抱琴挾書過飄泉，想君風度尤翩翩。"]'),
('f974e202-a99a-4d3d-ae0c-ec31bf98e299','贈劉解元','韓淲','宋','宋诗','song-poetry','','[]','潮落潮生一水通，崑山縣前桃花紅。',64,'全唐诗/poet.song.176000.json','["潮落潮生一水通，崑山縣前桃花紅。", "劉改之者忽相逢，桃花正在煙雨中。", "面須如戟頭已童，君雖不言我亦窮。", "一杯竟醉立下風，江西人物舊所宗。"]'),
('fbf5252f-5f8d-46a2-a855-949137a30207','溪路邂逅傅騏驥之在所沽酒話別','韓淲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','涼風吹溪雨吹蓬，故人意氣俄相逢。',64,'全唐诗/poet.song.176000.json','["涼風吹溪雨吹蓬，故人意氣俄相逢。", "停驂爲我一小飲，西湖東望兩高峰。", "人間萬事俱華髮，雨歇風清有佳月。", "不須千里苦相思，得酒陶然已兀兀。"]'),
('cbadb326-4602-46a2-8796-8454bd326a96','送吳判官','韓淲','宋','宋诗','song-poetry','','[]','儒家辰告當訏謨，紛紛莫厭形勢塗。',128,'全唐诗/poet.song.176000.json','["儒家辰告當訏謨，紛紛莫厭形勢塗。", "甲兵調度應敵爾，君行鄱水聊載驅。", "有文與詩錦機織，夾道雲山正堆積。", "癡兒固有了官事，歸日奚囊觀筆力。", "別酒無用鯨吸川，芝山杖藜湖接天。", "使君自是江海客，有來矍鑠當歡然。", "如今百事皆撐柱，寬得一分猶復古。", "蕭條野老爲賡吟，此話不同知底數。"]'),
('a48101ba-b642-44e6-944e-8144855141c6','二十六日贈鄭一有懷趙十閩嶠之役','韓淲','宋','宋诗','song-poetry','','[]','遊者未回居者藏，老我去各天一方。',64,'全唐诗/poet.song.176000.json','["遊者未回居者藏，老我去各天一方。", "目前聚集自落拓，背後往還誰論量。", "連連冰雪葉已脫，皎皎風霜梅更芳。", "燭明照坐更漏長，高溪里社靈山陽。"]'),
('abac0296-1ce4-4cf7-91d0-89d9be5400c1','戲柬胡教授','韓淲','宋','宋诗','song-poetry','','[]','去冬曾與十客遊，今夏還約幾人至。',64,'全唐诗/poet.song.176000.json','["去冬曾與十客遊，今夏還約幾人至。", "橋南花處數枝梅，青子林園尚堪醉。", "行者居者復不來，相賞相違何有哉。", "古栝蒼山照流水，我亦僅能知此爾。"]'),
('0004fc59-662c-4279-85ec-f89513aecb6a','寄昌甫','韓淲','宋','宋诗','song-poetry','','[]','深林蟬聲咽殘雨，又爾微炎起亭午。',64,'全唐诗/poet.song.176000.json','["深林蟬聲咽殘雨，又爾微炎起亭午。", "章泉幽流雨風寒，安得從之臂不羽。", "江南田薄多旱苦，冥鴻孤高畏羅罟。", "洪河東傾一砥柱，雲霏霏兮澹承宇。"]'),
('ac550059-d911-45a9-be49-62ddc3e0fec0','懷昌甫','韓淲','宋','宋诗','song-poetry','','[]','君頭短髮種種長，營營寒事驚流光。',64,'全唐诗/poet.song.176000.json','["君頭短髮種種長，營營寒事驚流光。", "手翻手覆謂可常，幽意祇覺來無方。", "今冬風雪多冰霜，靜夜不寐猶吟螿。", "竹隠我獨矯首望，詩寄尚喜筆健彊。"]'),
('389a0737-4c05-4678-81e5-44adf16ad695','趙十生日作醮事','韓淲','宋','宋诗','song-poetry','','[]','清飆吹塵玉溪煙，龍舟未收菖蒲天。',64,'全唐诗/poet.song.176000.json','["清飆吹塵玉溪煙，龍舟未收菖蒲天。", "城東寶香祈永年，振振公子陳醮筵。", "雨零霞外來羣仙，德我壽我明自然。", "宣簡流芳正綿延，華裾織翠金丹圓。"]'),
('6a15c596-7075-44ed-94cd-e3f62d452c8f','次韵耿運幹','韓淲','宋','宋诗','song-poetry','','[]','青鞋黄帽非左計，消得水涯與山顛。',64,'全唐诗/poet.song.176000.json','["青鞋黄帽非左計，消得水涯與山顛。", "吟邊憂世聽者哂，只宜尋醉陶陶然。", "貴人責重閒人輕，春風日高放脚眠。", "带湖拂波綠楊柳，吾儕靜勝可忘年。"]'),
('80deec18-46da-434a-9a00-b577b2283853','聞民瞻久歸一詩寄之','韓淲','宋','宋诗','song-poetry','','[]','我居溪南望城北，最高園臺竹樹碧。',64,'全唐诗/poet.song.176000.json','["我居溪南望城北，最高園臺竹樹碧。", "眼前带湖歌舞空，耳畔茶山陸子宅。", "知君纔自天竺歸，那得緇塵染客衣。", "日携研席過阿連，怡神散髮思采薇。"]'),
('c2e30e2c-3582-4ba3-a798-25da656a6f0b','聞趙十有詩上饒生朝後兩日次韵寄之','韓淲','宋','宋诗','song-poetry','','[]','文章精金真美玉，交往徒勞分雅俗。',128,'全唐诗/poet.song.176000.json','["文章精金真美玉，交往徒勞分雅俗。", "偶然邂逅一言詩，清秋付與陶潛菊。", "弦歌之聲譽甚休，田里民其無歎愁。", "誰將茗酒壽弧矢，長篇短句相唱酬。", "是中佳處有深趣，如龍翔雲豹起霧。", "力探樂取到古人，天地江山供指顧。", "從他駒隙歲月馳，我自舒徐蕭散之。", "罏香莫著鼻觀淨，喚醒伯牙鍾子期。"]'),
('c6847b4a-5b22-473b-96f6-85daf5e1c1f3','昌甫有詩學長句次韵以柬處晦且當應舉','韓淲','宋','宋诗','song-poetry','','[]','章泉老子之詩學，筆自崢嶸心自泊。',128,'全唐诗/poet.song.176000.json','["章泉老子之詩學，筆自崢嶸心自泊。", "暮春靜把一杯看，縱有世情無處著。", "三傳且莫束高閣，待子龍津名一躍。", "收回舊話再商量，沈謝應劉都掃却。", "蠶葉人家採摘忙，麥將秋矣水浮秧。", "平田冷漠吹朝雨，側徑深微過夕陽。", "殘酒餘香愁夢枕，斷篇遺簡苦吟囊。", "鶑啼燕語春歸也，不道高齋口自芳。"]'),
('d8ad6ca6-bd1a-48d4-a7c4-6c285acc6540','斯遠訪昌甫同作音字詩因又一首','韓淲','宋','宋诗','song-poetry','','[]','故人湖海誰知音，章泉病翁卧山林。',64,'全唐诗/poet.song.176000.json','["故人湖海誰知音，章泉病翁卧山林。", "我思不見夜長寂，君往與同秋正陰。", "修筠亂石一徑靜，風雨滿窗清且深。", "安得相從日上下，騷雅共傾陶寫心。"]'),
('0ee0f002-efbd-47e9-a87d-35812536d959','次韵吳推官二首  其一','韓淲','宋','宋诗','song-poetry','','[]','紫菊紅萸仍酒美，萬里秋雲接天水。',64,'全唐诗/poet.song.176000.json','["紫菊紅萸仍酒美，萬里秋雲接天水。", "登高能賦我何堪，會逢其適聊爾耳。", "蒼山小亭看弈棋，不有此客無此詩。", "古往今來吹破帽，河梁歸路月明知。"]'),
('435bd523-88fe-4319-aed0-c5394adc45ff','次韵吳推官二首  其二','韓淲','宋','宋诗','song-poetry','','[]','坡云今日我重九，自古騷人無此手。',96,'全唐诗/poet.song.176000.json','["坡云今日我重九，自古騷人無此手。", "一從陶令歸去來，誰有閒中能漉酒。", "籬邊采采黄花歌，不盈襟袖還幾多。", "滿城風雨固應爾，欲制頹齡如老何。", "怪來清氣侵毛髮，忽得新篇有風骨。", "溪亭應記見南山，玉水波寒步微月。"]'),
('ca497da2-d7c7-4121-8018-9bb72adbae50','讀東溪可正平詩','韓淲','宋','宋诗','song-poetry','','[]','冰霜落澗歲云暮，寂寂遠岫松風回。',64,'全唐诗/poet.song.176000.json','["冰霜落澗歲云暮，寂寂遠岫松風回。", "村深古寺作鐘磬，車馬路斷樵者來。", "參差一抹起宿雁，清淺數枝橫小梅。", "日昃翠寒雲屋迥，竹爐煨火盡餘杯。"]'),
('873a7e88-6026-431d-84ec-5d0d10308110','陳君舉舍人集新刊三山因讀其詩有感','韓淲','宋','宋诗','song-poetry','','[]','陳止齋詩不草草，約貌前頭諸舊老。',64,'全唐诗/poet.song.176000.json','["陳止齋詩不草草，約貌前頭諸舊老。", "大章短句可思議，妙意餘情愁絕倒。", "生薑門有水心道，赤水亭占龍窟好。", "伯牙無絃驥伏皂，摹搨賸殘人或葆。"]'),
('2ab9667d-8e5b-44d5-bd70-8ebd9ed25424','吳判官野閣詩述先公甚勤次韵謝之','韓淲','宋','宋诗','song-poetry','','[]','我登野閣思過庭，吻角欲語徒悲鳴。',192,'全唐诗/poet.song.176000.json','["我登野閣思過庭，吻角欲語徒悲鳴。", "麗譙西池水木秀，當年手種年年生。", "五六十春幾交印，幕畫英遊應接軔。", "由來感舊誰發揮，龍光斗牛知令問。", "詩來喚醒醉夢中，一日好事傳江東。", "吳公治行天下美，隠然蓋本西漢風。", "大抵軒窗數間屋，雅俗升沈堪躑躅。", "光前絕後得名章，便覺流芳爭誦讀。", "夕陽淡月色朦朧，想公退食書自工。", "黄卷之間欠伸處，催煎茶椀呼家童。", "妙聲直啟重玄鑰，惠徼先君寧苟作。", "其孤衰微但下拜，猶向霜天辱杯酌。"]'),
('5811c3d2-226a-4980-85b4-b1c87fe84429','錄王昌齡詩','韓淲','宋','宋诗','song-poetry','','[]','千古萬古琉璃堂，中有一人萬丈光。',64,'全唐诗/poet.song.176000.json','["千古萬古琉璃堂，中有一人萬丈光。", "長篇短篇任摸索，小句大句宜忖量。", "風花雪月初非遠，城郭山林各是忙。", "惆悵無因見范蠡，空留佳話說南唐。"]'),
('5283eb90-6ebc-4498-a613-220c417305d7','題紫溪春晚圖畫','韓淲','宋','宋诗','song-poetry','','[]','東風滿地吹瑶草，水煖雙流山四抱。',128,'全唐诗/poet.song.176000.json','["東風滿地吹瑶草，水煖雙流山四抱。", "參差樓觀倚晴空，林靄乍收初日杲。", "杏桃婀娜開花早，蝶遶鶑遷魚在藻。", "人家籬落動耕桑，溪女往來翁喚媼。", "務頭臘酒賤仍好，麥熟官清農晏保。", "岝崿峰高多醉遊，天目潭深無旱禱。", "誰把丹青能一掃，點綴毫芒殊可考。", "分明融蕩紫溪春，路入煙霞是仙島。"]'),
('549465a1-292a-4673-a1c9-a76a5a6e1a46','偶成','韓淲','宋','宋诗','song-poetry','','[]','蠻歌俚耳吾不愁，江南五月疑涼秋。',72,'全唐诗/poet.song.176000.json','["蠻歌俚耳吾不愁，江南五月疑涼秋。", "漸離荆卿易水流，圖窮匕首非覇謀。", "吳頭楚尾龍虎幽，擊筑乃爾聽市謳，調苦節促如遠遊。", "安得酒船同拍浮，衮衮切切終悠悠。"]'),
('2f408539-70e7-49e3-b734-fc44ad19aa44','雜賦二首','韓淲','宋','宋诗','song-poetry','','[]','今年臘盡春風起，凌曉撐船度溪水。',64,'全唐诗/poet.song.176000.json','["今年臘盡春風起，凌曉撐船度溪水。", "去年九日菊花開，相與周遊二三子。", "山深泉井一鄉村，地僻章丘數家市。", "酒飲詩成可奈何，坐想斯人消吝鄙。"]'),
('c967bb5a-0389-4ecc-bd18-29909aefbd1a','贈天台鄭道士','韓淲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','霞杯爲奏阮咸曲，悵望十年湖水煙。',64,'全唐诗/poet.song.176000.json','["霞杯爲奏阮咸曲，悵望十年湖水煙。", "聞過東嘉看雁蕩，野雲留宿話翛然。", "譚詩忽見蔣雲出，今去洞庭衡岳前。", "能說鍊師神不老，識全元是赤城仙。"]'),
('a5642b3b-6bf5-402e-8a7d-065cd531da7c','慈福太后生辰聖駕同中宮過北內上壽至曉鑾仗方回觀者無不仰贊慶禮四朝之尊也','韓淲','宋','宋诗','song-poetry','','[]','盛典行長樂，秋光溢壽樽。',48,'全唐诗/poet.song.176000.json','["盛典行長樂，秋光溢壽樽。", "后儀崇太姒，帝服見曾孫。", "遥想重闈集，咸推六殿恩。", "歡聲開九秩，誕節照乾坤。"]'),
('a97e6252-0c58-4f56-8947-78a454f374b9','春日','韓淲','宋','宋诗','song-poetry','','[]','院落無人到，遊絲自短長。',48,'全唐诗/poet.song.176000.json','["院落無人到，遊絲自短長。", "細風添霽色，斜日轉流光。", "柳入鶑邊嫩，花飛燕外香。", "一杯春晝永，試與問年芳。"]'),
('59156063-3ea5-49d1-a9d0-3c32592ee1cf','次韵元夕  其一','韓淲','宋','宋诗','song-poetry','','[]','煙月收微靄，春歸柳色深。',48,'全唐诗/poet.song.176000.json','["煙月收微靄，春歸柳色深。", "落梅還滿眼，啼鳥獨驚心。", "醉熟醒何益，愁多夢亦侵。", "銀花元夜句，猶記昔人吟。"]'),
('3a4a7361-3950-4c92-a54c-4beaa193a47f','次韵元夕  其二','韓淲','宋','宋诗','song-poetry','','[]','輦路元宵盛，樓臺煙火深。',48,'全唐诗/poet.song.176000.json','["輦路元宵盛，樓臺煙火深。", "異鄉今日意，樂事去年心。", "溪闊斜陽下，林空細雨侵。", "扶輿且蕭散，尋勝一閒吟。"]'),
('fc29e53d-c649-4660-b339-57844db7ad83','人日','韓淲','宋','宋诗','song-poetry','','[]','去年苦無雪，今雨又多風。',48,'全唐诗/poet.song.176000.json','["去年苦無雪，今雨又多風。", "人日平頭過，元宵轉眼中。", "野梅香更白，文杏色微紅。", "籬落春陰外，樓臺曉霧空。"]'),
('9bf3f3e6-550f-4c23-8c42-74f6d478528b','正月十一日','韓淲','宋','宋诗','song-poetry','','[]','春前三日雪，今則倏霜晴。',48,'全唐诗/poet.song.176000.json','["春前三日雪，今則倏霜晴。", "澗谷冰凘滿，溪山風物清。", "梅梢已飄灑，蘭穗始敷榮。", "宿約多神賽，君來酒重傾。"]'),
('641a6826-6286-43b9-b464-cc5b0b1e1ed4','三月一日','韓淲','宋','宋诗','song-poetry','','[]','海棠花上雪，憔悴却如人。',48,'全唐诗/poet.song.176000.json','["海棠花上雪，憔悴却如人。", "曉覺春光淡，時占天氣新。", "燕脂纔糝糝，翡翠正勻勻。", "睡足寒猶力，宜多酒入唇。"]'),
('49f3d97e-3c7e-483c-9b3b-e0a848c14f4f','雨中上巳','韓淲','宋','宋诗','song-poetry','','[]','風作連宵雨，山寒復晝冥。',48,'全唐诗/poet.song.176000.json','["風作連宵雨，山寒復晝冥。", "酴醾花白白，楊柳葉青青。", "令節空輕過，芳時惜易經。", "清真王逸少，修禊寫蘭亭。"]'),
('6327578e-c068-42d8-8cd1-808fce9d554d','次韵昌甫寒食','韓淲','宋','宋诗','song-poetry','','[]','南北已分壠，後來那得知。',48,'全唐诗/poet.song.176000.json','["南北已分壠，後來那得知。", "侵尋空歲月，流落漫歌詩。", "宿草露殊濕，白楊風更悲。", "江村暗寒食，老大故園思。"]'),
('cb93b003-03ff-4897-8a07-b280d8dcfd47','十四日  其一','韓淲','宋','宋诗','song-poetry','','[]','淡淡春晴晚，窗前燕子飛。',48,'全唐诗/poet.song.176000.json','["淡淡春晴晚，窗前燕子飛。", "酒盃誰共飲，詩筆自孤揮。", "上冢家山遠，下湖仙苑稀。", "空多冶遊者，扶醉趕門歸。"]'),
('f32de8dd-3771-4536-a9cd-f7f33ba67e0a','十四日  其二','韓淲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','風花郭店路，靈井隔雲溪。',48,'全唐诗/poet.song.176000.json','["風花郭店路，靈井隔雲溪。", "渡水魚爭出，隨山鶑亂啼。", "只疑身未老，不信夢還迷。", "今日逢寒食，西湖春草萋。"]'),
('84c68b7c-1712-45c4-aad2-111ffc6d1019','二十五日','韓淲','宋','宋诗','song-poetry','','[]','山徑瀕溪轉，林亭亞谷斜。',48,'全唐诗/poet.song.176000.json','["山徑瀕溪轉，林亭亞谷斜。", "老詩無住著，健酒有須賒。", "急雨催楊柳，微陰養杏花。", "重簾新燕子，隨處覓生涯。"]'),
('d11bc9b8-27aa-458a-9020-3445c4dfc4a2','晚春','韓淲','宋','宋诗','song-poetry','','[]','細雨收微暖，輕雲起薄陰。',48,'全唐诗/poet.song.176000.json','["細雨收微暖，輕雲起薄陰。", "舟橫蓮葉淺，人度柳花深。", "佛屋多支徑，旂亭亦遠林。", "一春思放浪，盡日喜登臨。"]'),
('a9ecb9df-7dd3-4d6a-8bae-bdae21ce79a0','初七日','韓淲','宋','宋诗','song-poetry','','[]','晚來臺上坐，猶自說春歸。',48,'全唐诗/poet.song.176000.json','["晚來臺上坐，猶自說春歸。", "可惜園林裏，都無花片飛。", "榜人勞載酒，鷗鳥定忘機。", "笑摘青梅子，停杯看雨肥。"]'),
('549c9ab6-cd6c-4b9a-8285-85d6dd65c5cc','七月','韓淲','宋','宋诗','song-poetry','','[]','水石雲山裏，歸來已九秋。',48,'全唐诗/poet.song.176000.json','["水石雲山裏，歸來已九秋。", "隔城如淺近，鄰寺始深幽。", "慧遠逢修靜，文淵說少游。", "徑荒殊不掃，風葉上牽牛。"]'),
('309c1b73-1c23-4f0b-9e5b-9fa2c430bd35','九日','韓淲','宋','宋诗','song-poetry','','[]','客裏逢重九，路經鵝嶺頭。',48,'全唐诗/poet.song.176000.json','["客裏逢重九，路經鵝嶺頭。", "物華元自好，意緒不禁愁。", "霜重曉猶積，烟低寒不收。", "營營本何事，吹笛下滄洲。"]'),
('39177ecf-e12e-41be-bf9f-62cd64468945','趙運幹秩滿經由寄懷任舍人直院九日','韓淲','宋','宋诗','song-poetry','','[]','季月黄花酒，今還過玉溪。',48,'全唐诗/poet.song.176000.json','["季月黄花酒，今還過玉溪。", "野僧談衆妙，林叟祇孤暌。", "滕閣有前境，胥山無別蹊。", "會須直學士，霄漢記閒栖。"]'),
('a7872b11-acc0-45e7-82e8-f46babbbe1a9','十一月晦','韓淲','宋','宋诗','song-poetry','','[]','沙鴈徒高下，荒雞任喔吚。',48,'全唐诗/poet.song.176000.json','["沙鴈徒高下，荒雞任喔吚。", "連山雲日過，夾澗雪霜吹。", "葉逕濕仍滑，柴扉久易欹。", "不知詩在否，詩亦費心思。"]'),
('eb6ecae7-d383-4c45-b6e2-ad90cd550341','十二月旦','韓淲','宋','宋诗','song-poetry','','[]','雪後寒簷滴，青燈夜看詩。',48,'全唐诗/poet.song.176000.json','["雪後寒簷滴，青燈夜看詩。", "人情雖已甚，物色又何其。", "永永孤城漏，垂垂老境時。", "瑠璃剪木葉，今歲是冰枝。"]'),
('e1507317-7e07-4931-a72e-24e82e19fd11','歲晚','韓淲','宋','宋诗','song-poetry','','[]','歲晚家何在，冰溪懷玉山。',48,'全唐诗/poet.song.176000.json','["歲晚家何在，冰溪懷玉山。", "雪梅香汎汎，霜樹色斑斑。", "村酒相招喚，田歌自往還。", "白頭搔更懶，今識市朝間。"]'),
('a6c95aa8-6faa-4e85-a252-38a723f53fab','十六日  其一','韓淲','宋','宋诗','song-poetry','','[]','不恨常疎隔，何疑欠討論。',48,'全唐诗/poet.song.176000.json','["不恨常疎隔，何疑欠討論。", "同心惟設飯，盡興亦空罇。", "日與樵爭席，時看子候門。", "山場風莽廣，溪港雨沉昏。"]'),
('117eb656-2536-4b4a-ba57-dd57c627b604','十六日  其二','韓淲','宋','宋诗','song-poetry','','[]','寒水浮沙急，昏煙擁樹深。',48,'全唐诗/poet.song.176000.json','["寒水浮沙急，昏煙擁樹深。", "茅茨得幽隠，藜杖失荒尋。", "地暖疎梅發，籬虛敗葉侵。", "終風驚達夜，未雪苦多陰。"]'),
('cfcab09d-0645-423d-b0eb-d1a13a774347','窗日','韓淲','宋','宋诗','song-poetry','','[]','飯已南窗暖，依違睡思生。',48,'全唐诗/poet.song.176000.json','["飯已南窗暖，依違睡思生。", "息虛神即固，氣定體殊輕。", "霜熟日初上，簷疎紙透明。", "欠伸詢早暮，一唱午雞聲。"]'),
('29a361f6-1c95-4af8-8882-b9b8bb1f8ec2','乍暖','韓淲','宋','宋诗','song-poetry','','[]','乍暖人多困，晝長春已深。',48,'全唐诗/poet.song.176000.json','["乍暖人多困，晝長春已深。", "殘花紅糝糝，新葉綠陰陰。", "山寺依巖曲，湖船過水心。", "鈎簾醒午睡，閒覺去來吟。"]'),
('dd6c7b44-3152-4e17-be2a-ec48cb696886','晚晴','韓淲','宋','宋诗','song-poetry','','[]','雨闊雲難斂，高樓忽晚晴。',48,'全唐诗/poet.song.176000.json','["雨闊雲難斂，高樓忽晚晴。", "地卑雖带潤，天近自增明。", "蚊動初成勢，鴉翻過宿聲。", "牆根有孤樹，清坐見凉生。"]'),
('bd89cbc3-7592-4e6d-a7ba-fe21852d90b5','乍冷洒然','韓淲','宋','宋诗','song-poetry','','[]','不可更禁當，伏陰多夏凉。',48,'全唐诗/poet.song.176000.json','["不可更禁當，伏陰多夏凉。", "體中時作惡，鼻觀日焚香。", "照眼驚雙鬢，支頤待一觴。", "詩來相勞苦，邊事敢籌量。"]'),
('ea5477a8-fba0-43b9-9a92-2a2015b1f9f8','初十日','韓淲','宋','宋诗','song-poetry','','[]','沉沉三日雨，衮衮四山風。',48,'全唐诗/poet.song.176000.json','["沉沉三日雨，衮衮四山風。", "潢潦從浮汎，羣陰漫長雄。", "深居何藉屐，矮屋且遮篷。", "急歛身心住，徐看鼻息通。"]'),
('0397506e-d84d-4368-8ed0-b4d25fce0cb3','二十一日','韓淲','宋','宋诗','song-poetry','','[]','向來愁見客，今去莫吟詩。',48,'全唐诗/poet.song.176000.json','["向來愁見客，今去莫吟詩。", "自是才情減，何勞朋舊爲。", "一身元屬我，百事總因誰。", "溪路多蝦菜，呼童問早炊。"]'),
('aba55e28-a0a9-480c-845b-64d939b0259f','曉冷','韓淲','宋','宋诗','song-poetry','','[]','曉霧知猶冷，初陽覺更和。',48,'全唐诗/poet.song.176000.json','["曉霧知猶冷，初陽覺更和。", "午風吹不斷，夜氣暑還多。", "簾檻翻黄蝶，燈窗撲白蛾。", "晚春初夏際，蠶麥復如何。"]'),
('9f5dad30-2c0b-4ea0-a1b2-a8d5f567a5d9','風落','韓淲','宋','宋诗','song-poetry','','[]','風落摇窗牖，煙垂暗屋簷。',48,'全唐诗/poet.song.176000.json','["風落摇窗牖，煙垂暗屋簷。", "漫空時衮衮，灑迥復纖纖。", "著柳真堪折，迷花自可粘。", "春前一尺雪，農事不須占。"]'),
('4cbbf40a-429d-4255-9d64-3450bddffd93','明月','韓淲','宋','宋诗','song-poetry','','[]','明月度窗櫺，荷香逼酒醒。',48,'全唐诗/poet.song.176000.json','["明月度窗櫺，荷香逼酒醒。", "水聲鳴澗壑，風影散林坰。", "暑雨收微眇，晴雲動杳冥。", "小軒清坐久，高下數飛螢。"]'),
('ac91b7e7-f364-4d99-921f-2348100c8799','夜月','韓淲','宋','宋诗','song-poetry','','[]','月近中秋好，人寧不用情。',48,'全唐诗/poet.song.176000.json','["月近中秋好，人寧不用情。", "那知雲欲暮，遽作雨連明。", "圓缺閒皆見，陰晴老自驚。", "夜凉山葉響，燈火短長檠。"]'),
('144ef6f0-563c-4357-924b-d55b2871ea49','聞雨凉意可掬','韓淲','宋','宋诗','song-poetry','','[]','秋聲連夜起，雨過雨來時。',48,'全唐诗/poet.song.176000.json','["秋聲連夜起，雨過雨來時。", "睡覺風生屋，凉知水到池。", "交游稀自好，出入嬾方宜。", "只被章泉誤，書題又寄詩。"]'),
('1a1cba40-6cc5-42fa-9d5a-8f13062bb222','雨多極凉冷','韓淲','宋','宋诗','song-poetry','','[]','焉知三伏雨，已作九秋風。',48,'全唐诗/poet.song.176000.json','["焉知三伏雨，已作九秋風。", "木葉凉應脫，禾苗潤必豐。", "地偏山吐月，橋斷水浮空。", "雞犬鄰家外，魚蝦小市中。"]'),
('b363eb2f-21ad-4252-adfb-de694c8d16b2','晚雨可愛','韓淲','宋','宋诗','song-poetry','','[]','燈火凉秋夜，空山雨到簷。',48,'全唐诗/poet.song.176000.json','["燈火凉秋夜，空山雨到簷。", "吹聲初甚少，落勢近頻添。", "籬菊叢叢潤，畦蔬種種霑。", "沈思仍靜聽，香鼎伴書籤。"]'),
('0f9498ba-53f9-4d7f-8fbe-ef2213db0ec3','初三日急雨湖山雲氣初霽樓居佳甚','韓淲','宋','宋诗','song-poetry','','[]','雨後見雲山，家林恨未還。',48,'全唐诗/poet.song.176000.json','["雨後見雲山，家林恨未還。", "人生何自苦，身老定誰閒。", "溶洩平輸處，縱橫羅列間。", "幽幽清潤氣，樓迥自怡顔。"]'),
('cf3e8000-2e97-4eb9-bc1a-b61e8c50e4ed','夜坐聞雨  其一','韓淲','宋','宋诗','song-poetry','','[]','夜靜時聞雨，山深遠聽更。',48,'全唐诗/poet.song.176000.json','["夜靜時聞雨，山深遠聽更。", "疎林聲轉永，孤戍景何清。", "方冊舒還卷，殘缸暗復明。", "脫巾搔首坐，曳履欠身行。"]'),
('f11a8edd-e970-48ba-8efe-ccdde68332a4','夜坐聞雨  其二','韓淲','宋','宋诗','song-poetry','','[]','寒夜空山雨，聲從遠樹來。',48,'全唐诗/poet.song.176000.json','["寒夜空山雨，聲從遠樹來。", "老懷渾木塞，癡坐只灰堆。", "抖擻閒題句，團欒試把杯。", "崢嶸歲云暮，春在臘前梅。"]'),
('a18e73d6-7a6c-46db-bbe5-3f422fec1e43','雨處','韓淲','宋','宋诗','song-poetry','','[]','雨處茫茫白，晴邊隠隠青。',48,'全唐诗/poet.song.176000.json','["雨處茫茫白，晴邊隠隠青。", "林間田舍屋，水際酒家亭。", "野迥驚初見，村深惜未經。", "陰沉思得月，歷落喜瞻星。"]'),
('f2dbc360-274e-4e7b-aa26-e8ab515043bc','煙雨','韓淲','宋','宋诗','song-poetry','','[]','汀洲生玉水，煙雨對靈山。',48,'全唐诗/poet.song.176000.json','["汀洲生玉水，煙雨對靈山。", "翠碧迷千嶂，清泠瀉一灣。", "尋春因共載，落日不知還。", "便是名人畫，無能寫此閒。"]'),
('f33c10af-58f9-4590-a515-5512d7ceb713','煖雨','韓淲','宋','宋诗','song-poetry','','[]','土煖鳴噓蚓，山昏聚宿鴉。',48,'全唐诗/poet.song.176000.json','["土煖鳴噓蚓，山昏聚宿鴉。", "沿流多佛屋，隔縣少詩家。", "怕醉休溫酒，狂吟待飲茶。", "花天晴自喜，麥地雨誰家。"]'),
('a2d5ceb8-7369-4ca7-a43e-2e80577f50d9','雨中  其一','韓淲','宋','宋诗','song-poetry','','[]','幽林遠朝市，太息古來今。',48,'全唐诗/poet.song.176000.json','["幽林遠朝市，太息古來今。", "四月麥秋後，江南梅雨臨。", "庭前三徑在，路口一溪深。", "車馬有時到，定多閒淡心。"]'),
('dfcea3b4-db76-4171-b94d-0e8b86b773c5','雨中  其二','韓淲','宋','宋诗','song-poetry','','[]','花浥垂垂細，林摇點點稀。',48,'全唐诗/poet.song.176000.json','["花浥垂垂細，林摇點點稀。", "綠繁枝困裊，紅淡蘂鮮肥。", "高下海棠起，淺深山柳圍。", "雲梳煙未止，風急雨爭飛。"]'),
('765828ff-982f-4008-a271-4e5d3706748f','雨中  其三','韓淲','宋','宋诗','song-poetry','','[]','雨葉凄凄晚，風花肅肅春。',48,'全唐诗/poet.song.176000.json','["雨葉凄凄晚，風花肅肅春。", "乍看渾入意，久坐恐傷神。", "城郭三家市，山林一病身。", "幽偏無客到，疎嬾寄吾真。"]'),
('f506158e-d0e0-4c3e-a543-f01753c8249b','雨後','韓淲','宋','宋诗','song-poetry','','[]','魚沼成吹沫，蛛簷落斷絲。',48,'全唐诗/poet.song.176000.json','["魚沼成吹沫，蛛簷落斷絲。", "盆花半開合，階草盡離披。", "風靜凉猶在，雲低曉更遲。", "懶能尋枕簟，好去把鉏犂。"]'),
('f9c6ca81-07a3-4656-99d0-5c3bb3fdc3cf','二十二日雨  其一','韓淲','宋','宋诗','song-poetry','','[]','整衾和枕簟，振席見燈檠。',48,'全唐诗/poet.song.176000.json','["整衾和枕簟，振席見燈檠。", "欲讀書休讀，難成夢也成。", "四山連屋靜，一葉隔窗鳴。", "總不關吾事，無非是物情。"]'),
('8b8fdacb-866a-4758-a540-5e750605b173','二十二日雨  其二','韓淲','宋','宋诗','song-poetry','','[]','澗水應添潤，山雲定不虛。',48,'全唐诗/poet.song.176000.json','["澗水應添潤，山雲定不虛。", "夜光離復合，朝氣慘而舒。", "履畝禾須穫，窺園菜可鉏。", "稀疎遍籬落，微密上階除。"]'),
('44860ff8-3e35-46f0-b47b-7e3660f2ce46','四月二十三日渴雨','韓淲','宋','宋诗','song-poetry','','[]','霧下疑成雨，簷低暗復明。',48,'全唐诗/poet.song.176000.json','["霧下疑成雨，簷低暗復明。", "田家思一稔，王國慮多晴。", "天豈預人事，世應容我耕。", "憑軒歸計定，只得待雷聲。"]'),
('00ad3b02-4ccd-420c-8ed9-42e010891945','丁寺丞靈山閣同國正小集是日得雨次韵仁甫五字','韓淲','宋','宋诗','song-poetry','','[]','野寺乘凉雨，宜從志喜論。',48,'全唐诗/poet.song.176000.json','["野寺乘凉雨，宜從志喜論。", "橋分一水隔，城列萬家屯。", "樂寓東山妓，賢歸北海樽。", "年登農滿望，客醉我忘言。"]'),
('7b2a60aa-afb8-44d4-ac9b-e225fed0c3ee','五六日大雨','韓淲','宋','宋诗','song-poetry','','[]','海角地蒸雨，江南天要梅。',48,'全唐诗/poet.song.176000.json','["海角地蒸雨，江南天要梅。", "晚春知望久，中夏得愁開。", "鬰鬰陰陰過，綿綿浩浩來。", "已傳增米價，只道損苗栽。"]'),
('f356c158-04bf-4afe-a296-4839385f545e','夏雨','韓淲','宋','宋诗','song-poetry','','[]','轉輸三伏雨，探借九秋風。',48,'全唐诗/poet.song.176000.json','["轉輸三伏雨，探借九秋風。", "沾灑蓮猶碧，飄摇葉未紅。", "荒凉甘退縮，清潤擬從容。", "在野農人喜，仍年禾黍豐。"]'),
('31e78308-ad1c-4506-b57e-18a5c290bc18','東流值雨','韓淲','宋','宋诗','song-poetry','','[]','客恨何時了，蕭蕭雨未晴。',48,'全唐诗/poet.song.176000.json','["客恨何時了，蕭蕭雨未晴。", "異鄉無伴處，荒縣少人行。", "樹色巡簷碧，江聲遶枕清。", "且憑閒景物，陶寫小詩成。"]'),
('322d51c6-ad96-494d-9266-fb42b87798a6','雪後微雨','韓淲','宋','宋诗','song-poetry','','[]','烟重雨尤寒，風銷日未乾。',48,'全唐诗/poet.song.176000.json','["烟重雨尤寒，風銷日未乾。", "江湖浮綠淨，巖岫列青攢。", "嬾出空穿履，宜歸且釣竿。", "凄凉兩都舊，洛下卧袁安。"]'),
('45d68f69-1323-462a-ae1d-9375b8a134cd','苦雨','韓淲','宋','宋诗','song-poetry','','[]','開歲晴非少，經旬雨是多。',48,'全唐诗/poet.song.176000.json','["開歲晴非少，經旬雨是多。", "澗寒人跡斷，山暖鳥聲和。", "試手應如畫，回身易擲梭。", "無聊宜已矣，有興竟云何。"]'),
('dcbbcb7a-6ef7-4ccf-b260-23db5ba0a382','五月八日喜雨','韓淲','宋','宋诗','song-poetry','','[]','洒洒如人意，明明助歲功。',48,'全唐诗/poet.song.176000.json','["洒洒如人意，明明助歲功。", "夜闌愁有月，曉起喜無風。", "坡老記爲美，宣王詩最工。", "朝家一祈禱，田里得和豐。"]'),
('a503ac09-2224-4618-a130-65d2556cd194','十一日同處晦蒼筤喜雨','韓淲','宋','宋诗','song-poetry','','[]','清坐看凉雨，山林靜有聲。',48,'全唐诗/poet.song.176000.json','["清坐看凉雨，山林靜有聲。", "交遊因共話，衰老欲何營。", "風急初疑斂，雲低又苦傾。", "爽然神觀定，籬逕不知塵。"]'),
('2f385592-41a9-4671-b7c1-33feebfb3ec7','凉雨  其一','韓淲','宋','宋诗','song-poetry','','[]','默坐看凉雨，山林有正聲。',48,'全唐诗/poet.song.176000.json','["默坐看凉雨，山林有正聲。", "冥濛元廣大，點滴半虛明。", "雲葉才羣起，風枝又一傾。", "信知塵易遣，徒亂雅難平。"]'),
('9867e84f-6414-47e3-a1ca-4dea0240c199','凉雨  其二','韓淲','宋','宋诗','song-poetry','','[]','陂池浮月影，橋閘瀉風聲。',48,'全唐诗/poet.song.176000.json','["陂池浮月影，橋閘瀉風聲。", "遠雨收還施，行雲翳忽明。", "襟期看我醉，譚笑待君傾。", "凉夜玉溪曲，行歌詠太平。"]'),
('748e76a3-f954-427d-9941-bbcd08fb5878','雨凉','韓淲','宋','宋诗','song-poetry','','[]','暑雨常憂缺，秋霖莫厭多。',48,'全唐诗/poet.song.176000.json','["暑雨常憂缺，秋霖莫厭多。", "夜雷聲復厲，朝霧氣方和。", "積潤花巖桂，橫流穗畝禾。", "酒閒吟解穢，茶熟困驅魔。"]'),
('e4ba9b1a-40a4-4a05-aabd-75500d541e1e','雪','韓淲','宋','宋诗','song-poetry','','[]','山外黄雲晚，溪頭白雪深。',48,'全唐诗/poet.song.176000.json','["山外黄雲晚，溪頭白雪深。", "不知嵐氣重，但覺水痕侵。", "老眼轉愁坐，孤懷聊醉吟。", "樵聲隨遠近，釣影任浮沉。"]'),
('204d7d54-bee5-466c-90c0-1f50257afcac','雪後霜結未釋','韓淲','宋','宋诗','song-poetry','','[]','苦雨翻明雪，酸風結暗霜。',48,'全唐诗/poet.song.176000.json','["苦雨翻明雪，酸風結暗霜。", "晚煙留積冷，曉日度微陽。", "茶竈薪難拾，詩箋筆易僵。", "粗官對窮臘，何事不謀長。"]'),
('e605201a-0bec-44c4-a308-013edf148c40','春雪再作凍甚','韓淲','宋','宋诗','song-poetry','','[]','春雪不可賞，草樹方萌芽。',48,'全唐诗/poet.song.176000.json','["春雪不可賞，草樹方萌芽。", "從渠滅萬徑，徒自負千花。", "兀坐地爐側，困眠山枕斜。", "渾忘瓶粟盡，吟復厭浮誇。"]'),
('dc9bd0d2-a5ee-4ae6-ab9f-20ff72c99d58','雪後如春','韓淲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雪消春意動，樓外已東風。',48,'全唐诗/poet.song.176000.json','["雪消春意動，樓外已東風。", "蘭珮新輸綠，梅瓶久薦紅。", "人生雖向老，歲事豈終窮。", "青瑣黄扉地，西湖一望中。"]'),
('9a6d04f7-cb1e-4cdd-8d7b-1f4936c917dc','對雪','韓淲','宋','宋诗','song-poetry','','[]','有霧光殊慘，無風勢轉豪。',48,'全唐诗/poet.song.176000.json','["有霧光殊慘，無風勢轉豪。", "形欹天已近，氣積地還高。", "上下何其別，周迴任所遭。", "虛緣詩悄悄，幻滅酒陶陶。"]'),
('6e4efac7-bf0d-4880-951c-9403d3c39ac6','雪望','韓淲','宋','宋诗','song-poetry','','[]','山黯荒荒霧，溪凝惻惻風。',48,'全唐诗/poet.song.176000.json','["山黯荒荒霧，溪凝惻惻風。", "乍明收髣髴，欲暮起曚曨。", "岸窄叢梅發，樓高老樹空。", "歸來煖杯酒，爐火夜深紅。"]'),
('2f5edd95-5a11-4287-b2da-589a0cefc8fb','風雪見山林佳絕','韓淲','宋','宋诗','song-poetry','','[]','煙濃山漸白，風急樹還青。',48,'全唐诗/poet.song.176000.json','["煙濃山漸白，風急樹還青。", "鶻落飛鳶逕，鷗浮宿鴈汀。", "周遮迷疊嶂，疾瀉快中泠。", "敝褐輿籃兀，村醪飲易醒。"]'),
('3acf1776-26f3-47f2-a1f5-cfa168607658','雨雪','韓淲','宋','宋诗','song-poetry','','[]','雨雪春將半，山寒澗溢時。',48,'全唐诗/poet.song.176000.json','["雨雪春將半，山寒澗溢時。", "誰題五字句，我得一篇詩。", "淡泊情何遠，綢繆味愈遲。", "閒中且陶寫，治國有安危。"]'),
('62e075ed-f868-4a61-a52d-93898e5f1ac5','雪天','韓淲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','寒色摇窗紙，瓶梅靜吐香。',48,'全唐诗/poet.song.176000.json','["寒色摇窗紙，瓶梅靜吐香。", "小樓深坐穩，矮屋欠伸長。", "雪意垂垂白，雲容淡淡黄。", "西湖林處士，侑食水仙王。"]'),
('94480ac7-cc11-4284-a957-9fdb67c11e0c','春分後一日雪','韓淲','宋','宋诗','song-poetry','','[]','尚覺梅花發，元知柳絮飛。',48,'全唐诗/poet.song.176000.json','["尚覺梅花發，元知柳絮飛。", "舞迴風蕩激，灑急雨霏微。", "解凍羣芳盛，餘寒百卉稀。", "小窗還附火，買酒典春衣。"]'),
('be6d8770-4c94-4b04-b8fb-c717fc4158a2','初八日雪','韓淲','宋','宋诗','song-poetry','','[]','江國春來淺，新年雪未闌。',48,'全唐诗/poet.song.176000.json','["江國春來淺，新年雪未闌。", "雨霏初急急，霰集復漫漫。", "固喜成三白，寧憂已十寒。", "微吟窗色晚，清聽落聲乾。"]'),
('55e99172-a79d-4cc2-b862-ecea11c78dd1','連日大雪','韓淲','宋','宋诗','song-poetry','','[]','年後猶仍臘，時閒即便春。',48,'全唐诗/poet.song.176000.json','["年後猶仍臘，時閒即便春。", "飛花殊惱我，惹絮却隨人。", "天地多奇觀，江湖獨老身。", "瓦溝填已遍，彈壓萬紅塵。"]'),
('6379f7f9-c27a-4ae6-a936-c2745b8fdcf0','雪作  其一','韓淲','宋','宋诗','song-poetry','','[]','臘裏春前雪，江南瘴癘清。',48,'全唐诗/poet.song.176000.json','["臘裏春前雪，江南瘴癘清。", "隔林應得趣，一壑豈忘情。", "已喜疎梅發，遥知細麥生。", "易疎何易密，積厚轉無聲。"]'),
('901e57fa-834a-4be6-99d3-162690715659','雪作  其二','韓淲','宋','宋诗','song-poetry','','[]','開明三景凈，幻化十方清。',48,'全唐诗/poet.song.176000.json','["開明三景凈，幻化十方清。", "此日扁舟景，古人高卧情。", "不知朝氣重，但覺夜寒生。", "漫漫疑無色，綿綿如有聲。"]'),
('07502e8d-905b-433d-a75b-dec9c5abf757','東山','韓淲','宋','宋诗','song-poetry','','[]','指點東山路，松林一望中。',48,'全唐诗/poet.song.176000.json','["指點東山路，松林一望中。", "芙蓉爭弄日，楊柳半凋風。", "我到吟何比，人閒興偶同。", "只宜携妓飲，名宦付諸公。"]'),
('7790f36d-f4db-4cc0-97f7-8f981b1f8cd4','黄巡檢攝官八房場聞西巖有龍湫光怪','韓淲','宋','宋诗','song-poetry','','[]','秋好西巖勝，閒身惜未遊。',48,'全唐诗/poet.song.176000.json','["秋好西巖勝，閒身惜未遊。", "桂花香亂石，楓葉暗長流。", "蠟屐輸君適，錦囊牽我愁。", "定知風雨夕，龍電震深湫。"]'),
('dac82ea6-257a-4b4e-9d21-c6a248db4f57','鷺鷥林','韓淲','宋','宋诗','song-poetry','','[]','一段寒煙上，雲行斷復低。',48,'全唐诗/poet.song.176000.json','["一段寒煙上，雲行斷復低。", "明中山映樹，暗處水平溪。", "村落籬門短，人家草屋齊。", "風回聽幽絕，鳴午有荒鷄。"]'),
('56fa9730-f5f6-4655-890f-34c9c0f498ec','坎石渡','韓淲','宋','宋诗','song-poetry','','[]','春風送春雨，細細濕輿籃。',48,'全唐诗/poet.song.176000.json','["春風送春雨，細細濕輿籃。", "過水航寒淥，橫山觸曉嵐。", "草芽時簇簇，梅片未毿毿。", "問友於何處，田礲坎石南。"]'),
('20185469-0918-49c5-826a-f18e581e1752','灘頭','韓淲','宋','宋诗','song-poetry','','[]','溪頭灘背狹，高下兩三家。',48,'全唐诗/poet.song.176000.json','["溪頭灘背狹，高下兩三家。", "風葉山銜日，煙莎路濕沙。", "傍船初落鴈，隔屋已棲鴉。", "何處吹崖蜜，滿園蕎麥花。"]'),
('f26cc81b-6744-4550-8aed-dbd813061cc4','月巖','韓淲','宋','宋诗','song-poetry','','[]','本意遊雲洞，因行過月巖。',48,'全唐诗/poet.song.176000.json','["本意遊雲洞，因行過月巖。", "西風低細竹，初日上長杉。", "塵外多仙隠，人間易謗讒。", "逍遥且黄帽，憔悴付青衫。"]'),
('5ea5cee6-4009-4021-a67e-cf45ffd1bf59','桐影澗流','韓淲','宋','宋诗','song-poetry','','[]','籬落梧桐月，情人語夜深。',48,'全唐诗/poet.song.176000.json','["籬落梧桐月，情人語夜深。", "露華垂近葉，煙翳失前林。", "茶果隨宜設，琴尊不用尋。", "山虛鳴絡緯，幽澗亦流音。"]'),
('583100f9-49c5-4e1b-8dec-0a56213b5191','禪月臺  其一','韓淲','宋','宋诗','song-poetry','','[]','渺渺凉風起，木犀相次開。',48,'全唐诗/poet.song.176000.json','["渺渺凉風起，木犀相次開。", "舉家空自住，過客有誰來。", "已是冰溪棹，更尋禪月臺。", "鬰乎湖海氣，鷗鳥莫驚猜。"]'),
('414a4b3a-9bad-43cd-b521-38ac5ba99986','禪月臺  其二','韓淲','宋','宋诗','song-poetry','','[]','僧清知野逸，禪月有高臺。',48,'全唐诗/poet.song.176000.json','["僧清知野逸，禪月有高臺。", "自是登山去，誰非入寺來。", "孤花明密葉，落絮起荒苔。", "香篆茶甌久，昏鐘我未回。"]'),
('7040d37c-94b2-4bb1-a8ce-01a4b4d8902c','桃花臺','韓淲','宋','宋诗','song-poetry','','[]','聳壑連天碧，危臺照水紅。',48,'全唐诗/poet.song.176000.json','["聳壑連天碧，危臺照水紅。", "何年仙子宅，今日梵王宮。", "勾漏人雖遠，凌雲話亦空。", "徘徊羨真隠，吟寫分詩窮。"]'),
('aece8ecb-b682-4ed9-ad5f-0c76c4f45f6b','趙推官求久齋詩項平甫有句','韓淲','宋','宋诗','song-poetry','','[]','萬好庵中主，今誰記此人。',48,'全唐诗/poet.song.176000.json','["萬好庵中主，今誰記此人。", "久齋詩固在，晏叟意尤新。", "已逸决科步，要持爲學身。", "尚賢而尚德，餘事了通津。"]'),
('e3e7a5fa-0532-45e8-bb29-c3b910f98cbe','次韵斯遠過風月齋  其一','韓淲','宋','宋诗','song-poetry','','[]','老去親朋少，相過夜達晨。',48,'全唐诗/poet.song.176000.json','["老去親朋少，相過夜達晨。", "百年俱逆旅，千載欠閒人。", "經隔情雖舊，綢繆意轉新。", "板橋籬竹凈，不著世紅塵。"]'),
('d54040d3-21fa-42c0-9e94-2a03476b0bc5','次韵斯遠過風月齋  其二','韓淲','宋','宋诗','song-poetry','','[]','地偏心愈遠，彼自物爭妍。',48,'全唐诗/poet.song.176000.json','["地偏心愈遠，彼自物爭妍。", "屋宇山圍匝，池塘水接連。", "持醪留野飯，推食有溪鮮。", "風月齋曾宿，施村阿那邊。"]'),
('57c54664-0c41-4e27-a33f-9d1ab676909f','趙主簿闢書室因喜三世兩中科舉','韓淲','宋','宋诗','song-poetry','','[]','喜闢書窗好，高垂鴈塔名。',48,'全唐诗/poet.song.176000.json','["喜闢書窗好，高垂鴈塔名。", "孫謀端有自，祖業信能宏。", "山木鬰爭秀，簷花香最清。", "太霞仙袂遠，老眼爲雙明。"]'),
('84d1c33f-606f-446d-813c-352536ef9912','山林堂  其一','韓淲','宋','宋诗','song-poetry','','[]','山林堂總好，六十有餘年。',48,'全唐诗/poet.song.176000.json','["山林堂總好，六十有餘年。", "轉變人常爾，興亡事亦然。", "僧廬雖一坐，道院尚相連。", "彈指三家住，蒼茫起白煙。"]'),
('a0a3ee69-dfd5-4acc-b25a-58ab4af3d6a8','山林堂  其二','韓淲','宋','宋诗','song-poetry','','[]','山林君已得，邱壑我猶居。',48,'全唐诗/poet.song.176000.json','["山林君已得，邱壑我猶居。", "地在名徒換，年深景自如。", "舍人詩可玩，丞相事堪書。", "領畧無輕負，交遊本未疎。"]'),
('43aa4a91-9baa-4625-a5f7-d1079a15f5f1','芙蓉堂和嚴丈韵','韓淲','宋','宋诗','song-poetry','','[]','綠遍小池頭，胡牀一日幽。',48,'全唐诗/poet.song.176000.json','["綠遍小池頭，胡牀一日幽。", "乍晴人意愜，欲暮鳥聲流。", "只道躭閒趣，那知接勝游。", "紅塵飛不到，城府亦山丘。"]'),
('c52c8d0d-b754-4684-acb5-6502c2a95ed4','西山嶽祠','韓淲','宋','宋诗','song-poetry','','[]','西山橋外路，傍水去穿林。',48,'全唐诗/poet.song.176000.json','["西山橋外路，傍水去穿林。", "石柱岧嶢起，溪流宛轉深。", "清音成小立，爽氣入孤斟。", "晻靄叢祠處，歸塗月已侵。"]'),
('16b54188-3cbe-4071-881a-35cf8fced142','凈居院','韓淲','宋','宋诗','song-poetry','','[]','薄晚經禪悅，深更宿淨居。',48,'全唐诗/poet.song.176000.json','["薄晚經禪悅，深更宿淨居。", "急灘鳴斷岸，絕磴下荒墟。", "茗椀僧同把，詩篇我謾書。", "快歟聞梵唄，解榻見鐘魚。"]'),
('35534dc5-641d-46cc-b311-76798c24fbf6','花庵次君實韵','韓淲','宋','宋诗','song-poetry','','[]','居山仍在澗，生事本無多。',48,'全唐诗/poet.song.176000.json','["居山仍在澗，生事本無多。", "老圃初收芋，窮檐待補蘿。", "逃虛惟獨往，入俗也相過。", "語默行藏外，衰榮奈汝何。"]'),
('3a2ac855-cd5c-46dc-b18c-cc63582d9b4f','崇福庵','韓淲','宋','宋诗','song-poetry','','[]','蓊鬰千山曲，周遊一徑斜。',48,'全唐诗/poet.song.176000.json','["蓊鬰千山曲，周遊一徑斜。", "老身多歲月，閑地少風沙。", "度密來尤迥，憑高望更賒。", "小庵含法界，不待野僧茶。"]'),
('e6d22644-aa3a-4ef8-9af8-8108d8868312','白蓮庵分韵','韓淲','宋','宋诗','song-poetry','','[]','好客不常遭，登臨眼自高。',48,'全唐诗/poet.song.176000.json','["好客不常遭，登臨眼自高。", "湖山起煙霧，江海暗風濤。", "酒美情尤暢，詩清氣本豪。", "相從真可樂，左手記持螯。"]'),
('22e2f55c-5cf0-4603-ad07-d46635095708','大明寺','韓淲','宋','宋诗','song-poetry','','[]','小泊大明寺，傷懷復歎誰。',48,'全唐诗/poet.song.176000.json','["小泊大明寺，傷懷復歎誰。", "黄花風未折，赤葉露空垂。", "已往更何說，相望只有詩。", "城南人亦客，數日夢行期。"]'),
('1f882bb8-9a7d-474b-bead-ef600f8cc584','尹山寺','韓淲','宋','宋诗','song-poetry','','[]','風淨綠陰合，山明清晝長。',48,'全唐诗/poet.song.176000.json','["風淨綠陰合，山明清晝長。", "鉢單浮野潤，龕座閟幽香。", "鳥哢集初夏，鶴飛迎夕陽。", "離人何用飲，有客又成章。"]'),
('0014e73b-30d4-4cbc-942d-522be8e57877','朱卿約余倅澗上招昌甫次韵昌甫','韓淲','宋','宋诗','song-poetry','','[]','春雨得晴明，山扉澗道清。',48,'全唐诗/poet.song.176000.json','["春雨得晴明，山扉澗道清。", "朋來何以報，雅集偶然成。", "柳暗枝枝重，花疎片片輕。", "經年不相見，好事滿壺傾。"]'),
('c54582e0-156a-413b-bb36-589ac0fbd2d8','市遠','韓淲','宋','宋诗','song-poetry','','[]','市遠塵埃少，村虛煙雨多。',48,'全唐诗/poet.song.176000.json','["市遠塵埃少，村虛煙雨多。", "極知九日近，無奈一秋何。", "掃徑尋僧話，關門待友過。", "巖香送籬艷，儘可伴婆娑。"]'),
('f376c4de-f62e-448c-b556-8585d1e3cdf0','稻田','韓淲','宋','宋诗','song-poetry','','[]','秋深耕稼熟，綠浪起黄雲。',48,'全唐诗/poet.song.176000.json','["秋深耕稼熟，綠浪起黄雲。", "縱却牛羊踐，難驅鵝鴨羣。", "斷乾根易撥，摧壓穟頻分。", "烟露未全冷，村村晴氣曛。"]'),
('107d9139-9603-41dc-8cb2-1ca045a63ad8','颺糠','韓淲','宋','宋诗','song-poetry','','[]','颺糠新出米，打穀旋推禾。',48,'全唐诗/poet.song.176000.json','["颺糠新出米，打穀旋推禾。", "健婦行茶椀，癡兒守飯籮。", "一秋能飽未，終歲得閒麽。", "農事無終極，人生可奈何。"]'),
('3566cb7c-74a4-44c1-83ca-0a45d9da0cd2','種樹','韓淲','宋','宋诗','song-poetry','','[]','種樹擁牆隙，伐茅開地偏。',48,'全唐诗/poet.song.176000.json','["種樹擁牆隙，伐茅開地偏。", "老衰常問祿，貧窘失求田。", "晴熱山前日，陰凉澗底泉。", "賢哉陶五柳，只愛北窗眠。"]'),
('efd2f053-9e12-4e33-ad72-07f2dc3e95d7','和韵紫芝留句寄之','韓淲','宋','宋诗','song-poetry','','[]','一柱觀能好，臞仙須討尋。',48,'全唐诗/poet.song.176000.json','["一柱觀能好，臞仙須討尋。", "從渠有丘壑，何處沒山林。", "乍惜靈舒試，或矜莊可吟。", "颯然秋氣冷，清夢水之心。"]'),
('58204eb0-735b-4cb6-a0cd-096d18a58fcc','蘇堤芙蓉','韓淲','宋','宋诗','song-poetry','','[]','爛熳芙蓉發，霜前城北花。',48,'全唐诗/poet.song.176000.json','["爛熳芙蓉發，霜前城北花。", "因君話書室，使我出山家。", "風雨三杯後，烟雲一望賒。", "石丁餘興在，相與醉生涯。"]'),
('21da0510-b2e4-4396-8a7b-4485ab41574a','觀柳見桃','韓淲','宋','宋诗','song-poetry','','[]','柳已看看暖，桃仍恰恰開。',48,'全唐诗/poet.song.176000.json','["柳已看看暖，桃仍恰恰開。", "葉間驚甚雨，花外合輕雷。", "不分青春半，其如素髮催。", "官閒惟可句，心醉也尋杯。"]'),
('4f124c0c-002a-4fb0-b06c-5ccaa03d6d45','竹外荷花','韓淲','宋','宋诗','song-poetry','','[]','雨竹翻山翠，風荷漾水香。',48,'全唐诗/poet.song.176000.json','["雨竹翻山翠，風荷漾水香。", "我行三步遠，人飲一杯長。", "不以扶頭去，其如掃迹藏。", "柳花纔露白，梅子又傳黄。"]'),
('90e87d9d-e3ab-4d32-bfb4-6822ce88e100','次韵昌父梅花','韓淲','宋','宋诗','song-poetry','','[]','山水孤根畔，行吟不盡情。',48,'全唐诗/poet.song.176000.json','["山水孤根畔，行吟不盡情。", "花爲天下白，人比聖之清。", "冬日真無對，春風合主盟。", "可憐香浩蕩，歲歲落還生。"]'),
('1ac144c5-8948-4a04-b5e0-6283d399a984','梅','韓淲','宋','宋诗','song-poetry','','[]','霜風小摇落，梅已到南枝。',48,'全唐诗/poet.song.176000.json','["霜風小摇落，梅已到南枝。", "要識人間事，須從物理推。", "虛緣看影動，昭徹待香吹。", "此後唯愁酒，從來未欠詩。"]'),
('a092860d-6010-4404-adde-230c8870d37c','野趣軒見梅花','韓淲','宋','宋诗','song-poetry','','[]','相逢暗香底，又見一年梅。',48,'全唐诗/poet.song.176000.json','["相逢暗香底，又見一年梅。", "枝既爾許瘦，花猶如此開。", "橋橫紅葉逕，山晚白雲堆。", "凍雨時吹灑，人閒寒事催。"]'),
('eb783769-c94f-4924-8aba-2d9eb4d660a0','梅逕','韓淲','宋','宋诗','song-poetry','','[]','掃葉去宿草，園空起碧苔。',48,'全唐诗/poet.song.176000.json','["掃葉去宿草，園空起碧苔。", "晚烟收未了，初日又還來。", "老樹幸無恙，新花應有開。", "年年到寒月，全望數枝梅。"]'),
('81d20935-768a-4031-ac62-83a1af49c196','西軒','韓淲','宋','宋诗','song-poetry','','[]','聞道西軒整，登臨識自今。',48,'全唐诗/poet.song.176000.json','["聞道西軒整，登臨識自今。", "溪山雖郭外，樓殿接池陰。", "舊觀趙岐發，新詩尹喜深。", "水南如此勝，吾老復關心。"]'),
('030a2d8c-709e-4398-ac2c-b7d6e508ec23','題水鵲','韓淲','宋','宋诗','song-poetry','','[]','水鵲衝衝過，山鴉撲撲飛。',48,'全唐诗/poet.song.176000.json','["水鵲衝衝過，山鴉撲撲飛。", "澗深應得趣，樹密自能歸。", "古路人行少，家寒客到稀。", "世途多轗軻，隣里且相依。"]'),
('8001a060-13cc-404e-ba04-820872d0b120','山鳥','韓淲','宋','宋诗','song-poetry','','[]','春晚雨時晴，隔簷山鳥鳴。',48,'全唐诗/poet.song.176000.json','["春晚雨時晴，隔簷山鳥鳴。", "留連因共話，拓落又閒行。", "不選呢喃語，從教格磔聲。", "酒來誰可飲，吾亦小詩成。"]'),
('e5cd70e2-31ba-4354-92e2-2ddaa1721f7c','鴈度','韓淲','宋','宋诗','song-poetry','','[]','鴈度南樓雪，寒聲裂紙窗。',48,'全唐诗/poet.song.176000.json','["鴈度南樓雪，寒聲裂紙窗。", "身雖回五嶺，影亦落千江。", "抱膝吟諸葛，全家隠老龐。", "冥冥避矰繳，一往信難雙。"]'),
('e93714ea-fa6d-407e-b2a3-d0f761edb938','高鴈','韓淲','宋','宋诗','song-poetry','','[]','高鴈承雲薄，參差去復齊。',48,'全唐诗/poet.song.176000.json','["高鴈承雲薄，參差去復齊。", "水村連落岸，山寺迫浮溪。", "風定轉宜遠，日斜元未棲。", "一聲歸兩眼，不負拄枯藜。"]'),
('f27375ac-57e4-4f64-afc1-70444f8efc15','仲至看杜詩分古語妙語老語甚精微','韓淲','宋','宋诗','song-poetry','','[]','刺骨分三語，刳心就一編。',48,'全唐诗/poet.song.176000.json','["刺骨分三語，刳心就一編。", "古來雖簡短，妙處實綿延。", "飛動徐陳外，淋漓劉柳邊。", "泉溪有底急，老乃更精研。"]'),
('e45aa772-fee7-44f5-ba23-c9d04f46a541','和張祐孤山寺詩','韓淲','宋','宋诗','song-poetry','','[]','嵐光湧翠岑，寺影照波心。',48,'全唐诗/poet.song.176000.json','["嵐光湧翠岑，寺影照波心。", "風月明春曉，雲霞起夕陰。", "兩山幽草合，中道綠楊深。", "誰與尋詩句，空懷處士林。"]'),
('0eced1ce-8938-46d1-b653-d05a8687df18','綠筠軒觀坡翁詩刻','韓淲','宋','宋诗','song-poetry','','[]','野寺餘詩石，誰移榜縣齋。',48,'全唐诗/poet.song.176000.json','["野寺餘詩石，誰移榜縣齋。", "閒來得尋句，小立爲興懷。", "人俗真難療，言高不可埋。", "窗前有疎竹，大嚼對吾儕。"]'),
('de298f02-e121-49ee-ae73-0961384ed274','讀魏仲先處士詩有感偶成二首  其一','韓淲','宋','宋诗','song-poetry','','[]','顧影自婆娑，食貧如我何。',48,'全唐诗/poet.song.176000.json','["顧影自婆娑，食貧如我何。", "不嫌知己少，常畏識人多。", "過澗耿獨立，看山行自歌。", "衡茅濕餘雪，風葉亂煙波。"]'),
('27b469d8-421b-4246-919d-498bdd36a899','讀魏仲先處士詩有感偶成二首  其二','韓淲','宋','宋诗','song-poetry','','[]','澗泉韓仲止，生計聊復爾。',48,'全唐诗/poet.song.176000.json','["澗泉韓仲止，生計聊復爾。", "無錢向誰嗟，有酒徒自喜。", "盡日覽形容，流年驚髮齒。", "夜夜猶早眠，寒來更慵起。"]'),
('f4513391-cf36-42b4-bac9-c3d007e18852','晁家觀葉少藴朱希真詩帖尹家諸賢書尺','韓淲','宋','宋诗','song-poetry','','[]','摩挲石林帖，太息巖壑詩。',48,'全唐诗/poet.song.176000.json','["摩挲石林帖，太息巖壑詩。", "竹院茶話久，方齋酒行遲。", "南遊耆舊盡，北客子孫知。", "聚集麥秋日，飄流槐夏時。"]'),
('ee29fbc7-4e9c-4f44-8ddd-3791f768eabf','昌甫以平生詩藁俾趙家浄錄因見題後','韓淲','宋','宋诗','song-poetry','','[]','藁不隨時廢，詩須以藁傳。',48,'全唐诗/poet.song.176000.json','["藁不隨時廢，詩須以藁傳。", "老身猶在澗，舊話只章泉。", "籜笋看成竹，藕荷將出蓮。", "居然閒摸索，久矣奉周旋。"]'),
('19bee6f6-c42b-46f5-b42e-9fc1de62d282','閒居圖','韓淲','宋','宋诗','song-poetry','','[]','閒居本在我，山林皆畫圖。',48,'全唐诗/poet.song.176000.json','["閒居本在我，山林皆畫圖。", "百世有新舊，一朝非卷舒。", "薰風入窗牖，晚雨過庭除。", "小醉同杯者，幽偏得自如。"]'),
('fa56fca2-839c-4ce7-912f-8c5fc2d6e332','夔一翁靈溪古松','韓淲','宋','宋诗','song-poetry','','[]','邂逅靈溪水，東風二月辰。',48,'全唐诗/poet.song.176000.json','["邂逅靈溪水，東風二月辰。", "其誰留象駕，爲我出龍鱗。", "等是人間幻，聊分物外真。", "知心莫彈指，笑殺箇中人。"]'),
('6f5aa6e5-4661-4315-9a70-0f27ab452538','金焦二山雪望圖','韓淲','宋','宋诗','song-poetry','','[]','京口酒可飲，江山開畫圖。',48,'全唐诗/poet.song.176000.json','["京口酒可飲，江山開畫圖。", "幻成清落索，要識雪糢糊。", "不用袁安卧，只消漁父居。", "幾回煙浪遠，落木墮寒蘆。"]'),
('5298388b-a709-4bdb-95a2-cb0673a9d504','題江南','韓淲','宋','宋诗','song-poetry','','[]','邂逅江南景，蕭蕭小桂叢。',48,'全唐诗/poet.song.176000.json','["邂逅江南景，蕭蕭小桂叢。", "不知春已過，常得晚能同。", "冉冉塵寰偪，勞勞色界空。", "飛潛與幽顯，同是一樊籠。"]'),
('dd758ffd-ae1f-4c45-bd71-935d72d1ba9f','次韵胡教授送行詩','韓淲','宋','宋诗','song-poetry','','[]','小作高溪泛，灘光又滿眸。',48,'全唐诗/poet.song.176000.json','["小作高溪泛，灘光又滿眸。", "新春纔兩日，殘歲忽扁舟。", "契闊思良覿，吟哦合共遊。", "掀蓬聞送句，一片雨初收。"]'),
('2e1d34d0-5909-4c15-b315-f1c60000e414','上饒送番江酒次韵謝之','韓淲','宋','宋诗','song-poetry','','[]','薦福湖邊酒，能來爲一中。',48,'全唐诗/poet.song.176000.json','["薦福湖邊酒，能來爲一中。", "傃庵知祖道，鄱郡見家風。", "治縣聊綏撫，詩壇更長雄。", "名章敢酬唱，雨後夕陽紅。"]'),
('d54d9963-1d82-4110-a12d-37e4a42fc732','送黄寺丞商伯浙倉罷歸南康  其一','韓淲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','邂逅登臨勝，從容杯酒閒。',48,'全唐诗/poet.song.176000.json','["邂逅登臨勝，從容杯酒閒。", "脫身方甫里，滿眼已廬山。", "此道天能會，端人世所慳。", "丹心空磊磊，綠鬢只斑斑。"]'),
('5b442feb-4b6b-4fef-8449-e35f8b4ee408','送黄寺丞商伯浙倉罷歸南康  其二','韓淲','宋','宋诗','song-poetry','','[]','問學無窮事，功名有定期。',48,'全唐诗/poet.song.176000.json','["問學無窮事，功名有定期。", "古今誠可見，治否老尤知。", "袖手尋幽隠，存心付嶮巇。", "一時還別去，何日更追隨。"]'),
('b1f2abb6-1ca4-4c90-9b5e-0bef9229d77e','八月四日仁甫行','韓淲','宋','宋诗','song-poetry','','[]','投老不堪別，莫云師友情。',48,'全唐诗/poet.song.176000.json','["投老不堪別，莫云師友情。", "當時建陽聚，何日上饒行。", "舊事消除盡，新愁積漸生。", "酒杯無浪與，醉醒是秋聲。"]'),
('2a615320-57f8-4a34-a250-9f387cf740c4','施教授考校他州','韓淲','宋','宋诗','song-poetry','','[]','陶冶于文舉，才賢定靡遺。',48,'全唐诗/poet.song.176000.json','["陶冶于文舉，才賢定靡遺。", "三年欽掌教，一旦慶衡持。", "過慮同官雜，焉知監試誰。", "無爲我先達，不念士人時。"]'),
('105486de-b654-4243-b7fd-78f3fccbb193','鄭一浙運使','韓淲','宋','宋诗','song-poetry','','[]','好在春秋學，宜乘筆力初。',48,'全唐诗/poet.song.176000.json','["好在春秋學，宜乘筆力初。", "邦畿緣伯討，王道付儒書。", "超乘亦人爾，焚舟其我歟。", "兩年嘉尚意，東上赴傳臚。"]'),
('d1172808-62f3-494a-986f-ac3ebc6d84f3','黄靖州子孫江西漕試','韓淲','宋','宋诗','song-poetry','','[]','淬礪酬先志，家傳合奏功。',48,'全唐诗/poet.song.176000.json','["淬礪酬先志，家傳合奏功。", "子孫當決勝，詞賦况同風。", "南浦聯名處，西江一戰中。", "鄉閭飛榜到，丹桂滿芳叢。"]'),
('5456bf18-5fea-4742-a42e-251f79e8f5cb','送趙五哥秋試','韓淲','宋','宋诗','song-poetry','','[]','才俊毋輕敵，精神急護持。',48,'全唐诗/poet.song.176000.json','["才俊毋輕敵，精神急護持。", "寓鄉能取友，官路必修爲。", "胄監秋高日，禮闈春盛時。", "龍蛇飛健步，好好對丹墀。"]'),
('c286a108-6959-423b-8dbf-7dc90add8387','送葉卿湖南轉運判官  其一','韓淲','宋','宋诗','song-poetry','','[]','野路荷花發，薰風使者車。',48,'全唐诗/poet.song.176000.json','["野路荷花發，薰風使者車。", "老懷諳萬事，雅俗問三閭。", "嶽麓只如此，湘江應可居。", "時平閒護漕，歷覽且舒徐。"]'),
('d024f5c4-e470-4d14-a56e-b74a56e15525','送葉卿湖南轉運判官  其二','韓淲','宋','宋诗','song-poetry','','[]','自恨登門久，飄零歲月深。',48,'全唐诗/poet.song.176000.json','["自恨登門久，飄零歲月深。", "近知無復舊，後定不如今。", "聲迹嗟貧病，形容入醉吟。", "經行纔頃刻，何日奉書琴。"]'),
('509dc5a0-2302-4148-8bcb-e1fa4457b389','送顧丞沿檄徽饒','韓淲','宋','宋诗','song-poetry','','[]','柳暗煙霏綠，花殘雨潤紅。',48,'全唐诗/poet.song.176000.json','["柳暗煙霏綠，花殘雨潤紅。", "夢思今夜遠，別恨一枝同。", "杖舄經行處，江山興寄中。", "紛紛鶑蝶閙，得意正東風。"]'),
('c5fb124f-aa2a-4619-a983-1217de21d4bb','送顧丞赴張軍師辟書','韓淲','宋','宋诗','song-poetry','','[]','細雨春帆外，江波漫漫流。',48,'全唐诗/poet.song.176000.json','["細雨春帆外，江波漫漫流。", "人情雖忍別，風景可言愁。", "時命豈大繆，功名寧罷休。", "倚天長劍在，談笑即公侯。"]'),
('ce08b852-d509-41a0-bc47-50b6fe776423','送俞司戶','韓淲','宋','宋诗','song-poetry','','[]','喜見魁鄉士，薰風唱第歸。',48,'全唐诗/poet.song.176000.json','["喜見魁鄉士，薰風唱第歸。", "豈惟榮里社，亦足慶庭闈。", "仕路當亨奮，儒家要發揮。", "一杯餞行色，靈鷲想煙霏。"]'),
('72b23586-512f-4d0f-9998-01199483ef4f','送施仲益何文蔚余子任及蔣吳二友赴省','韓淲','宋','宋诗','song-poetry','','[]','會適章丘役，寒梅滿路生。',48,'全唐诗/poet.song.176000.json','["會適章丘役，寒梅滿路生。", "逢花百餘韵，顧我不勝情。", "祖送尋言句，相期豈利營。", "南宮三數子，能賦復經明。"]'),
('6f59bcab-3877-4582-b433-619762f847ca','送履常中州買漁艇歸半溪二三友放溜來迎','韓淲','宋','宋诗','song-poetry','','[]','送客中州外，乘流只自看。',48,'全唐诗/poet.song.176000.json','["送客中州外，乘流只自看。", "日斜孤棹晚，月上一溪寒。", "離合原非易，行藏似不難。", "歸來理幽伴，莫負酒盃寬。"]'),
('b2af138a-e387-46e5-9a03-4d6f6e80a95e','送榘恭回貴池','韓淲','宋','宋诗','song-poetry','','[]','乃祖朱轓地，銅章又若翁。',48,'全唐诗/poet.song.176000.json','["乃祖朱轓地，銅章又若翁。", "江山應似舊，郡邑本來同。", "浙右還圍棘，湖邊又艤篷。", "思常游宦處，爲子送秋風。"]'),
('b739d1b5-d511-47ef-ad39-ff905c8b532e','十五日玉山道中見文蔚買酒送之','韓淲','宋','宋诗','song-poetry','','[]','雪嶺吹寒霧，行田過遠村。',48,'全唐诗/poet.song.176000.json','["雪嶺吹寒霧，行田過遠村。", "班荆得佳士，促席置清尊。", "官業從茲始，離懷不用論。", "洋洋晁董對，指日上金門。"]'),
('611cfd32-88d2-4e09-9cd0-5ae6c38d7543','錢塘送元立','韓淲','宋','宋诗','song-poetry','','[]','鳳闕追隨外，龍山判別中。',48,'全唐诗/poet.song.176000.json','["鳳闕追隨外，龍山判別中。", "怒濤翻夕照，遠樹起秋風。", "我亦情何限，君應興與同。", "舉杯淩浩渺，挂席看空濛。"]'),
('697109c4-196c-4891-9a36-bbf5cbbae487','別德久丈','韓淲','宋','宋诗','song-poetry','','[]','四海轉庵老，清詩晚更傳。',48,'全唐诗/poet.song.176000.json','["四海轉庵老，清詩晚更傳。", "幾回看點筆，頃刻誦成篇。", "顧我直瞠若，別公還惘然。", "放懷琴酒地，不覺已三年。"]'),
('eb5869dd-9872-44de-a8f4-09058e8de0f5','別陳平甫','韓淲','宋','宋诗','song-poetry','','[]','清暑蓮堂上，何心詠別詩。',48,'全唐诗/poet.song.176000.json','["清暑蓮堂上，何心詠別詩。", "敢云歸計早，常恨結交遲。", "林舘主人勝，江山客子宜。", "相看在霄漢，折取桂高枝。"]'),
('51a6993b-b769-4b57-85db-a2e3027bb58f','別鄭盱眙','韓淲','宋','宋诗','song-poetry','','[]','谷口從遊久，流光恰六年。',48,'全唐诗/poet.song.176000.json','["谷口從遊久，流光恰六年。", "湖山常盡日，樽酒或談天。", "世豈無他士，公應自昔賢。", "有閒應念我，歸去白雲邊。"]'),
('4acadc59-fa59-471e-b73f-6f57db7f1210','別希之','韓淲','宋','宋诗','song-poetry','','[]','雪裏江亭醉，何時復賦詩。',48,'全唐诗/poet.song.176000.json','["雪裏江亭醉，何時復賦詩。", "豈無閒地飲，那有主人奇。", "忍別君言論，徒勞我夢思。", "尺書頻寄取，莫負此襟期。"]'),
('8dd29e42-39e3-4eb9-85ba-7d4fda600c89','子功過別','韓淲','宋','宋诗','song-poetry','','[]','細酌林亭久，風煙起近鐘。',48,'全唐诗/poet.song.176000.json','["細酌林亭久，風煙起近鐘。", "蒼蒼雖暮色，淅淅是秋容。", "老眼渾相對，幽懷不易逢。", "人生幾兩屐，小榼尚能供。"]'),
('69f1eef0-5911-4ff3-89d2-44c18ef2d8ce','客樓南窗晴日中與坐客論別','韓淲','宋','宋诗','song-poetry','','[]','樓舘南窗暖，追隨欲別時。',48,'全唐诗/poet.song.176000.json','["樓舘南窗暖，追隨欲別時。", "青衫空自老，白髮未相知。", "研墨因成事，爐煙靜入詩。", "家山有泉澗，休問我歸遲。"]'),
('b47bdd44-e117-48da-8131-27cf8c2d7ff3','寄章泉','韓淲','宋','宋诗','song-poetry','','[]','苔竹軒前笋，薰風已布陰。',48,'全唐诗/poet.song.176000.json','["苔竹軒前笋，薰風已布陰。", "清詩誰可和，白酒自成斟。", "顧我塵埃迹，思君泉石心。", "一貧驅就祿，不覺二毛侵。"]'),
('a4da4d70-0d7d-420a-b63f-d947ce0a2cac','寄斯遠','韓淲','宋','宋诗','song-poetry','','[]','不識後田路，林廬近石阿。',48,'全唐诗/poet.song.176000.json','["不識後田路，林廬近石阿。", "卜居誰晤語，屏跡自婆娑。", "木落靈山出，風凉玉水波。", "明年當共醉，盡日爲長哦。"]'),
('f969c0fa-d00e-40f3-a417-7401f8b4da09','寄周景瑜','韓淲','宋','宋诗','song-poetry','','[]','春山風物美，秋半復如何。',48,'全唐诗/poet.song.176000.json','["春山風物美，秋半復如何。", "巖桂香仍發，芙蓉花更多。", "績文應委曲，獵德且婆娑。", "閒僻離羣久，新凉入短歌。"]'),
('96da9c3f-4e4c-4833-a68e-6c5310cbe8e8','寄章丘','韓淲','宋','宋诗','song-poetry','','[]','揚雄一區宅，今乃在章丘。',48,'全唐诗/poet.song.176000.json','["揚雄一區宅，今乃在章丘。", "老樹葉叢茂，小溪灘亂流。", "雞豚爲歲計，穀米望秋收。", "曉暮襟懷裏，携琴得句不。"]'),
('560d4acb-5684-4ea9-b898-3aa6c354d20e','寄楊伯升','韓淲','宋','宋诗','song-poetry','','[]','趁虛雞犬雜，清有草玄家。',48,'全唐诗/poet.song.176000.json','["趁虛雞犬雜，清有草玄家。", "支逕開山嘴，長橋過水涯。", "歲寒梅弄蘂，春到柳舒芽。", "城裏歸時晚，年華與物華。"]'),
('e4e0b509-6440-4f14-83e5-2f1b23c90e15','寄亨中','韓淲','宋','宋诗','song-poetry','','[]','冬至後踰月，風霜欠雪霏。',48,'全唐诗/poet.song.176000.json','["冬至後踰月，風霜欠雪霏。", "團源新市井，高隠舊書幃。", "薪水誰爲給，山園自不歸。", "歲前春事動，佚老是忘機。"]'),
('9d62fe9e-4acb-40fb-9614-cd3db2724dea','鞏仲至和張少卿韵約同寄一首','韓淲','宋','宋诗','song-poetry','','[]','歎息南湖老，詩禪只自深。',48,'全唐诗/poet.song.176000.json','["歎息南湖老，詩禪只自深。", "雨花歸宴坐，風葉對孤斟。", "城郭舟車會，齋房翰墨林。", "遥知定中起，吟嘯也如瘖。"]'),
('04d19cfc-e90a-46d2-bb55-e89bd296b517','次韵王教授同寄昌甫器遠無爲臨漳  其一','韓淲','宋','宋诗','song-poetry','','[]','長哦招隠句，待月坐黄曛。',48,'全唐诗/poet.song.176000.json','["長哦招隠句，待月坐黄曛。", "望望前村雨，行行別渚雲。", "敢期千里共，常恨一橋分。", "鬢影吹凉處，樓高孰與論。"]'),
('27dbb5d5-3d65-4214-ab20-4acc43b1fe9f','次韵王教授同寄昌甫器遠無爲臨漳  其二','韓淲','宋','宋诗','song-poetry','','[]','月到章泉白，冥濛入杳茫。',48,'全唐诗/poet.song.176000.json','["月到章泉白，冥濛入杳茫。", "四邊山影亂，一路水聲長。", "促織吟方動，流螢起復藏。", "夢思飛羽翼，已墮晏齋傍。"]'),
('63fea15a-8342-4bf3-8225-d4f69891d92c','次韵王教授同寄昌甫器遠無爲臨漳  其三','韓淲','宋','宋诗','song-poetry','','[]','清時朝蹟後，休道不知津。',48,'全唐诗/poet.song.176000.json','["清時朝蹟後，休道不知津。", "城市誰多客，山林自少人。", "儘常開老眼，應甚惜閒身。", "愛月聞吳詠，無嫌更薦紳。"]'),
('d9b5d279-606a-4836-a072-96239b102be4','次韵王教授同寄昌甫器遠無爲臨漳  其四','韓淲','宋','宋诗','song-poetry','','[]','濡須誰築塢，玉兔王迷離。',48,'全唐诗/poet.song.176000.json','["濡須誰築塢，玉兔王迷離。", "兩歲能爲守，五言應報詩。", "息峰延月夜，稔稻得秋時。", "湖海驚零落，無癡了事兒。"]'),
('c8113c10-8499-455f-9da9-a06ca4a21a7d','次韵王教授同寄昌甫器遠無爲臨漳  其五','韓淲','宋','宋诗','song-poetry','','[]','甌閩何處是，絕嶺更危谿。',48,'全唐诗/poet.song.176000.json','["甌閩何處是，絕嶺更危谿。", "乘障消蠻虺，望洋蒐水犀。", "庾公情不淺，朱老世思齊。", "乘月胡牀坐，角巾隨意低。"]'),
('7653985c-be02-43f9-8f52-422196efbaf1','昌甫回自大明見過別後二詩寄之  其一','韓淲','宋','宋诗','song-poetry','','[]','袖遺大明果，編因徐照題。',48,'全唐诗/poet.song.176000.json','["袖遺大明果，編因徐照題。", "騷吟歸是正，香味得非迷。", "鄰邑十方轉，到城還重携。", "新霜林路滑，山遠羨高棲。"]'),
('be91aea8-a718-4435-843d-686ae76a1d3b','昌甫回自大明見過別後二詩寄之  其二','韓淲','宋','宋诗','song-poetry','','[]','早鬻翁歸去，窗寒自撥灰。',48,'全唐诗/poet.song.176000.json','["早鬻翁歸去，窗寒自撥灰。", "算程明日到，失記去年來。", "雨葉頻仍墮，雪梅相次開。", "吾生亦華髮，易怕惹塵埃。"]'),
('d929c6d0-8f2c-4c41-9ec5-79d5209a5a8a','寄鄭一','韓淲','宋','宋诗','song-poetry','','[]','禪月臺高冷，溪虛城背山。',48,'全唐诗/poet.song.176000.json','["禪月臺高冷，溪虛城背山。", "人烟知井絡，鳥雀見灣澴。", "竹裏繁霜後，梅邊欲雪間。", "讀書有幽子，歲晚更怡顔。"]'),
('f87c0752-2f26-4304-b825-21f6d8c051e8','寄履道','韓淲','宋','宋诗','song-poetry','','[]','宰上廬深迥，將書定苦心。',48,'全唐诗/poet.song.176000.json','["宰上廬深迥，將書定苦心。", "夜聲寒柏慘，晴色古苔侵。", "徑側牛羊履，山空鴈鶩臨。", "明燈撥殘火，幽夢理寒衾。"]'),
('937fe568-db6e-4f79-8041-2f9d27bf949f','寄尹一','韓淲','宋','宋诗','song-poetry','','[]','尋丈方齋地，移居城市東。',48,'全唐诗/poet.song.176000.json','["尋丈方齋地，移居城市東。", "燈窗唯刻苦，編集入磨礲。", "北客家能爾，南遊事不同。", "常思文獻大，祖道古人風。"]'),
('a3698fd7-43f1-4738-927f-f10edfafec5b','寄王二萬頃','韓淲','宋','宋诗','song-poetry','','[]','一曲清江上，君能靜結廬。',48,'全唐诗/poet.song.176000.json','["一曲清江上，君能靜結廬。", "年豐時釀黍，身老更收書。", "家世遺風在，閭閻是事疎。", "只宜沮溺地，著我伴耕鋤。"]'),
('ddcd6f9e-8fca-4192-ae63-b29e624cd34a','二十九日歸寄鄭一','韓淲','宋','宋诗','song-poetry','','[]','野外青巖寺，城邊禪月臺。',48,'全唐诗/poet.song.176000.json','["野外青巖寺，城邊禪月臺。", "收功行藥後，排悶坐輿來。", "宿雨苗當熟，新凉桂已開。", "誰知老丘壑，自不奈塵埃。"]'),
('9f809610-8f8a-4020-88c1-c410f43e05f9','浙運寄聲子任子恕','韓淲','宋','宋诗','song-poetry','','[]','浙水文場好，成才屬少年。',48,'全唐诗/poet.song.176000.json','["浙水文場好，成才屬少年。", "龍遊看過鎖，漁浦發潮船。", "才地當强仕，朝廷正選賢。", "會逢余與趙，爲報各揚鞭。"]'),
('48344205-4e88-4f2e-a66b-fbdd1521e883','寄敖器之','韓淲','宋','宋诗','song-poetry','','[]','絕代敖夫子，春來定若何。',48,'全唐诗/poet.song.176000.json','["絕代敖夫子，春來定若何。", "新豐逆旅市，叩角飯牛歌。", "漢相延東閣，成周在泰和。", "彙征調玉燭，小用亦金坡。"]'),
('d2551df9-852f-4e32-b80d-951275be166e','寄仁□','韓淲','宋','宋诗','song-poetry','','[]','分外僧家好，如今更住山。',48,'全唐诗/poet.song.176000.json','["分外僧家好，如今更住山。", "都無城市閙，只有水雲閒。", "打供隨緣後，罷參開淨間。", "紛紛底榮宦，何事復相關。"]'),
('bdf8c776-ec94-498a-b357-763cd815c0f8','趙寺丞之子來代書寄','韓淲','宋','宋诗','song-poetry','','[]','只有心情在，都無言語吟。',48,'全唐诗/poet.song.176000.json','["只有心情在，都無言語吟。", "子官忻見面，翁節苦爲心。", "霜雪歲云暮，風雷冬已深。", "老身相望處，徒益鬢華侵。"]'),
('20e151c3-41ee-43db-98dd-7656831753ce','柬周五哥','韓淲','宋','宋诗','song-poetry','','[]','我欲春山去，呼兒取杖藜。',48,'全唐诗/poet.song.176000.json','["我欲春山去，呼兒取杖藜。", "弄晴方見日，吹雨又生泥。", "悵望還歸舍，懷思未隔溪。", "會當舒此興，花草步芳蹊。"]'),
('f75f0e16-3c80-4824-a9a5-48ac8d02f6e7','寄趙十監試','韓淲','宋','宋诗','song-poetry','','[]','先朝重詞賦，人道小賢良。',48,'全唐诗/poet.song.176000.json','["先朝重詞賦，人道小賢良。", "善記推才博，雕章驗識長。", "宗英龍首盛，名字鴈行香。", "王舍城中試，月華仙桂芳。"]'),
('51b71ec7-1cce-4c8b-b91e-20ee793d4df6','贈趙十  其一','韓淲','宋','宋诗','song-poetry','','[]','泉石何關爾，多應潔我塵。',48,'全唐诗/poet.song.176000.json','["泉石何關爾，多應潔我塵。", "試揩雙泪眼，徒惜一吟身。", "選甚年年別，須當物物親。", "相遭雖澹泊，秋得雨方新。"]'),
('be0c4694-9839-4193-b0d2-2700a23e030a','贈趙十  其二','韓淲','宋','宋诗','song-poetry','','[]','薄夢驚秋曉，窮原喜夕陰。',48,'全唐诗/poet.song.176000.json','["薄夢驚秋曉，窮原喜夕陰。", "只知閒迤邐，不覺老侵尋。", "鳥翼應知倦，蟬聲亦和吟。", "酒闌詩更逸，巖寺記同臨。"]'),
('0cfe57cb-25bb-42fc-947c-496e23fc6511','贈成季子任','韓淲','宋','宋诗','song-poetry','','[]','心跡能閒淡，何勞數面親。',48,'全唐诗/poet.song.176000.json','["心跡能閒淡，何勞數面親。", "沙坑元似故，坎石更常新。", "陶寫非流俗，尋思隔幾塵。", "清溪舟楫句，乃復在茲辰。"]'),
('474aa524-b3af-4c44-8c94-4f71f07f80ff','贈懃老','韓淲','宋','宋诗','song-poetry','','[]','客路何曾好，禪林一味清。',48,'全唐诗/poet.song.176000.json','["客路何曾好，禪林一味清。", "鐘聲回短夢，梵唄入幽情。", "綺語多生債，塵勞宿念輕。", "詩邊懷抱嬾，聊復爲君傾。"]'),
('91bac585-4986-4b9e-b8ed-26b67888312b','贈趙成父','韓淲','宋','宋诗','song-poetry','','[]','教得兒登第，儒科一素風。',48,'全唐诗/poet.song.176000.json','["教得兒登第，儒科一素風。", "故家欣未艾，吾黨不應窮。", "拭目行都裏，興懷寓里中。", "如君老兄弟，好去一尊同。"]'),
('5259e8b6-ff87-4fe3-bd35-f7aa5efc8671','贈子任','韓淲','宋','宋诗','song-poetry','','[]','每恨沙坑遠，十年纔兩過。',48,'全唐诗/poet.song.176000.json','["每恨沙坑遠，十年纔兩過。", "閒人身則爾，君子意如何。", "古井無驚浪，喬林不改柯。", "留連因繾綣，躑躅爲婆娑。"]'),
('094900ea-e164-479c-bdb3-6084845e071f','贈曾承務','韓淲','宋','宋诗','song-poetry','','[]','紹興人物志，贛上盛諸曾。',48,'全唐诗/poet.song.176000.json','["紹興人物志，贛上盛諸曾。", "積厚培應固，流長續更興。", "四明愁獨散，二浙喜相承。", "再緝文盟日，吾儕豈面朋。"]'),
('38e121ff-7b1c-4eed-a8d2-a9dfc908c37a','初六日呈仲至兄聞告假欲還婺','韓淲','宋','宋诗','song-poetry','','[]','已是多疎隔，更言當暫歸。',48,'全唐诗/poet.song.176000.json','["已是多疎隔，更言當暫歸。", "歲新雲未解，風轉雪還飛。", "曉岸蒼山古，春江白浪肥。", "過家無宿留，急此醉芳菲。"]'),
('be9a9df7-c69c-43c3-9317-3c7e80b0078c','呈坐客','韓淲','宋','宋诗','song-poetry','','[]','酒在詩情外，詩成酒量中。',48,'全唐诗/poet.song.176000.json','["酒在詩情外，詩成酒量中。", "氣清吟奧妙，神受醉朦朧。", "到手千鍾在，回身一笑空。", "故家人有幾，我輩興無窮。"]'),
('e8a0785e-ed57-4f9f-b734-864be3aec281','愛客','韓淲','宋','宋诗','song-poetry','','[]','婆餠焦何急，飛鳴小竹間。',48,'全唐诗/poet.song.176000.json','["婆餠焦何急，飛鳴小竹間。", "雨多溪漲水，雲厚日藏山。", "景物固無恙，人情終等閒。", "老來惟愛客，茶果或相關。"]'),
('9fa90d41-971c-4185-8f67-d09b62ed6ebf','王有道詩刊成謝林教授','韓淲','宋','宋诗','song-poetry','','[]','七卷靈溪集，有誰能爲傳。',48,'全唐诗/poet.song.176000.json','["七卷靈溪集，有誰能爲傳。", "既勞親校勘，便得與雕鎸。", "從昔詩雖在，因茲名可全。", "摩挲新敘引，羨爾廣文賢。"]'),
('990c997c-07bb-4fc4-8ce9-86c056d3bada','十月十九日頭昏痛忽教授過別','韓淲','宋','宋诗','song-poetry','','[]','卧病空山裏，公來忽語離。',48,'全唐诗/poet.song.176000.json','["卧病空山裏，公來忽語離。", "風行殘葉日，霜淨早梅時。", "湖上探龍井，天邊入鳳池。", "西疇富魚蟹，能復寄清詩。"]'),
('02eddd2d-1097-454e-b804-918350061a0f','次韵胡教授','韓淲','宋','宋诗','song-poetry','','[]','猶記到階除，虛懷不自居。',48,'全唐诗/poet.song.176000.json','["猶記到階除，虛懷不自居。", "從容姑借酒，厭飫愜於書。", "物物徒娛客，人人足勝予。", "年來數相過，此道定誰如。"]'),
('d67d84f4-60ac-4436-bb70-ccb87751ce97','用處晦韵送蘄州趙教授有懷寺簿王聖俞丈','韓淲','宋','宋诗','song-poetry','','[]','得官居上第，掌教喜青春。',48,'全唐诗/poet.song.176000.json','["得官居上第，掌教喜青春。", "斆學須相長，仁賢必可親。", "舉文元不易，斯道本常親。", "若理中州話，應逢舊德人。"]'),
('ac2272b2-0d4e-401a-9403-3a200bc3431a','和孟五十六韵','韓淲','宋','宋诗','song-poetry','','[]','沙淨水爭流，輿籃呼渡幽。',48,'全唐诗/poet.song.176000.json','["沙淨水爭流，輿籃呼渡幽。", "酒行因繾綣，詩到得夷猶。", "盛日騰高步，飛雲裂醉眸。", "江山無盡藏，楚尾又吳頭。"]'),
('c5aadc5d-4d46-4e2b-ab77-b3f2a94b04c2','和昌甫夢中見寄','韓淲','宋','宋诗','song-poetry','','[]','高人山枕曉，何必問鈞天。',48,'全唐诗/poet.song.176000.json','["高人山枕曉，何必問鈞天。", "自覺無他夢，誰言有此篇。", "交遊疑是熟，時序亦非便。", "寒食蘧蘧裏，清江憶釣鯿。"]'),
('61d89567-e709-4546-9655-0aa62870bfec','昌甫題徐仙民詩集因和韵兩篇  其一','韓淲','宋','宋诗','song-poetry','','[]','斷自晚唐後，人人盡做詩。',48,'全唐诗/poet.song.176000.json','["斷自晚唐後，人人盡做詩。", "生前由我集，名後得誰碑。", "眇眇三靈見，蕭蕭一葉知。", "塔山林覆土，若奠替芳巵。"]'),
('a0ea0f31-f1fe-4fea-86c8-4fbaf31dd6f0','昌甫題徐仙民詩集因和韵兩篇  其二','韓淲','宋','宋诗','song-poetry','','[]','東南蟠海嶠，天也斲閒民。',48,'全唐诗/poet.song.176000.json','["東南蟠海嶠，天也斲閒民。", "歲月高儕侶，江湖競比倫。", "楊劉萬代手，溫李再生身。", "雪跨水懸處，遊魂不見人。"]'),
('34b0052d-4fc1-4828-9fb1-1f1d1e8a6d85','和子仁','韓淲','宋','宋诗','song-poetry','','[]','古達多從隠，巢由復卞隨。',48,'全唐诗/poet.song.176000.json','["古達多從隠，巢由復卞隨。", "既拚身似葉，何藉命如絲。", "世道無庸憾，人生有不爲。", "深山窮谷裏，莫負酒盈巵。"]'),
('96ec0589-1182-46cf-9009-bbf7bd69cca3','周七有詩續至和韵','韓淲','宋','宋诗','song-poetry','','[]','淨坊成野約，樂地可清論。',48,'全唐诗/poet.song.176000.json','["淨坊成野約，樂地可清論。", "士以世何貴，佛於人轉尊。", "茫茫空遠志，歷歷任驚魂。", "連日巖花發，佳哉月下門。"]'),
('cfcea869-9df8-482c-998a-d6edacd5d266','和履道出會宗伯回訪趙晏叟  其一','韓淲','宋','宋诗','song-poetry','','[]','山行仍野次，零落數家村。',48,'全唐诗/poet.song.176000.json','["山行仍野次，零落數家村。", "積雨浮秧把，隨風護笋根。", "去來應自喜，將送與誰論。", "寢飯朝昏處，翛然付五言。"]'),
('23a62590-a75c-4d58-b253-d1318470668e','和履道出會宗伯回訪趙晏叟  其二','韓淲','宋','宋诗','song-poetry','','[]','江山迎世父，芒種夏將深。',48,'全唐诗/poet.song.176000.json','["江山迎世父，芒種夏將深。", "家道修遺事，人生懷好音。", "衰榮元自古，雅俗况居今。", "歸興尋幽隠，柴門月色侵。"]'),
('65eeb295-a949-47e4-808b-cc5c160a7cfd','昌甫有詩和韵','韓淲','宋','宋诗','song-poetry','','[]','寒食家家酒，誰人不賦詩。',48,'全唐诗/poet.song.176000.json','["寒食家家酒，誰人不賦詩。", "久陰忻霽日，餘潤入花時。", "此老非三畧，今朝欲四維。", "落紅供醉卧，松底著殘棋。"]'),
('fce87d83-1af3-4941-a540-4b61f78d3cae','昌甫入城席上和韵','韓淲','宋','宋诗','song-poetry','','[]','因人雖暫賞，分韵偶然成。',48,'全唐诗/poet.song.176000.json','["因人雖暫賞，分韵偶然成。", "不道觥慵舉，那知僕屢更。", "老成關世道，交舊豈時情。", "簷雨林逾靜，橋風境過清。"]'),
('40e1cf72-0f3a-42e0-a190-ac00653d839d','二十四日回泊東阜和舊題酬唱十九年矣','韓淲','宋','宋诗','song-poetry','','[]','海棠枝上日，依舊照窗明。',48,'全唐诗/poet.song.176000.json','["海棠枝上日，依舊照窗明。", "文會驚猶在，重來詠轉清。", "林廬記經始，花逕已栽成。", "良友仙山去，空留百世名。"]'),
('051b660a-72e3-4938-9897-454e592d34c0','初六日過尹家再和西軒韵贈子文  其一','韓淲','宋','宋诗','song-poetry','','[]','制宅思前緒，軒名到處幽。',48,'全唐诗/poet.song.176000.json','["制宅思前緒，軒名到處幽。", "不須論夢蝶，只是合盟鷗。", "北望劉琨嘯，南遊庾信愁。", "百年五字在，吾豈爲詩謀。"]'),
('4ddd1a3d-7421-4401-975d-affda590e679','初六日過尹家再和西軒韵贈子文  其二','韓淲','宋','宋诗','song-poetry','','[]','家學流風懿，成才世自豪。',48,'全唐诗/poet.song.176000.json','["家學流風懿，成才世自豪。", "出羣能秀發，何獨類賢髦。", "紬繹遺編富，規模古訓高。", "青青秋桂子，餘事等毫毛。"]'),
('4f93ed37-2dc9-4937-83b9-46f20e3b6243','鄭一病中見寄和韵答之','韓淲','宋','宋诗','song-poetry','','[]','愛酒阮宣杖，倦行陶令輿。',48,'全唐诗/poet.song.176000.json','["愛酒阮宣杖，倦行陶令輿。", "閒投本無意，垂老亦何居。", "萬事付杯水，一貧唯飯蔬。", "秋懷苦相望，幽寺挾殘書。"]'),
('3aba64b9-b2fe-49f7-9fd7-e2a5de850dcf','元立復和伯皋送行詩次韵併答之  其一','韓淲','宋','宋诗','song-poetry','','[]','倒載臨離日，搜吟出餞時。',48,'全唐诗/poet.song.176000.json','["倒載臨離日，搜吟出餞時。", "老身猶藉酒，親意不徒詩。", "山水東西去，園池上下隨。", "凝香兵衛戟，應復野人思。"]'),
('6337d67b-81fa-48f6-8703-7ab5af0b0f8c','元立復和伯皋送行詩次韵併答之  其二','韓淲','宋','宋诗','song-poetry','','[]','半隠平生句，年來果謂何。',48,'全唐诗/poet.song.176000.json','["半隠平生句，年來果謂何。", "軻雄牆已及，李杜壘終摩。", "籍籍須傳遠，紛紛何足多。", "斯文千古事，自笑得如麽。"]'),
('10b3ad38-d78d-472e-b25d-72ba4624a8b5','次韵所東因有感答之','韓淲','宋','宋诗','song-poetry','','[]','籌邊須善策，是古肯非今。',48,'全唐诗/poet.song.176000.json','["籌邊須善策，是古肯非今。", "名士自江左，丈人誰漢陰。", "敝廬清晝永，幽磴白雲深。", "可在唱酬句，豈多陶寫心。"]'),
('47a825ec-2f3f-4b78-bc9b-f6902837ca6a','和卿贈別次韵答之','韓淲','宋','宋诗','song-poetry','','[]','兩岸春風暖，山花水噴泉。',48,'全唐诗/poet.song.176000.json','["兩岸春風暖，山花水噴泉。", "歸期雖較晚，行樂肯輸先。", "來燕知猶未，賓鴻信欲遄。", "故人詩送我，吟思滿江天。"]'),
('9fc3e88b-6524-423b-9897-b8bce3e0b2bc','次韵趙理丞','韓淲','宋','宋诗','song-poetry','','[]','相去如霄壤，寒吟只短歌。',48,'全唐诗/poet.song.176000.json','["相去如霄壤，寒吟只短歌。", "春前知歲早，臘裏見時和。", "待把閒情賦，空將老眼摩。", "年年願强健，江海有披蓑。"]'),
('d75da231-ecff-430a-99a2-9ec39647abb6','次韵昌甫九峰留詩  其一','韓淲','宋','宋诗','song-poetry','','[]','遠峙山常峻，幽泉水自泠。',48,'全唐诗/poet.song.176000.json','["遠峙山常峻，幽泉水自泠。", "幾回靈井曲，如入九峰屏。", "雅以平生舊，空懷萬古靈。", "詩成霜露濕，原上草青青。"]'),
('b18ac083-3748-4d3f-8df3-de69c5fbd97d','次韵昌甫九峰留詩  其二','韓淲','宋','宋诗','song-poetry','','[]','每恨居山淺，扶輿過九峰。',48,'全唐诗/poet.song.176000.json','["每恨居山淺，扶輿過九峰。", "幾年無恃怙，常此痛音容。", "風雨寒垂點，雲煙晚復重。", "市廛多汩沒，忽爾脫塵蹤。"]'),
('a553cedf-f6e3-4772-830a-58d7ba187ec8','次韵昌甫九峰留詩  其三','韓淲','宋','宋诗','song-poetry','','[]','每恨居山淺，扶輿過九峰。',48,'全唐诗/poet.song.176000.json','["每恨居山淺，扶輿過九峰。", "溪清通亂石，路暗失長松。", "鬚鬢時時換，身心事事慵。", "雨寒樵牧斷，朝暮聽鳴鐘。"]'),
('3f42d4df-03c9-4748-8a51-ae9add53a4e6','次韵昌甫九峰留詩  其四','韓淲','宋','宋诗','song-poetry','','[]','每恨居山淺，扶輿過九峰。',48,'全唐诗/poet.song.176000.json','["每恨居山淺，扶輿過九峰。", "塵銷草色淡，嵐染木陰濃。", "瓢飲真堪羨，盤飧粗得供。", "一庵饑渴外，何事入心胸。"]'),
('a2e350cf-68b3-429e-970f-0b86d166262c','次韵吳推官','韓淲','宋','宋诗','song-poetry','','[]','楚雨黄梅熟，卑枝易積陰。',48,'全唐诗/poet.song.176000.json','["楚雨黄梅熟，卑枝易積陰。", "山園三逕少，澗水一溝深。", "蕭颯寒猶起，低回老亦侵。", "尋詩爲君和，絕唱有遺音。"]'),
('f9b81051-a26b-40d5-806a-bc8e32176450','次韵趙景伯南巖','韓淲','宋','宋诗','song-poetry','','[]','披藿南巖寺，無僧林蕩虛。',48,'全唐诗/poet.song.176000.json','["披藿南巖寺，無僧林蕩虛。", "崖懸徒可望，泉滴又何居。", "時世悠悠轉，心情落落疎。", "山行有吟嘯，佳處莫躊躇。"]'),
('bb119908-3b99-4c7a-b7ed-5e53b696b7d1','昌甫自衢送客入城得其詩次韵呈之  其一','韓淲','宋','宋诗','song-poetry','','[]','霜風散焦暵，霧日照寒凉。',48,'全唐诗/poet.song.176000.json','["霜風散焦暵，霧日照寒凉。", "影迹連山白，聲華落木黄。", "俗情難以澹，幽事不關忙。", "我覺年逾邁，君吟詩益昌。"]'),
('000a3e14-1cc1-4f60-af77-4e8d269af9a5','昌甫自衢送客入城得其詩次韵呈之  其二','韓淲','宋','宋诗','song-poetry','','[]','三見木樨開，香傳好客來。',48,'全唐诗/poet.song.176000.json','["三見木樨開，香傳好客來。", "龐公隠能出，杜老句欣陪。", "市近心終遠，交親語易諧。", "柯山玉溪水，人道謂何哉。"]'),
('220601bf-123d-4c3b-b38d-f8b305eef1f2','昌甫自衢送客入城得其詩次韵呈之  其三','韓淲','宋','宋诗','song-poetry','','[]','蓬戶爲君開，荒園少舊栽。',48,'全唐诗/poet.song.176000.json','["蓬戶爲君開，荒園少舊栽。", "猶存小籬落，不比一軒苔。", "前月訪彼矣，今朝同此哉。", "人間花草地，終古歲寒梅。"]'),
('3579b061-7eac-4bee-9cb0-cc62f82bc2d1','次韵昌甫見寄','韓淲','宋','宋诗','song-poetry','','[]','相逢雖數數，共話祇匆匆。',48,'全唐诗/poet.song.176000.json','["相逢雖數數，共話祇匆匆。", "不覺中秋過，還當九日中。", "登臺嗟往事，覓句憶高風。", "人物方彫謝，吾儕孰與同。"]'),
('af46b444-ef4b-47d4-aa0a-6d87e9413606','次韵昌甫見詒','韓淲','宋','宋诗','song-poetry','','[]','屏跡丘園矣，秋來事亦忙。',48,'全唐诗/poet.song.176000.json','["屏跡丘園矣，秋來事亦忙。", "開林朝斧鈍，鑽紙夜燈煌。", "一潦屋殊損，屢空饑易忘。", "俄而對時菊，種種髮能長。"]'),
('a1a40eb1-f547-4ab4-a5bd-f4d59462284b','次韵昌甫歸後所寄','韓淲','宋','宋诗','song-poetry','','[]','祇怪深居簡，徒希逸駕攀。',48,'全唐诗/poet.song.176000.json','["祇怪深居簡，徒希逸駕攀。", "風清玉田路，雲白瑞峰山。", "心事吟章外，情文作帖間。", "相望初若遠，一出本非艱。"]'),
('8488d0c0-5cee-47c6-85d2-8617cb11e7fc','二十日入章泉次韵昌甫所贈','韓淲','宋','宋诗','song-poetry','','[]','老夢困其獨，微吟愜所同。',48,'全唐诗/poet.song.176000.json','["老夢困其獨，微吟愜所同。", "閒中徒著句，高處盡歸翁。", "一代文章志，諸方風俗通。", "息交惟士賤，尚友則師隆。"]'),
('cc9f0b5e-1a8e-4b76-ad15-e9401487c98d','次韵昌甫別後所寄','韓淲','宋','宋诗','song-poetry','','[]','居山更入山，百事不相關。',48,'全唐诗/poet.song.176000.json','["居山更入山，百事不相關。", "只有猿狙外，更無鷄犬間。", "淵泉得沿濯，巖岫要躋攀。", "最是高人語，時容見一斑。"]'),
('40507c3b-def7-4a7f-be8e-7a9186f6237f','徐仁甫建陽一別忽已二十五六年見過惘然次韵道院池上所作','韓淲','宋','宋诗','song-poetry','','[]','逃暑身何寄，池荷竹院間。',48,'全唐诗/poet.song.176000.json','["逃暑身何寄，池荷竹院間。", "交朋如玉潔，名字飲冰閒。", "吹雨餘毫髮，鳴泉落珮環。", "長年葑村路，往日考亭山。"]'),
('376207cb-3ea8-42c4-9133-290ae3725936','次韵成季病中見寄','韓淲','宋','宋诗','song-poetry','','[]','閒意忽不愜，秋聲隔市門。',48,'全唐诗/poet.song.176000.json','["閒意忽不愜，秋聲隔市門。", "千林空白晝，一葉下黄昏。", "歸馬正修睦，捕蝗俄討論。", "願豐穰慮歉，相望數家村。"]'),
('3d9e960b-0e5c-4f70-8b11-abc6c44c0bc7','次韵仲至','韓淲','宋','宋诗','song-poetry','','[]','能道意中事，詩來看復嗟。',48,'全唐诗/poet.song.176000.json','["能道意中事，詩來看復嗟。", "春風殊作惡，春雪固能佳。", "引玉下梅萼，輸金上柳芽。", "睡翁山水縣，隔竹定敲茶。"]'),
('6b6c3b8c-ed66-4675-84a6-1bd91cd20a1d','次韵黄崇道','韓淲','宋','宋诗','song-poetry','','[]','長夏得閒趣，無過里社中。',48,'全唐诗/poet.song.176000.json','["長夏得閒趣，無過里社中。", "往來三逕日，舒寫一襟風。", "幸與陶潛醉，從渠阮籍窮。", "人家鶑燕裏，猶記淡烟籠。"]'),
('35416cb7-b387-443d-9ed1-0986a7d83570','馬莊甫經過留五字次韵','韓淲','宋','宋诗','song-poetry','','[]','老却溪山眼，荒寒不見人。',48,'全唐诗/poet.song.176000.json','["老却溪山眼，荒寒不見人。", "草深多爛舊，梅淺易尖新。", "歲事誰嗟晚，年齡自惜春。", "相逢既相識，聊借酒精神。"]'),
('4e9b7d63-a12d-4d9c-af07-f6ad93abb89f','盧教授約周縣丞來訪次周丞韵','韓淲','宋','宋诗','song-poetry','','[]','今古山陰道，誰吟雪下船。',48,'全唐诗/poet.song.176000.json','["今古山陰道，誰吟雪下船。", "久將隨俗好，便擬作春妍。", "朝市無閒日，山林有瀑泉。", "薰風吹兩鬢，蠶事欲三眠。"]'),
('83846556-09de-4b72-ae8a-810435c2d7b1','次韵仲至','韓淲','宋','宋诗','song-poetry','','[]','臘向殘年去，春從元日迴。',48,'全唐诗/poet.song.176000.json','["臘向殘年去，春從元日迴。", "急搔雙鬢髮，渾染幾塵埃。", "詩話驚頻改，杯停喜更催。", "椒盤隨綵勝，金柳带瓊梅。"]'),
('9878c7b4-53f0-48fb-a8fd-ff40dd14863e','次韵趙將','韓淲','宋','宋诗','song-poetry','','[]','箯輿來澗谷，話久不知還。',48,'全唐诗/poet.song.176000.json','["箯輿來澗谷，話久不知還。", "自是無人到，誰能有我閒。", "綠陰晴樹外，清馥野花間。", "客去鷄鳴午，呼兒又掩關。"]'),
('986ce412-624f-465b-a12f-5990afea5986','次韵德久','韓淲','宋','宋诗','song-poetry','','[]','澄淨清秋夜，詩成兩眼明。',48,'全唐诗/poet.song.176000.json','["澄淨清秋夜，詩成兩眼明。", "佳人千古意，濁酒一杯情。", "湖水魚龍舞，天風鴻鴈鳴。", "菊花九日近，便合上崢嶸。"]'),
('0e614bbe-5e04-4833-8412-b271b5295f22','次韵劉召虎','韓淲','宋','宋诗','song-poetry','','[]','論交貴知己，相與可忘年。',48,'全唐诗/poet.song.176000.json','["論交貴知己，相與可忘年。", "久旱爲霖日，餘凉畏暑天。", "浮沉非識治，用舍不因賢。", "只有青山好，分明阿那邊。"]'),
('fb90469a-ee55-4b2f-9dc7-10315416da4c','昌甫念某生朝寄詩來次韵謝之','韓淲','宋','宋诗','song-poetry','','[]','俾壽情何重，酬吟報恐遲。',48,'全唐诗/poet.song.176000.json','["俾壽情何重，酬吟報恐遲。", "拜嘉誠自喜，友誼尚誰爲。", "醑我遥相命，思翁不獨詩。", "晚生頭已禿，敬長眼空窺。"]'),
('c08591f9-c212-4a56-9fd7-be59c5b3236e','次韵昌甫  其一','韓淲','宋','宋诗','song-poetry','','[]','相知新固樂，人物易如林。',48,'全唐诗/poet.song.176000.json','["相知新固樂，人物易如林。", "遊愛郭同許，衰思范與吟。", "放歌能共和，會約待重斟。", "還我晏齋隠，何嘗枉尺尋。"]'),
('f9ebfae7-1c8e-4d8a-8a2b-246bd02a39cf','次韵昌甫  其二','韓淲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','相送思前日，同吟憶此時。',48,'全唐诗/poet.song.176000.json','["相送思前日，同吟憶此時。", "情親五字句，意妙一篇詩。", "長夏看榴火，薰風入鬢絲。", "西湖渺何許，終愧北山移。"]'),
('b68ac25e-c41d-405b-91a3-f305c491d8f3','次韵昌甫  其三','韓淲','宋','宋诗','song-poetry','','[]','古道定誰成，莊周與淨名。',48,'全唐诗/poet.song.176000.json','["古道定誰成，莊周與淨名。", "勞哉秦外趣，甚矣潁陽清。", "並舍披衣去，行橋拄杖聲。", "遥知園列樹，新好看初榮。"]'),
('3c77a3f7-2058-4395-ab96-949a9c20b0b3','次韵昌甫  其四','韓淲','宋','宋诗','song-poetry','','[]','別後忽逢雪，歲寒殊惘然。',48,'全唐诗/poet.song.176000.json','["別後忽逢雪，歲寒殊惘然。", "自憐疎酒盞，誰識寄詩編。", "老矣思離闊，遐哉漫屬聯。", "金仙玉田路，來往記今年。"]'),
('acea757c-7f9a-431e-a856-b90b50e49ebd','次韵昌甫  其五','韓淲','宋','宋诗','song-poetry','','[]','章泉泉上屋，茅補定牽蘿。',48,'全唐诗/poet.song.176000.json','["章泉泉上屋，茅補定牽蘿。", "意象時間少，心思古處多。", "暑風今夏矣，凉雨奈秋何。", "顧我顛毛白，門閒亦養疴。"]'),
('6562ca57-6293-48a3-b438-c322d5ebd5fa','次韵昌甫  其六','韓淲','宋','宋诗','song-poetry','','[]','老嘆交情少，閒知友道難。',48,'全唐诗/poet.song.176000.json','["老嘆交情少，閒知友道難。", "何堪武夷曲，更近子陵灘。", "絕口談龍肉，從渠食馬肝。", "敢云棲擇木，隨世一枝安。"]'),
('730a2601-3fac-488e-a9c9-f8d3df4c0a1d','次韵昌甫  其七','韓淲','宋','宋诗','song-poetry','','[]','秋風過秋雨，眇眇正愁予。',48,'全唐诗/poet.song.176000.json','["秋風過秋雨，眇眇正愁予。", "望斷嗟何寄，吟成懶自書。", "齒摇誠有數，鬢禿恐無餘。", "幾載章泉水，山深只晏如。"]'),
('41a55857-a79d-4e75-96b9-6bcfd23f9ab8','次韵景瑜','韓淲','宋','宋诗','song-poetry','','[]','盡道今年煖，冬來十月中。',48,'全唐诗/poet.song.176000.json','["盡道今年煖，冬來十月中。", "更無霜共雪，時有雨隨風。", "薄宦其如拙，浮生乃奈窮。", "衰顔負清鏡，猶借酒能紅。"]'),
('b341fdd6-fbaa-4e2c-9837-ec56b611c16c','同周次公步尋起雲舊基次韵','韓淲','宋','宋诗','song-poetry','','[]','起雲亭不見，立盡水邊人。',48,'全唐诗/poet.song.176000.json','["起雲亭不見，立盡水邊人。", "滿眼高情少，驚心得句頻。", "龜毛真兔角，鳳翼漫龍鱗。", "山澤行吟久，淵明漉酒巾。"]'),
('f70f5471-dfb1-46f1-bec0-b4e399d88b3d','次韵見詒','韓淲','宋','宋诗','song-poetry','','[]','倦作京華夢，秋霖失旱乾。',48,'全唐诗/poet.song.176000.json','["倦作京華夢，秋霖失旱乾。", "故人相見後，不覺話悲酸。", "酒琖還更酌，詩盟復肇端。", "如翁真老大，莫數鄭都官。"]'),
('1ab1adeb-d8c6-4af0-bc8c-56f66fbe3feb','次韵蓋友','韓淲','宋','宋诗','song-poetry','','[]','林外山平遠，衰顔落筆難。',48,'全唐诗/poet.song.176000.json','["林外山平遠，衰顔落筆難。", "風聲催日晚，雲物轉霜寒。", "京邑九衢盛，江湖千里寬。", "交遊盡詩社，名譽得蘇端。"]'),
('f884e9fa-bbb6-4d99-b311-0233ac7eb478','次韵潘文','韓淲','宋','宋诗','song-poetry','','[]','小試登山屐，因閒見野僧。',48,'全唐诗/poet.song.176000.json','["小試登山屐，因閒見野僧。", "談禪還靜憩，望遠得虛憑。", "分韵吟心適，歸來醉夢騰。", "酒醒深夜起，推枕只寒燈。"]'),
('8f5431ac-1645-48c7-8176-16fe4d475e82','次韵伯皋','韓淲','宋','宋诗','song-poetry','','[]','易別難相聚，傾懷語未終。',48,'全唐诗/poet.song.176000.json','["易別難相聚，傾懷語未終。", "敝廬纔郭外，高隠遠鄉中。", "天地常年在，溪山觸處同。", "營營非我事，有句欲乘風。"]'),
('45b4c84d-259d-4804-a3d9-aaf0b8c73258','次韵斯遠見贈','韓淲','宋','宋诗','song-poetry','','[]','剝啄君家去，同爲兩縣來。',48,'全唐诗/poet.song.176000.json','["剝啄君家去，同爲兩縣來。", "趙施元保社，徐鄭亦尊罍。", "便做壯心已，須饒老眼開。", "交遊容易別，十日重徘徊。"]'),
('12fe4f43-dcf7-42cc-9306-9701c5bb436c','次韵希之','韓淲','宋','宋诗','song-poetry','','[]','山遠飛晴靄，春江景有餘。',48,'全唐诗/poet.song.176000.json','["山遠飛晴靄，春江景有餘。", "推窗風浩蕩，憑几日徐舒。", "何計用休沐，忘懷得燕居。", "從容話千載，隨飯只盤蔬。"]'),
('7e3db185-0284-4fb3-9869-9e66aa175a15','次韵石魯瞻','韓淲','宋','宋诗','song-poetry','','[]','髣髴徂徠老，因詩只遡風。',48,'全唐诗/poet.song.176000.json','["髣髴徂徠老，因詩只遡風。", "胡爲猶爾健，應怪懶能工。", "此道今皆棄，高情自不同。", "和成千里夢，題寄欲歸鴻。"]'),
('a41a8a2c-ea44-4a1e-b404-e196a01ab684','次韵昌甫鎸歙硯','韓淲','宋','宋诗','song-poetry','','[]','圓澤三生石，陳登百尺樓。',48,'全唐诗/poet.song.176000.json','["圓澤三生石，陳登百尺樓。", "硯因銘共永，詩與字俱鎪。", "此老非徒耳，閒人更點頭。", "魏銅那敢擬，朱錫盍爲侔。"]'),
('052e6c83-5514-4725-a0f4-abfd9e84c1ec','次韵叔向','韓淲','宋','宋诗','song-poetry','','[]','君在南湖住，我同東郭遊。',48,'全唐诗/poet.song.176000.json','["君在南湖住，我同東郭遊。", "陳蕃無下榻，王粲有登樓。", "吟苦詩陶寫，酣沉酒拍浮。", "德輝天外鳳，機靜水邊鷗。"]'),
('c4968cef-6a26-4458-85d4-39d1abe71bcd','次韵趙清江','韓淲','宋','宋诗','song-poetry','','[]','煙禁憑誰會，杯寒只自斟。',48,'全唐诗/poet.song.176000.json','["煙禁憑誰會，杯寒只自斟。", "幾多原上恨，猶記少年心。", "領畧因初見，經行或重臨。", "攀花問楊柳，絲竹也清音。"]'),
('07587d7b-8001-4bf9-959c-77e1d0bbce6a','次韵上饒  其一','韓淲','宋','宋诗','song-poetry','','[]','有句閒中得，應知百慮休。',48,'全唐诗/poet.song.176000.json','["有句閒中得，應知百慮休。", "麥天連澗冷，梅月夾山稠。", "喚起陶潛醉，能消庾信秋。", "朝端富鵷鷺，邊瑣少貔貅。"]'),
('174915e6-d421-42c8-95ba-5a41f777b31a','次韵上饒  其二','韓淲','宋','宋诗','song-poetry','','[]','官事人人衮，誰憐寂寞鄉。',48,'全唐诗/poet.song.176000.json','["官事人人衮，誰憐寂寞鄉。", "卑高多貴賤，寒暑易炎凉。", "歎息絃歌美，殷勤篇翰長。", "閒民爲興起，交道得其詳。"]'),
('1239df72-acbd-4eb4-b25c-0b5d57501533','次韵成季  其一','韓淲','宋','宋诗','song-poetry','','[]','短短長長柳，紅紅白白梅。',48,'全唐诗/poet.song.176000.json','["短短長長柳，紅紅白白梅。", "溪浮何處棹，山對別時盃。", "春事還應爾，人情有是哉。", "却因嘉樹底，渾見好花開。"]'),
('f2355d60-4e55-4f3f-aa77-8b11c48ea89f','次韵成季  其二','韓淲','宋','宋诗','song-poetry','','[]','畎畝秋來雨，村村不厭多。',48,'全唐诗/poet.song.176000.json','["畎畝秋來雨，村村不厭多。", "暑應無熱惱，凉可起沉疴。", "花動門中桂，葉浮池上荷。", "南豅詩到手，想像與同哦。"]'),
('c7df898b-3e1b-43fb-a1d5-d4e2e0015ab4','次韵周五哥','韓淲','宋','宋诗','song-poetry','','[]','莫道春猶遠，連陰初未曦。',48,'全唐诗/poet.song.176000.json','["莫道春猶遠，連陰初未曦。", "振衣行復阻，岸幘坐成癡。", "芳事誠須酒，交情豈爲詩。", "清明翻手是，常記舊相隨。"]'),
('0a394ab3-b4e7-4465-8eaf-1a6ca57ec608','次韵子任','韓淲','宋','宋诗','song-poetry','','[]','城郭秋風晚，人來自遠山。',48,'全唐诗/poet.song.176000.json','["城郭秋風晚，人來自遠山。", "荒荒行硌确，淺淺渡潺湲。", "虎尾休論履，龍鱗且願攀。", "過從因煮餠，惜取片時閒。"]'),
('18839aa9-6d70-4b73-8529-1cc3c7a890af','小酌餞耿幹運趙推官分韵復和韵  其一','韓淲','宋','宋诗','song-poetry','','[]','潛魚空浪藻，倦翼漫風林。',48,'全唐诗/poet.song.176000.json','["潛魚空浪藻，倦翼漫風林。", "邂逅留連飲，從容取次吟。", "名言驚思苦，離話惜情深。", "昔爾那知此，他還未必今。"]'),
('425cd521-a192-46cc-a031-d60a50bfd3bd','小酌餞耿幹運趙推官分韵復和韵  其二','韓淲','宋','宋诗','song-poetry','','[]','雨歇收朝潤，風迴起夕凉。',48,'全唐诗/poet.song.176000.json','["雨歇收朝潤，風迴起夕凉。", "君今過澧浦，客有到錢塘。", "落澗高槐影，浮簷細竹光。", "尋思須浪賦，雜伯更談王。"]'),
('6d7d111b-f054-42e1-ac57-5cb71f30af17','二十四日昌甫斯遠子功集雪觀次韵斯遠','韓淲','宋','宋诗','song-poetry','','[]','閒將詩句和，凉自雨中來。',48,'全唐诗/poet.song.176000.json','["閒將詩句和，凉自雨中來。", "可是不相聚，那能得此回。", "香爐連筆格，茶椀更山罍。", "一架蒲陰綠，殘陽晚又開。"]'),
('7e4f5150-8b44-43aa-9c33-9015fef326bf','示棐榘茶','韓淲','宋','宋诗','song-poetry','','[]','乃祖文名在，羣兒好讀書。',48,'全唐诗/poet.song.176000.json','["乃祖文名在，羣兒好讀書。", "愁深我將去，恨不汝同居。", "風俗隨時薄，人情莫自疎。", "傳家詩禮學，勤苦要三餘。"]'),
('3c24d175-736e-4513-a342-c9a6c6c9b32d','亨中之孫求詩','韓淲','宋','宋诗','song-poetry','','[]','團源古君子，老去孰追隨。',48,'全唐诗/poet.song.176000.json','["團源古君子，老去孰追隨。", "隠約孫能奉，高深我却知。", "家傳無自畫，鄉薦有誰爲。", "成立須勤苦，清哉是祖師。"]'),
('a3381c65-d59d-4754-9949-a1017d0bfba7','柬乙翁上人  其一','韓淲','宋','宋诗','song-poetry','','[]','草樹隨時長，城春雨易蒸。',48,'全唐诗/poet.song.176000.json','["草樹隨時長，城春雨易蒸。", "閒人來入市，官舍却逢僧。", "覿面非竿木，何心是葛藤。", "喫茶看洗鉢，忘却老昏瞢。"]'),
('58f0cd6d-9d03-448e-9bb6-d40ad5954acd','柬乙翁上人  其二','韓淲','宋','宋诗','song-poetry','','[]','山玉冰溪地，常年衲子過。',48,'全唐诗/poet.song.176000.json','["山玉冰溪地，常年衲子過。", "杖挑明月重，笠戴白雲多。", "洞遠今無鷲，湖高舊見鵝。", "與君三歎息，佛法付天魔。"]'),
('b99cf975-e6c6-40a4-a8c4-773c583badc5','九月四日黄子功林德久自柳州共汎訪銛師','韓淲','宋','宋诗','song-poetry','','[]','閒得琴尊勝，尋詩約俊遊。',48,'全唐诗/poet.song.176000.json','["閒得琴尊勝，尋詩約俊遊。", "欲窮山下寺，旋買水邊舟。", "誰悟牽黄犬，自應盟白鷗。", "野晴秋意思，渾付碧雲休。"]'),
('69be16a3-c7df-47e6-90fe-9e29eb1447d6','寄乙上人','韓淲','宋','宋诗','song-poetry','','[]','盂蘭盆會日，元自目犍連。',48,'全唐诗/poet.song.176000.json','["盂蘭盆會日，元自目犍連。", "攝化應無量，追修亦有緣。", "荒荒誰正令，的的漫單傳。", "業報衆生苦，三塗對四禪。"]'),
('ecaee8ca-62fd-434a-844f-184667eec4ab','過沙坑留遺余子任','韓淲','宋','宋诗','song-poetry','','[]','約我沙坑外，南豅共說詩。',48,'全唐诗/poet.song.176000.json','["約我沙坑外，南豅共說詩。", "山林已黄葉，籬菊尚青枝。", "良晤真難事，相期若舊知。", "翩翩乘果下，想像入城時。"]'),
('13e34cff-f41b-471e-86fa-06862a59f2f2','次韵斯遠喜予見過  其一','韓淲','宋','宋诗','song-poetry','','[]','無地尋明月，因人且出遊。',48,'全唐诗/poet.song.176000.json','["無地尋明月，因人且出遊。", "猖狂疑有謂，拓落信何求。", "山水知回薄，杯觴得獻酬。", "秋情吾卜夜，垂老未爲羞。"]'),
('e433e7ae-4433-48a6-9e3b-865c610fa845','次韵斯遠喜予見過  其二','韓淲','宋','宋诗','song-poetry','','[]','望望公超市，烟雲滿眼過。',48,'全唐诗/poet.song.176000.json','["望望公超市，烟雲滿眼過。", "經時不相見，此地復如何。", "物色真難識，情懷敢自多。", "喜君詩在手，吟諷亦婆娑。"]'),
('1b105068-cd16-44d3-ad4f-5e5def062e25','同鄭處晦尹子潛過趙十','韓淲','宋','宋诗','song-poetry','','[]','老去吟何味，分明水一杯。',48,'全唐诗/poet.song.176000.json','["老去吟何味，分明水一杯。", "目前輕過節，身外待尋梅。", "尚以同盟至，寧云不速來。", "此時心寸折，猶幸小徘徊。"]'),
('690579ea-2eb8-4f2d-bf20-669d0dc4dd65','十一日過景瑜','韓淲','宋','宋诗','song-poetry','','[]','下郭山盤屋，軒亭景晏如。',48,'全唐诗/poet.song.176000.json','["下郭山盤屋，軒亭景晏如。", "淺斟留把酒，細字見抄書。", "河洛無由返，江湖已定居。", "子孫皆土著，魚米我還疎。"]'),
('234f326c-9ee5-4d87-b08c-bc0b61b2c7eb','子似見過','韓淲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','門外梅枝曉，人來乃是君。',48,'全唐诗/poet.song.176000.json','["門外梅枝曉，人來乃是君。", "衝風迎臘日，欲雪動寒雲。", "禹穴山陰道，西湖處士墳。", "我懷何用寄，搔鬢白紛紛。"]'),
('c1033ad7-a0d5-4770-b8e7-a8b14b5e28d6','邢大聲廣聲于去非携酒約解元衡畢叔文及蕃過陳叔尹值叔尹之出成四十字','韓淲','宋','宋诗','song-poetry','','[]','松竹連花樹，田園带隠廬。',48,'全唐诗/poet.song.176000.json','["松竹連花樹，田園带隠廬。", "青衫寧累我，黄卷不孤渠。", "載酒期問字，經邱逢命車。", "龐公雖浪出，且慰故人疎。"]'),
('cf51ac11-8269-49cc-a781-d33ea6ca2ea5','添倅至因謁之來訪乃故相郡侯之子也','韓淲','宋','宋诗','song-poetry','','["\u8861\u5c71"]','相國推前輩，通家復勝游。',48,'全唐诗/poet.song.176000.json','["相國推前輩，通家復勝游。", "人知新別駕，我嘆舊州侯。", "世數推遷遠，時情展轉休。", "衡山雲冉冉，玉水日悠悠。"]'),
('59f71f8b-c411-4241-a748-175f43e73a4f','過王仲如林隠','韓淲','宋','宋诗','song-poetry','','[]','莫把閑情醉，空留野老詩。',48,'全唐诗/poet.song.176000.json','["莫把閑情醉，空留野老詩。", "雷聲梅雨過，日影竹風吹。", "林隠訪前話，華陽非近知。", "相過二三友，比客更邀誰。"]'),
('20007772-b713-4eb3-a8ea-e82499ab1eb5','昌甫携兒姪載酒來送分韵得房字','韓淲','宋','宋诗','song-poetry','','[]','春寺不尋芳，詩翁作醉鄉。',48,'全唐诗/poet.song.176000.json','["春寺不尋芳，詩翁作醉鄉。", "花香空夾徑，草細恰通房。", "僧固枯禪寂，人非好句忙。", "出城惟怕晚，冉冉趁斜陽。"]'),
('88fff923-2676-4bc6-ab3b-7e514066465b','二十七日周七載酒且懷春伯','韓淲','宋','宋诗','song-poetry','','[]','十載梅陂酒，青巖始共游。',48,'全唐诗/poet.song.176000.json','["十載梅陂酒，青巖始共游。", "香傳高樹晚，涼映小塘秋。", "飲亦何勞醉，吟成苦未休。", "補陀山下客，能爲此回頭。"]'),
('6524c727-70fb-4f8f-b411-05732aeb6d6e','黄仁卿見過留之而無酒因要宋衡携酒以至得以款語已又酌仁卿携行之茶成四十字','韓淲','宋','宋诗','song-poetry','','[]','雨重烏臼樹，風微萱草花。',48,'全唐诗/poet.song.176000.json','["雨重烏臼樹，風微萱草花。", "重携萬安酒，再瀹建州茶。", "邂逅年何晚，情親日自加。", "兩君真玉立，而我愧無瑕。"]'),
('9edf24b2-7882-45b5-81db-a034c084b078','施重益留夜飲','韓淲','宋','宋诗','song-poetry','','[]','秋閒得幽討，竹澗款門時。',48,'全唐诗/poet.song.176000.json','["秋閒得幽討，竹澗款門時。", "絕壑通流水，橫橋壅斷陂。", "巖花已芬郁，山木未凋披。", "靜夜持杯酒，人清更說詩。"]'),
('ec781b01-b9ae-4e60-8c10-f6457be2edf9','蹈中見過山間  其一','韓淲','宋','宋诗','song-poetry','','[]','貴賤曾何在，悲歡孰使然。',48,'全唐诗/poet.song.176000.json','["貴賤曾何在，悲歡孰使然。", "如君真絕足，奈我已華顛。", "勳業誰彝鼎，文章自簡編。", "中原有前輩，吾憶范忠宣。"]'),
('f72f7937-ae8b-4e14-a821-246dd81ff506','蹈中見過山間  其二','韓淲','宋','宋诗','song-poetry','','[]','三月多風雨，門前澗水侵。',48,'全唐诗/poet.song.176000.json','["三月多風雨，門前澗水侵。", "岸花無一片，園柳忽成陰。", "有客因留飲，呼兒取次斟。", "橋南春郭外，珍重肯幽尋。"]'),
('c9c47519-3f4d-4da1-82af-fd7af9536c15','小飲春山','韓淲','宋','宋诗','song-poetry','','[]','細雨初冬夜，溪山書院燈。',48,'全唐诗/poet.song.176000.json','["細雨初冬夜，溪山書院燈。", "閑來四五輩，留飲兩三升。", "久坐形神定，高談意氣增。", "我歸眠蕙帳，誰信在家僧。"]'),
('2bcb01cb-1d84-4e61-a5fc-eb36d447b5ca','初十日黄仲明見過留飯却同至野趣飲茶  其一','韓淲','宋','宋诗','song-poetry','','[]','風力催雲雪，比鄰往復還。',48,'全唐诗/poet.song.176000.json','["風力催雲雪，比鄰往復還。", "穿林踏黄葉，沿澗看青山。", "共飯因而款，煎茶益以閒。", "歲寒如此過，他事肯相關。"]'),
('2fe91cea-65da-4c11-8eba-49114edf3601','初十日黄仲明見過留飯却同至野趣飲茶  其二','韓淲','宋','宋诗','song-poetry','','[]','山空吹雪意，草樹晚天寒。',48,'全唐诗/poet.song.176000.json','["山空吹雪意，草樹晚天寒。", "烟抹忽收起，風行時坐看。", "鷄聲村店遠，雁落市橋寬。", "儘道閑多病，老身還自安。"]'),
('424c62ed-d8db-42a5-85df-6a7740964e19','同昌甫陪朱虞卿約尹鄭二士飲食艮堂','韓淲','宋','宋诗','song-poetry','','[]','到處逢春酌，閑吟過此生。',48,'全唐诗/poet.song.176000.json','["到處逢春酌，閑吟過此生。", "落花亭上飲，芳草岸邊行。", "我亦非無興，人應不負情。", "風光共流轉，樓外遠山明。"]'),
('5c8db220-e3e2-45b8-ab1b-78c28e2b9348','朱虞卿以詩送家釀和韵','韓淲','宋','宋诗','song-poetry','','[]','絕嘆交遊落，何論比與周。',48,'全唐诗/poet.song.176000.json','["絕嘆交遊落，何論比與周。", "座開今日酒，門款昔年秋。", "濯錦江頭杜，玄都觀裏劉。", "相望風雅在，天地一虛舟。"]'),
('a89207e8-c9c2-42c7-8ba2-ba698274610a','王校以詩送筍及一壺','韓淲','宋','宋诗','song-poetry','','[]','磵道迷蓬藿，山空且熟眠。',48,'全唐诗/poet.song.176000.json','["磵道迷蓬藿，山空且熟眠。", "雨多從蔽日，風橫任吹烟。", "歡喜收牋翰，提携到酒泉。", "更逢初斸筍，急急和新篇。"]'),
('d15f4076-2dc4-4e52-9ae0-4abb0af73972','坐客競置殽核因賦示尹子潛','韓淲','宋','宋诗','song-poetry','','[]','魚蟹人人饌，柑橙盞盞詩。',48,'全唐诗/poet.song.176000.json','["魚蟹人人饌，柑橙盞盞詩。", "醪芳隣所借，情分客能知。", "城外溪山在，門前巷陌卑。", "寒雖欺木葉，春已報梅枝。"]'),
('81361f8a-9502-4bdb-875a-c549c813e161','雪寒錢','韓淲','宋','宋诗','song-poetry','','[]','加賜雪寒錢，歡聲禁旅傳。',48,'全唐诗/poet.song.176000.json','["加賜雪寒錢，歡聲禁旅傳。", "妻孥應盼盼，兒女定躚躚。", "醉熟千家酒，炊香萬竈烟。", "何須談挾纊，王道本通天。"]'),
('50e75880-5b42-471b-969f-b0704588cf56','次韵昌甫分遺烏石茶','韓淲','宋','宋诗','song-poetry','','[]','茶經空爛讀，讀罷出溪頭。',48,'全唐诗/poet.song.176000.json','["茶經空爛讀，讀罷出溪頭。", "竹杖雖流憇，藜牀復倦投。", "尋思煎以喫，展轉卧而遊。", "烏石瓶能好，甌犧底用憂。"]'),
('8d40019a-5de4-414f-8854-e340ea88b746','昌甫送艾葉餠','韓淲','宋','宋诗','song-poetry','','[]','我愛郊居者，春芽艾葉長。',48,'全唐诗/poet.song.176000.json','["我愛郊居者，春芽艾葉長。", "雲舂和豆實，霧摘带麻香。", "杞菊天隨舊，蓬蒿仲蔚常。", "近來關膈病，且得煖枯腸。"]'),
('ec227c6b-5e32-437c-bfa0-70e093c74087','十三日至草衣院因上靈山閣','韓淲','宋','宋诗','song-poetry','','[]','塔院橫塘草，階梯大谷林。',48,'全唐诗/poet.song.176000.json','["塔院橫塘草，階梯大谷林。", "風聲迷近渚，雨氣暗遥岑。", "索麵僧回鉢，持醪客屢斟。", "依歸從早出，靜寄得幽尋。"]'),
('dc17b0bc-7e45-4966-a6f2-a0b05876e0a5','謝乙翁上人','韓淲','宋','宋诗','song-poetry','','[]','雨後晚窗日，方盃燎竹爐。',48,'全唐诗/poet.song.176000.json','["雨後晚窗日，方盃燎竹爐。", "二茶勞見餉，一記又能摹。", "看了信何有，啜來昏更無。", "阿師莫作劇，我悔不逃儒。"]'),
('506cb6db-25c6-4474-9c32-19563037af99','訪杰上人','韓淲','宋','宋诗','song-poetry','','[]','澗道濕凍雨，林扉藏斷雲。',48,'全唐诗/poet.song.176000.json','["澗道濕凍雨，林扉藏斷雲。", "寒聲肅肅起，暝色杳杳分。", "齋餘隨動息，禪外失知聞。", "坐久催煎茗，爐深亦炷熏。"]'),
('ddbffaac-bea6-4624-a9bf-21260aa74551','初二日大雪訪杰上人','韓淲','宋','宋诗','song-poetry','','[]','山中知我老，雪裏見僧清。',48,'全唐诗/poet.song.176000.json','["山中知我老，雪裏見僧清。", "物色添幽意，年華近俗情。", "樹遥風共晚，岸窄水初生。", "一榻茶烟熟，更聞寒雀聲。"]'),
('c973827a-3e81-4ee5-8d9c-fea1752c546e','王通叟自溫之贛過門因得五字','韓淲','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','菴高一宿覺，不是二乘禪。',48,'全唐诗/poet.song.176000.json','["菴高一宿覺，不是二乘禪。", "露柱燈籠裏，貍奴白牯邊。", "前資欽戒臘，參學待機緣。", "吸盡西江水，從將此話傳。"]'),
('ceb18f86-cb26-422b-873e-36c2a8347e0a','建陽連周賓幼入佛學近祝髮江東真運副請住信鵝湖不出','韓淲','宋','宋诗','song-poetry','','[]','不住鵝湖寺，惟甘小隠堂。',48,'全唐诗/poet.song.176000.json','["不住鵝湖寺，惟甘小隠堂。", "老來纔祝髮，靜處久燒香。", "妙喜機緣峻，竹源滋味長。", "建陽橋下水，夢見亦清涼。"]'),
('f6e4d67b-51d8-4382-8e48-2dbee999c96a','寄天目僧文禮滅翁','韓淲','宋','宋诗','song-poetry','','[]','生怕人饒舌，詩吟不著題。',48,'全唐诗/poet.song.176000.json','["生怕人饒舌，詩吟不著題。", "飄零驚已晚，依約夢還迷。", "但願乘風去，何言立雪齊。", "萬緣誰百計，谷隠自巖棲。"]'),
('6bd8a851-1ced-4c28-9d3d-82fac1bd4367','柬宿之藏主','韓淲','宋','宋诗','song-poetry','','[]','雪觀碧雲合，簷花带女蘿。',48,'全唐诗/poet.song.176000.json','["雪觀碧雲合，簷花带女蘿。", "磬清收梵唄，香淨入禪那。", "粥飯門房少，經齋城市多。", "幽人隣近住，取次一相過。"]'),
('658eb41c-e4f3-49bf-9131-565edf3c6641','乙上人來過','韓淲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','恰自山巖轉，又逢瓶錫過。',48,'全唐诗/poet.song.176000.json','["恰自山巖轉，又逢瓶錫過。", "風軒灑飛雨，雲壑漾迴波。", "且喫廬山飯，休論擊壤歌。", "塵勞空恁麽，禪悅竟如何。"]'),
('e2584292-56f2-47ff-a697-aff25da4f161','雨中過春山','韓淲','宋','宋诗','song-poetry','','[]','溪南上下郭，得得過春山。',48,'全唐诗/poet.song.176000.json','["溪南上下郭，得得過春山。", "自嘆欲何往，相從非等閑。", "波深魚潑潑，竹靜鳥關關。", "若箇漁舟晚，延緣見葦間。"]'),
('9625dff6-ffeb-40d7-b8eb-1b2133df2dbd','十六日過萬頃新田','韓淲','宋','宋诗','song-poetry','','[]','別墅能懷謝，開軒既有雲。',48,'全唐诗/poet.song.176000.json','["別墅能懷謝，開軒既有雲。", "大田還築室，小醉話知聞。", "葉縣仙非俗，蘭亭字不羣。", "吾儕今老矣，隨意度朝曛。"]'),
('42686e58-dfb6-428b-ab07-52c9a9cace32','山崦','韓淲','宋','宋诗','song-poetry','','[]','山崦昏濛雨，溪流冷落風。',48,'全唐诗/poet.song.176000.json','["山崦昏濛雨，溪流冷落風。", "隔城須會友，閉戶獨衰翁。", "交氣遊譚外，存神燕息中。", "可容諸念起，應與此心同。"]'),
('91224a85-c923-40d9-8c98-375c5db50a42','晚步東庵','韓淲','宋','宋诗','song-poetry','','[]','薄晚登山屐，霜林脫葉飛。',48,'全唐诗/poet.song.176000.json','["薄晚登山屐，霜林脫葉飛。", "中間看月上，低處覺烟霏。", "鷄犬近相接，人家遠獨稀。", "故園應好在，凝望客思歸。"]'),
('6e4178c3-450c-41f4-89f4-72b04285b1a1','二十一日晴過山園  其一','韓淲','宋','宋诗','song-poetry','','[]','飯了小園間，乘晴享此閑。',48,'全唐诗/poet.song.176000.json','["飯了小園間，乘晴享此閑。", "因行掃黄葉，隨意看青山。", "取逕嫌林密，爲基惜地慳。", "繩牀坐來久，一飲又徐還。"]'),
('8cc6c1d7-301b-48c8-bf7c-dcd2c517dbce','二十一日晴過山園  其二','韓淲','宋','宋诗','song-poetry','','[]','飲亦微微醉，歸來睡思濃。',48,'全唐诗/poet.song.176000.json','["飲亦微微醉，歸來睡思濃。", "身形方放脚，鼻息自填胸。", "熟美可嫌老，輕安只益慵。", "分明醒復寢，不覺到昏鐘。"]'),
('f7891f80-7760-4e53-b789-1a34d407ab0f','幽豔','韓淲','宋','宋诗','song-poetry','','[]','幽豔人誰識，孤標我豈堪。',48,'全唐诗/poet.song.176000.json','["幽豔人誰識，孤標我豈堪。", "水烟春淡淡，山日晚酣酣。", "縱以詩隨看，其如把酒參。", "子游清興發，半道記輿籃。"]'),
('751c5c7e-0427-4c59-a788-de977a3e98b7','十二月入城因步城東','韓淲','宋','宋诗','song-poetry','','[]','霧暖南溪路，日斜東郭門。',48,'全唐诗/poet.song.176000.json','["霧暖南溪路，日斜東郭門。", "老身愁近俗，閑步喜前村。", "訪舊尋詩話，同來取酒尊。", "幾多山樹外，梅動影黄昏。"]'),
('f07ef308-f39b-4484-9e01-fa8916e62e31','二十日雪中入城','韓淲','宋','宋诗','song-poetry','','[]','不須深巷卧，懶學剡溪回。',48,'全唐诗/poet.song.176000.json','["不須深巷卧，懶學剡溪回。", "破轎身閑出，衡門手亟開。", "山林遽如許，人物豈他哉。", "橋過城東宅，朋從三兩來。"]'),
('a7cd615a-c3eb-48c9-a547-b738438506d9','一曲','韓淲','宋','宋诗','song-poetry','','[]','一曲寒城外，青山四五家。',48,'全唐诗/poet.song.176000.json','["一曲寒城外，青山四五家。", "庭空鳴敗葉，樓迥起清笳。", "市遠興逾逸，人來話亦佳。", "夜深殘月澹，還有未棲鴉。"]'),
('cd8831d3-b7bf-412e-b174-9b4040842217','靈溪道中','韓淲','宋','宋诗','song-poetry','','[]','但覺村深好，青山分外多。',48,'全唐诗/poet.song.176000.json','["但覺村深好，青山分外多。", "連延俄聳拔，回復又坡陀。", "風冷平沙鴈，天空上水鵝。", "晚時見魚艇，吾欲借其簑。"]'),
('d489e8e8-fa6c-4bf7-9eeb-74ef97f2e6bc','靈鷲道中','韓淲','宋','宋诗','song-poetry','','[]','歷歷山川舊，輿籃我爲遲。',48,'全唐诗/poet.song.176000.json','["歷歷山川舊，輿籃我爲遲。", "偶同三友去，又作一篇詩。", "懷德樟丘遠，閶門玉片思。", "僧窗欹夢枕，休問夜何其。"]'),
('3e758a27-1213-4929-a80e-3118223d4a0f','過吳淞','韓淲','宋','宋诗','song-poetry','','[]','敢有懷君意，人生任所從。',48,'全唐诗/poet.song.176000.json','["敢有懷君意，人生任所從。", "千山纔越楚，一水又吳淞。", "白髮居頭亂，青春入眼濃。", "乾坤隨處好，詩酒自能供。"]'),
('192fb472-99d0-44d2-999c-569f2cfff581','震澤','韓淲','宋','宋诗','song-poetry','','[]','春風吹震澤，欲雪未多晴。',48,'全唐诗/poet.song.176000.json','["春風吹震澤，欲雪未多晴。", "轉柁何忙去，停篙且緩行。", "柳摇田漠漠，草軟岸平平。", "四十年前夢，心驚熱眼生。"]'),
('fb767679-dd77-42ca-9387-fce6ec1c8d7c','秋閑因小舟上南豅  其一','韓淲','宋','宋诗','song-poetry','','[]','老自轉便靜，閑誰不奈貧。',48,'全唐诗/poet.song.176000.json','["老自轉便靜，閑誰不奈貧。", "山林無長物，天地有忙人。", "玉水時時急，靈山日日新。", "涼風吹四壁，吾憶坐忘真。"]'),
('7b9d53b4-ae0c-4797-8b5c-a1f63479b358','秋閑因小舟上南豅  其二','韓淲','宋','宋诗','song-poetry','','[]','野意不堪老，秋懷無用悲。',48,'全唐诗/poet.song.176000.json','["野意不堪老，秋懷無用悲。", "更容書作祟，猶藉酒能醫。", "去去孤雲片，垂垂小雨絲。", "人生偶然爾，天地也如斯。"]'),
('7a98d5e7-6b70-4a91-8b27-ff2a389f9ab8','秋閑因小舟上南豅  其三','韓淲','宋','宋诗','song-poetry','','[]','暑退涼生處，新秋月滿軒。',48,'全唐诗/poet.song.176000.json','["暑退涼生處，新秋月滿軒。", "僧坊從解夏，符籙競中元。", "桂菊花將動，禾苗穟正繁。", "世間多俗節，投老且清言。"]'),
('90a855b1-1901-436c-b8fe-164dd200e868','秋閑因小舟上南豅  其四','韓淲','宋','宋诗','song-poetry','','[]','澗谷慙真隠，溪山欲浪遊。',48,'全唐诗/poet.song.176000.json','["澗谷慙真隠，溪山欲浪遊。", "流長宜逸槳，灘淺可移舟。", "秋淨雲初薄，時豐雨未休。", "短篷吾自喜，知識有浮鷗。"]'),
('7de3105d-96dc-42ad-a270-facbd6d831f9','除夕前一日溪岸晚步  其一','韓淲','宋','宋诗','song-poetry','','[]','春動高溪水，交遊獨有君。',48,'全唐诗/poet.song.176000.json','["春動高溪水，交遊獨有君。", "人情雖澹澹，物色已欣欣。", "香轉梅梢日，光分嶺外雲。", "林亭同眺久，竟把一杯醺。"]'),
('aff59a42-ffe3-40ef-9a69-5bbd2e4804fe','除夕前一日溪岸晚步  其二','韓淲','宋','宋诗','song-poetry','','[]','午步溪邊路，誰家小築幽。',48,'全唐诗/poet.song.176000.json','["午步溪邊路，誰家小築幽。", "敲門問亭榭，迎我具觥籌。", "意適春光動，晴曛野色浮。", "一株梅更好，香艷發梢頭。"]'),
('432700f6-0a2e-40f2-81cb-147d556950ed','除夕前一日溪岸晚步  其三','韓淲','宋','宋诗','song-poetry','','[]','小醉歸來處，陶然度夕陽。',48,'全唐诗/poet.song.176000.json','["小醉歸來處，陶然度夕陽。", "一溪波汎汎，半嶺樹蒼蒼。", "歲晚身何用，春新意欲狂。", "只宜同判斷，柳外百花光。"]'),
('c782ba4d-fde7-49bc-9b6d-4782c4bbef4b','雪晴南圃放步','韓淲','宋','宋诗','song-poetry','','[]','臘閏春爲早，梅花處處多。',48,'全唐诗/poet.song.176000.json','["臘閏春爲早，梅花處處多。", "不知千樹暗，無奈一枝何。", "雪後風初峭，霜前日已和。", "老人山澗曲，不飲亦婆娑。"]'),
('30e8e2d3-bb01-41d0-927a-f35092935015','過野趣','韓淲','宋','宋诗','song-poetry','','[]','春澗涓涓水，山雲放晚晴。',48,'全唐诗/poet.song.176000.json','["春澗涓涓水，山雲放晚晴。", "捧身推戶出，夷步過橋行。", "細草梅英嫩，崇桃柳線輕。", "人忻得芳事，禽鳥亦飛鳴。"]'),
('9bffe924-9951-48b3-af17-7716df9951bd','晚步溪山堂下','韓淲','宋','宋诗','song-poetry','','[]','曉園經雨潤，飲罷過溪邊。',48,'全唐诗/poet.song.176000.json','["曉園經雨潤，飲罷過溪邊。", "燈火三家市，檣竿獨客船。", "傍崖支徑去，設席得茶煎。", "寄語同來者，茲游亦自便。"]'),
('9f5a82c6-ea68-4ca8-ae9d-04c70705a8f1','香積寺閑步','韓淲','宋','宋诗','song-poetry','','[]','瀹茗幽窗下，圍棋小檻旁。',48,'全唐诗/poet.song.176000.json','["瀹茗幽窗下，圍棋小檻旁。", "同來一尋勝，散坐共追涼。", "水竹元深茂，巖花已再香。", "長安塵土裏，城外喜行藏。"]'),
('6cdfcc68-86b0-4009-949c-12b31288ff32','十三日自趙十家同諸友步至浮梁','韓淲','宋','宋诗','song-poetry','','[]','淥淨偏浮月，清虛正得秋。',48,'全唐诗/poet.song.176000.json','["淥淨偏浮月，清虛正得秋。", "半酣元有興，投老却無愁。", "露氣遠猶見，煙光冷不收。", "孤城對蕭寺，新鴈便滄洲。"]'),
('9614c384-11ea-40cf-b26b-6051366f86e3','同黄靖州閑步','韓淲','宋','宋诗','song-poetry','','[]','秋淨晴原日，因行過屋東。',48,'全唐诗/poet.song.176000.json','["秋淨晴原日，因行過屋東。", "歸來三載後，猶得五人同。", "問訊荒園外，周遊並舍中。", "留連一盃酒，還我舊家風。"]'),
('12026db5-cca5-45c0-9163-4d20e12932d3','夜同處晦霞山','韓淲','宋','宋诗','song-poetry','','[]','燈影山窗淡，盃寒道院深。',48,'全唐诗/poet.song.176000.json','["燈影山窗淡，盃寒道院深。", "世塵心力弱，時俗鬢毛侵。", "煙莽開幽逕，霜枝墮遠林。", "地偏愁獨往，鄰近喜相尋。"]'),
('9b6638e3-3997-484e-92e7-43ac096b0b94','晚過靈室','韓淲','宋','宋诗','song-poetry','','[]','溪淺寒光合，山橫夜氣深。',48,'全唐诗/poet.song.176000.json','["溪淺寒光合，山橫夜氣深。", "擁爐詩觸撥，舉白醉侵尋。", "話久銷塵慮，情忘見道心。", "斷霞明別渚，霏霧鎖遥岑。"]'),
('c5691a1a-9904-426d-ab7b-b81ab6c3e3f5','報昌甫青巖之遊','韓淲','宋','宋诗','song-poetry','','[]','秋到青巖寺，山深眼爲新。',48,'全唐诗/poet.song.176000.json','["秋到青巖寺，山深眼爲新。", "尋思曾宿客，笑我再來人。", "欲住苦違俗，便歸愁染塵。", "爭如兩峰底，苔竹養吾真。"]'),
('bdde9661-7e92-47a1-ac6f-97dbdc049fe8','黄仲明同看池上菊一酌因出溪橋久之','韓淲','宋','宋诗','song-poetry','','[]','飲菊明山日，行林挾岸風。',48,'全唐诗/poet.song.176000.json','["飲菊明山日，行林挾岸風。", "近霜雖落木，得雨自成叢。", "小醉情懷外，微吟步武中。", "幽閑有如我，邂逅復心同。"]'),
('03a07db9-b0e1-491d-b32d-7cf6adbf9618','兩倅約過南臺','韓淲','宋','宋诗','song-poetry','','[]','別乘偷閒裏，南臺避暑初。',48,'全唐诗/poet.song.176000.json','["別乘偷閒裏，南臺避暑初。", "招邀到班邴，宦達付嚴徐。", "賢相規尤遠，靈山畫不如。", "荆淮多戰鼓，煮餠少躊躇。"]'),
('b2db5c2b-4fd3-4f28-a351-0f18ddeebcfc','聞昌甫斯遠成季下瓦窯灘又與伯皋回塗小集成季書院','韓淲','宋','宋诗','song-poetry','','[]','八月南豅夜，遥知聚德星。',48,'全唐诗/poet.song.176000.json','["八月南豅夜，遥知聚德星。", "航溪不用楫，解榻卧長瓶。", "上下知何往，違離憶屢經。", "前簷撲山翠，梅葉映窗櫺。"]'),
('5b7ce651-d395-4d6f-9ad7-4665f2ea93c8','六月二日晨起','韓淲','宋','宋诗','song-poetry','','[]','雨足風尤潤，嵐深日未開。',48,'全唐诗/poet.song.176000.json','["雨足風尤潤，嵐深日未開。", "一山涼有樹，四壁淨無埃。", "雞唱遠仍密，鳥飛低復回。", "寧憂身已老，尚喜客能來。"]'),
('bcfc1d2f-8605-4941-9025-9d2c0f63e944','曉起','韓淲','宋','宋诗','song-poetry','','[]','曉起百無營，山空一澗清。',48,'全唐诗/poet.song.176000.json','["曉起百無營，山空一澗清。", "林霜知爽甚，簷日覺寒輕。", "靜整遺編讀，閑循古道行。", "囂塵不到眼，禽鳥亦忘情。"]'),
('43944344-bc32-4219-8106-af4d0e24e6dd','聽琴','韓淲','宋','宋诗','song-poetry','','[]','以彼發此意，因此知彼聲。',48,'全唐诗/poet.song.176000.json','["以彼發此意，因此知彼聲。", "山川既閑遠，天地亦清寧。", "獨撫曲空奏，相宣調易成。", "何由俗子愛，宜是老夫驚。"]'),
('06f88e67-0e23-46de-a4c0-9cc03aa06749','靈芝寺清坐聽潘德久弄琴久之小酌而散','韓淲','宋','宋诗','song-poetry','','[]','秋晚靈芝寺，陰雲闔復開。',48,'全唐诗/poet.song.176000.json','["秋晚靈芝寺，陰雲闔復開。", "荷枯半倚草，柏老徧生苔。", "興到容吾賦，閑知與客來。", "琴邊更三疊，莫放酒船回。"]'),
('91db4343-4b21-4e9c-b3b2-9c46d5b83097','晝困','韓淲','宋','宋诗','song-poetry','','[]','困來四壁雨，睡覺一窗晴。',48,'全唐诗/poet.song.176000.json','["困來四壁雨，睡覺一窗晴。", "頃刻寒猶煖，移時暗復明。", "揚揚柳絮起，矗矗竹萌生。", "芳檻鳥啼濕，小池魚隊平。"]'),
('7d8697d4-d6a9-4fce-86ab-66771ea7e934','南窗日午困坐','韓淲','宋','宋诗','song-poetry','','[]','困頓南窗日，衰頹畏隙風。',48,'全唐诗/poet.song.176000.json','["困頓南窗日，衰頹畏隙風。", "酒因寒得策，茶與睡書功。", "不比馮唐老，渾如阮籍窮。", "驚心還嗣歲，隨意過殘冬。"]'),
('fb3dbbdc-dcf4-4e8d-ba42-bbf4b490c89c','雪中圍棋','韓淲','宋','宋诗','song-poetry','','[]','樓外千山雪，年年只欠詩。',48,'全唐诗/poet.song.176000.json','["樓外千山雪，年年只欠詩。", "盃停常欲速，棋負不容遲。", "玉振光回合，冰清氣眇彌。", "咸言聊自惜，世路易磷緇。"]'),
('afaa6e20-b9e7-43d5-93e8-99c512b4a0c2','夜坐','韓淲','宋','宋诗','song-poetry','','[]','冷夜灰堆坐，尋詩細撥燈。',48,'全唐诗/poet.song.176000.json','["冷夜灰堆坐，尋詩細撥燈。", "心懷爲宛轉，語句得憑凌。", "歲晚愁多飲，冬來煖未冰。", "俄聽荒犬吠，村靜遠相仍。"]'),
('1f796d7b-a238-41e3-9be6-766e45d94a47','鄰家夜坐','韓淲','宋','宋诗','song-poetry','','[]','燈影摇初夜，寒聲落近山。',48,'全唐诗/poet.song.176000.json','["燈影摇初夜，寒聲落近山。", "酒隨人意淺，詩寫我身閒。", "莫忿流年速，空搔短髮斑。", "然而醒復醉，蓋謂往仍還。"]'),
('c7ca3be4-7158-46ba-a6f6-c9f9806e5748','好仁齋夜雨與子似對牀','韓淲','宋','宋诗','song-poetry','','[]','湖上歸來晚，空齋夜雨聲。',48,'全唐诗/poet.song.176000.json','["湖上歸來晚，空齋夜雨聲。", "對牀驚昨夢，隠几話平生。", "燈淨書還讀，香銷句忽成。", "他年相望處，吾亦用吾情。"]'),
('9564be1f-0cd7-4aa0-8eb0-202dde117946','杰上人房午睡','韓淲','宋','宋诗','song-poetry','','[]','喧卑無睡處，猶得到僧牀。',48,'全唐诗/poet.song.176000.json','["喧卑無睡處，猶得到僧牀。", "凉潤新蒲雨，清熏老柏香。", "不嫌茶作祟，何待醉爲鄉。", "事事俱離眼，其功接混茫。"]'),
('66115931-a62a-4161-921a-06e2c6578675','次公招飲余子壽同坐','韓淲','宋','宋诗','song-poetry','','[]','老覺過從少，斯文恐不然。',48,'全唐诗/poet.song.176000.json','["老覺過從少，斯文恐不然。", "參天兩玉樹，忽墮一杯前。", "意象心非石，談鋒思湧泉。", "冰霜凍梅蘂，滿眼是新年。"]'),
('7f150be6-c96c-4ddb-9387-a4b58ecdcbbc','縱酒','韓淲','宋','宋诗','song-poetry','','[]','縱酒非能飲，長言未是詩。',48,'全唐诗/poet.song.176000.json','["縱酒非能飲，長言未是詩。", "年華除夜逼，心事故人爲。", "君欲醉須醉，我還歸便歸。", "南豅到南澗，官柳野梅知。"]'),
('6df10844-1051-4eaa-a314-57e86667fef0','示病','韓淲','宋','宋诗','song-poetry','','[]','示病原非病，愛閑方始閑。',48,'全唐诗/poet.song.176000.json','["示病原非病，愛閑方始閑。", "水邊寧欠水，山外更多山。", "我豈要人拙，人應嫌我頑。", "臘窮春又立，梅雪共斑斑。"]'),
('35ccbd2a-ff3e-4c3e-a34a-290baf8a45e9','感風發汗卧病數日推枕翛然敘事爲十詩  其一','韓淲','宋','宋诗','song-poetry','','[]','病起窗前坐，哦詩一解顔。',48,'全唐诗/poet.song.176000.json','["病起窗前坐，哦詩一解顔。", "人生祇恁麽，世事未如閑。", "朝路誰知舊，田廬自往還。", "從今無別計，風月老溪山。"]'),
('76f0a31c-253a-4a3e-a7a8-978361574300','感風發汗卧病數日推枕翛然敘事爲十詩  其二','韓淲','宋','宋诗','song-poetry','','[]','病起香初炷，蓬蓬噴玉煙。',48,'全唐诗/poet.song.176000.json','["病起香初炷，蓬蓬噴玉煙。", "絲頭方過眼，穗脚忽成拳。", "垢盡心無染，塵銷意欲仙。", "吾生太癡絕，臭味乃如然。"]'),
('9bf32140-5ce1-4da8-a948-faa256ac0d63','感風發汗卧病數日推枕翛然敘事爲十詩  其三','韓淲','宋','宋诗','song-poetry','','[]','病起思新茗，催煎蠏眼湯。',48,'全唐诗/poet.song.176000.json','["病起思新茗，催煎蠏眼湯。", "分來香細膩，啜處味偏長。", "日永門庭靜，風輕院宇涼。", "更尋雙井試，甌面乳如霜。"]'),
('0dc0f7e1-2a02-41d3-b2e9-f0d4a0f3a9cc','感風發汗卧病數日推枕翛然敘事爲十詩  其四','韓淲','宋','宋诗','song-poetry','','[]','病起支頤久，形神稍稍安。',48,'全唐诗/poet.song.176000.json','["病起支頤久，形神稍稍安。", "豈堪誇壯健，只怕已衰殘。", "希聖心無倦，求官意漸闌。", "不爲君子棄，何恨對瓢簞。"]'),
('a8f965af-1e35-42ba-b348-878ddef32838','感風發汗卧病數日推枕翛然敘事爲十詩  其五','韓淲','宋','宋诗','song-poetry','','[]','病起水邊行，風回柳弄晴。',48,'全唐诗/poet.song.176000.json','["病起水邊行，風回柳弄晴。", "岸虛微坼土，澗淺細無聲。", "寂寂心逾靜，飄飄神轉清。", "衣襟带波影，搔首又詩成。"]'),
('f71cf752-e589-4e4d-bd86-a4b054e62903','感風發汗卧病數日推枕翛然敘事爲十詩  其六','韓淲','宋','宋诗','song-poetry','','[]','病起呼童語，門前客不來。',48,'全唐诗/poet.song.176000.json','["病起呼童語，門前客不來。", "無人理花草，爲我掃莓苔。", "只欲尋書帙，何心泥酒杯。", "樹陰橫澗水，鷗下莫相猜。"]'),
('5c147c41-d24b-429a-91ec-d657bf03b61a','感風發汗卧病數日推枕翛然敘事爲十詩  其七','韓淲','宋','宋诗','song-poetry','','[]','病起尋藜杖，閑情孰可論。',48,'全唐诗/poet.song.176000.json','["病起尋藜杖，閑情孰可論。", "騰身上危徑，著眼已高軒。", "城堞看州宅，沙汀識遠村。", "幸無衰老相，逸興且丘園。"]'),
('8e8b12d4-04d7-415a-a9f2-590931126ede','感風發汗卧病數日推枕翛然敘事爲十詩  其八','韓淲','宋','宋诗','song-poetry','','[]','病起加餐飯，隨宜且菜蔬。',48,'全唐诗/poet.song.176000.json','["病起加餐飯，隨宜且菜蔬。", "何須尊有酒，豈歎食無魚。", "絕不關人事，多慙得自如。", "從他志溫飽，我愧腹空虛。"]'),
('4e23ef1d-1f3b-457b-a3de-59d8bb4a106c','感風發汗卧病數日推枕翛然敘事爲十詩  其九','韓淲','宋','宋诗','song-poetry','','[]','病起看兒戲，階庭閙不休。',48,'全唐诗/poet.song.176000.json','["病起看兒戲，階庭閙不休。", "覓錢何所用，得果更無求。", "轉覺童心好，翻令老態羞。", "年光正如電，愁入鬢邊秋。"]'),
('f41da5b6-fe45-46c5-ad2c-71855afe1f42','感風發汗卧病數日推枕翛然敘事爲十詩  其一○','韓淲','宋','宋诗','song-poetry','','[]','病起何思慮，空齋讀易時。',48,'全唐诗/poet.song.176000.json','["病起何思慮，空齋讀易時。", "沉潛三畫象，研究六爻詞。", "孔繫誠難識，揚玄恐易知。", "乾乾且修業，學處在觀頤。"]'),
('7a9796b6-71fb-41e4-9742-7f768290bf2b','中歲','韓淲','宋','宋诗','song-poetry','','[]','中歲百事懶，頗覺山林深。',48,'全唐诗/poet.song.176000.json','["中歲百事懶，頗覺山林深。", "體適解巾屨，情安弄書琴。", "流年度寒暑，盡日看晴陰。", "窮達苟不委，何以全素襟。"]'),
('06c1adcb-4288-4688-86fe-55863f81611e','白髭一莖欣然爲賦','韓淲','宋','宋诗','song-poetry','','[]','髮已經年白，今朝又到鬚。',48,'全唐诗/poet.song.176000.json','["髮已經年白，今朝又到鬚。", "形容真易改，心事合全無。", "曉室開青鏡，晴窗據槁梧。", "門前誰送酒，不恨老東吳。"]'),
('4f069432-4f64-484e-a707-f2b02c3b27c3','燈火','韓淲','宋','宋诗','song-poetry','','[]','燈火水邊城，閭閻月始明。',48,'全唐诗/poet.song.176000.json','["燈火水邊城，閭閻月始明。", "舊年行樂事，新歲合歡聲。", "雪後猶含凍，風前未喜晴。", "崇朝雨如瀉，溝澮又皆盈。"]'),
('d288c7b5-8d6f-4857-942b-d10852d8b259','寒燈','韓淲','宋','宋诗','song-poetry','','[]','撥剔寒燈燄，消停煖酒杯。',48,'全唐诗/poet.song.176000.json','["撥剔寒燈燄，消停煖酒杯。", "醉從愁畔過，夢自覺中迴。", "幽興故爲熟，衰顔底用催。", "小園荒草外，山意數枝梅。"]'),
('184de230-7912-4ad5-b35f-d3d2381f0d2e','短吟','韓淲','宋','宋诗','song-poetry','','[]','高看復下看，長吟時短吟。',48,'全唐诗/poet.song.176000.json','["高看復下看，長吟時短吟。", "人寧常適意，世或盡知音。", "靈運穿高屐，淵明理素琴。", "海隅風渺渺，山窟雪森森。"]'),
('b1769b25-1783-4c9b-9fbc-3c6abf73366d','即事','韓淲','宋','宋诗','song-poetry','','[]','蒲葉亂陰雨，藤花開煖風。',48,'全唐诗/poet.song.176000.json','["蒲葉亂陰雨，藤花開煖風。", "澗流欹岸遠，山逼小亭空。", "躍黽疎叢外，啼鶑密樹中。", "望隨橋上下，行過屋西東。"]'),
('7e5eba31-010c-469c-9913-14e8ada98b5e','春情','韓淲','宋','宋诗','song-poetry','','[]','結綺尋芳去，春光處處多。',48,'全唐诗/poet.song.176000.json','["結綺尋芳去，春光處處多。", "鶑花遲日麗，燕麥惠風和。", "翠滴烟林石，紅摇晴浪波。", "餘情約重醉，歸路聽行歌。"]'),
('c721ab13-dfec-4d9a-9f30-6969be6b5659','偶懷','韓淲','宋','宋诗','song-poetry','','[]','已過中秋月，木犀猶少開。',48,'全唐诗/poet.song.176000.json','["已過中秋月，木犀猶少開。", "固嘗同客飲，終是欠朋來。", "烈士志何在，幽人喚不回。", "淒風亂紅葉，零雨濕荒苔。"]'),
('39c0d16f-57f2-48a6-a80c-3ed439d3383f','偶成  其一','韓淲','宋','宋诗','song-poetry','','[]','酒亦逢人飲，詩須任我吟。',48,'全唐诗/poet.song.176000.json','["酒亦逢人飲，詩須任我吟。", "短長徒有興，醒醉蓋無心。", "爛漫歡中趣，幽微得處尋。", "佳時思共賞，良夜忍孤斟。"]'),
('da912f1a-25ad-4357-8c8b-8a16cb7ba5e9','偶成  其二','韓淲','宋','宋诗','song-poetry','','[]','惜氣思仙伎，因心理佛書。',48,'全唐诗/poet.song.176000.json','["惜氣思仙伎，因心理佛書。", "心安何所覺，氣積本乘虛。", "造化融成後，神明主宰初。", "縱疑摩詰贅，未信洞賓疎。"]'),
('a4cf4332-4c8c-464d-b185-68c361632447','偶成  其三','韓淲','宋','宋诗','song-poetry','','[]','出處升沉地，中年付短歌。',48,'全唐诗/poet.song.176000.json','["出處升沉地，中年付短歌。", "世情時轉變，人事日銷磨。", "盪寇聲雖在，平戎意尚多。", "山空流水急，啼鳥下烟蘿。"]'),
('b4316406-8bee-46a6-bfcc-780d38b8cd43','偶興','韓淲','宋','宋诗','song-poetry','','[]','老喜交親熟，貧嫌故舊真。',48,'全唐诗/poet.song.176000.json','["老喜交親熟，貧嫌故舊真。", "山林無長物，天地有垂綸。", "胡蝶身中葉，銅駝世上塵。", "江南要梅雨，耕稼一番新。"]'),
('8d1fd0c3-1c7f-4f67-84c0-d68d7a3408d7','轉覺','韓淲','宋','宋诗','song-poetry','','[]','轉覺親知少，旁觀事緒多。',48,'全唐诗/poet.song.176000.json','["轉覺親知少，旁觀事緒多。", "百年從汩沒，一句待吟哦。", "小雨催新桂，連陰養晚禾。", "山深秋澗水，清溜亦盤渦。"]'),
('5e90c215-7753-420a-a096-d2ad332fa8d1','隱遯禪參','韓淲','宋','宋诗','song-poetry','','[]','索隠安肥遯，安禪豈飽參。',48,'全唐诗/poet.song.176000.json','["索隠安肥遯，安禪豈飽參。", "有緣皆可到，無悶悉能甘。", "野飯耕而美，村酤醉以酣。", "因思前後際，不與話三三。"]'),
('b9e2d75b-5ec8-4e38-9e6a-ced68204ca7d','三月下旬藥局書滿','韓淲','宋','宋诗','song-poetry','','[]','賣藥居吳市，人猶識姓名。',48,'全唐诗/poet.song.176000.json','["賣藥居吳市，人猶識姓名。", "自驚無遯志，誰信有浮榮。", "野迥林須密，泉深水更清。", "春帆送歸棹，天地一身輕。"]'),
('e9b54355-2d6f-42a5-b01b-2f13fa3abf61','初五日聞遣戍','韓淲','宋','宋诗','song-poetry','','[]','摇落秋風急，蕭條易水寒。',48,'全唐诗/poet.song.177000.json','["摇落秋風急，蕭條易水寒。", "悲歌誰激烈，宵雅自平寬。", "本道尊中國，何庸伐可汗。", "山居聞備塞，莫厭腐儒餐。"]'),
('59fd65fd-4eab-46ae-8e59-03541a77f516','游宦','韓淲','宋','宋诗','song-poetry','','[]','遊宦家何似，兒啼婢僕寒。',48,'全唐诗/poet.song.177000.json','["遊宦家何似，兒啼婢僕寒。", "敝衣無服飾，薄飯少杯盤。", "原憲貧非病，龐公遺以安。", "江山冬自好，梅已發林端。"]'),
('e263de2e-cd30-4d8d-a3f2-69891776bc8d','歛膝','韓淲','宋','宋诗','song-poetry','','[]','歛膝貪窗日，抽身避隙風。',48,'全唐诗/poet.song.177000.json','["歛膝貪窗日，抽身避隙風。", "深藏破屋底，困處小樓中。", "舊雪積猶在，新霜凍未空。", "壺漿無剩綠，爐炭尚微紅。"]'),
('9ab90385-324b-4799-ad15-9b246a167e42','書懷','韓淲','宋','宋诗','song-poetry','','[]','古來憎命達，今亦歎才難。',48,'全唐诗/poet.song.177000.json','["古來憎命達，今亦歎才難。", "我自厭時暑，人誰耐歲寒。", "升沉空早計，中外試徐看。", "莫爲多窮困，而懷常晏安。"]'),
('2c574d60-d935-4f95-b065-541b5275e2e7','有懷  其一','韓淲','宋','宋诗','song-poetry','','[]','晏齋風雨夜，門掩是深山。',48,'全唐诗/poet.song.177000.json','["晏齋風雨夜，門掩是深山。", "絕俗詩編淨，懷人書尺閑。", "兒孫今滿眼，鷄犬久怡顔。", "萬籟定俱寂，高標不可攀。"]'),
('67577e5c-663e-43fe-8f11-a830d4ef0020','有懷  其二','韓淲','宋','宋诗','song-poetry','','[]','獨行風雨夜，家事復身謀。',48,'全唐诗/poet.song.177000.json','["獨行風雨夜，家事復身謀。", "推枕茅簷起，停驂麥隴收。", "親情離聚矣，故舊往還不。", "撫著時文笑，榮塗遍九州。"]'),
('73b122d4-527b-412a-a050-21df2f115b7e','有懷  其三','韓淲','宋','宋诗','song-poetry','','[]','山臺風雨夜，一點是青燈。',48,'全唐诗/poet.song.177000.json','["山臺風雨夜，一點是青燈。", "獨把麟經究，誰知驥志憑。", "隔溪常過客，近寺不聞僧。", "梅夏清清裏，翻愁易鬰蒸。"]'),
('8ad29cb2-b010-4a67-bd2d-e5719f262175','有懷  其四','韓淲','宋','宋诗','song-poetry','','[]','山庵風雨夜，莫惜細論文。',48,'全唐诗/poet.song.177000.json','["山庵風雨夜，莫惜細論文。", "友直惟家學，僧清豈世氛。", "隨宜粥飯好，奚止搢紳云。", "磬歇香燈上，詞場自策勳。"]'),
('9cb9cbb1-205c-4c79-9ca9-c5e9fcd7ee90','有懷  其五','韓淲','宋','宋诗','song-poetry','','[]','山居風雨夜，吾亦老侵尋。',48,'全唐诗/poet.song.177000.json','["山居風雨夜，吾亦老侵尋。", "搔屑蕭蕭髮，收平耿耿心。", "更初殊不寐，人靜尚孤斟。", "盡屏閑書帙，猶餘一破琴。"]'),
('29356550-fdee-4110-8bdb-11e4b53062e8','有懷  其六','韓淲','宋','宋诗','song-poetry','','[]','泠齋風雨夜，兄弟笑言溫。',48,'全唐诗/poet.song.177000.json','["泠齋風雨夜，兄弟笑言溫。", "燈火萊衣戲，文書馬帳尊。", "更聲傳杳杳，簷溜落紛紛。", "茶果團欒坐，都無官舍喧。"]'),
('72290fa4-e33a-442d-90bf-ffca593a56a2','宋監倉挽詞','韓淲','宋','宋诗','song-poetry','','[]','祖禰碑銘在，階庭經術長。',48,'全唐诗/poet.song.177000.json','["祖禰碑銘在，階庭經術長。", "宦塗欽撫字，祠館歎行藏。", "北客多先契，中原隔故鄉。", "交遊真破夢，哀挽不成章。"]'),
('0b52f714-7b45-4dcf-9913-9d4e69dc12c3','太尉武泰節度壽昌侯挽詞  其一','韓淲','宋','宋诗','song-poetry','','[]','漢數當時盛，唐知餘慶家。',48,'全唐诗/poet.song.177000.json','["漢數當時盛，唐知餘慶家。", "至今猶相衮，從昔建高牙。", "陰鄧何勞擬，崔盧亦漫誇。", "南來方再世，閥閲本京華。"]'),
('edbca0ed-10f2-4051-a68f-91982eb0b432','太尉武泰節度壽昌侯挽詞  其二','韓淲','宋','宋诗','song-poetry','','[]','乾道風雲際，公持繡斧初。',48,'全唐诗/poet.song.177000.json','["乾道風雲際，公持繡斧初。", "既爲澄獄戶，常憶使穹廬。", "主聖元無隠，官邪可痛鋤。", "閩山江浙水，屈指事堪書。"]'),
('10964375-1bff-4140-99e8-e4246c2f9244','太尉武泰節度壽昌侯挽詞  其三','韓淲','宋','宋诗','song-poetry','','[]','晚節齋壇拜，勳名已四朝。',48,'全唐诗/poet.song.177000.json','["晚節齋壇拜，勳名已四朝。", "開邊屢銅虎，告弟僅金貂。", "壯志自難已，英魂孰得招。", "中原諸老盡，江海聽吹簫。"]'),
('4d54f3a8-5760-4736-a193-7ded60c5e9b9','江西趙漕送丞相行狀索挽詩  其一','韓淲','宋','宋诗','song-poetry','','[]','歎息經邦志，恢洪發大魁。',48,'全唐诗/poet.song.177000.json','["歎息經邦志，恢洪發大魁。", "兩宮傳眷賞，諸老競招徠。", "雨露銓衡際，風雲史館開。", "宗英圖一相，盛事却生哀。"]'),
('23ed3555-80e7-46db-8f41-6a84c2b0af45','江西趙漕送丞相行狀索挽詩  其二','韓淲','宋','宋诗','song-poetry','','[]','全蜀欽隆委，閩山兩帥華。',48,'全唐诗/poet.song.177000.json','["全蜀欽隆委，閩山兩帥華。", "中權收節制，入告罄忠嘉。", "宣輦猶持柄，垂簾竟報麻。", "奮身扶日手，國爾信忘家。"]'),
('461f2717-451a-496c-b187-948dcbc638fb','江西趙漕送丞相行狀索挽詩  其三','韓淲','宋','宋诗','song-poetry','','[]','任道崇儒素，虛謙不近名。',48,'全唐诗/poet.song.177000.json','["任道崇儒素，虛謙不近名。", "門庭規以睦，塗路畏夫清。", "世固推源委，人今孰統盟。", "皇明酬卹典，四表亦歡聲。"]'),
('1b08ee9d-264a-4c7c-acd8-4a1e5fa2cd98','李信州挽詩  其一','韓淲','宋','宋诗','song-poetry','','[]','一自南臺酒，公今成古人。',48,'全唐诗/poet.song.177000.json','["一自南臺酒，公今成古人。", "方期千載事，豈料百年身。", "從俗心良苦，安時志欲伸。", "稽山歸旐颭，我淚亦沾巾。"]'),
('d79dd78a-96d0-4742-bb53-4c9b6aef95c4','李信州挽詩  其二','韓淲','宋','宋诗','song-poetry','','[]','家世既如此，爲邦可謂賢。',48,'全唐诗/poet.song.177000.json','["家世既如此，爲邦可謂賢。", "廉名前後少，儉德始終全。", "時喜政平矣，吏嫌民晏然。", "下車雖未久，遺愛玉溪邊。"]'),
('e50fc45b-d754-49bb-a55d-08f408031175','吳雷州挽詩  其一','韓淲','宋','宋诗','song-poetry','','[]','睦信推潛德，饒封代有成。',48,'全唐诗/poet.song.177000.json','["睦信推潛德，饒封代有成。", "海康開郡紱，淮甸入廷評。", "進劄誠良遇，蠲輸惜重征。", "誠齋廉茂薦，尤足動簪纓。"]'),
('25371314-9180-4ac0-a10f-b59bfa75828d','吳雷州挽詩  其二','韓淲','宋','宋诗','song-poetry','','[]','冰壺時泛玉，水宿更雲莊。',48,'全唐诗/poet.song.177000.json','["冰壺時泛玉，水宿更雲莊。", "捐館嗟何憾，移庵得所藏。", "開田期族衆，濬港見流長。", "普濟名陂意，南中保衛方。"]'),
('5c4bf2be-e3d3-4306-8d86-cd715b65fb99','耿和州挽詩  其一','韓淲','宋','宋诗','song-poetry','','[]','歎息餘光舊，吾翁識此公。',48,'全唐诗/poet.song.177000.json','["歎息餘光舊，吾翁識此公。", "後來持帥閫，勇退有高風。", "示疾带湖上，真祠崇道中。", "傷心華山路，松柏窆幽宮。"]'),
('b5b7b075-da24-40b6-8e82-efafe1678379','耿和州挽詩  其二','韓淲','宋','宋诗','song-poetry','','[]','右學騰高第，掄才閤策尊。',48,'全唐诗/poet.song.177000.json','["右學騰高第，掄才閤策尊。", "一心依日月，無力正乾坤。", "插带環宮陛，蕃宣復塞垣。", "遺芳餘慶在，猶記笑言溫。"]'),
('e843ccd7-43a9-44ef-a96c-1327473778b2','何信州挽詩  其一','韓淲','宋','宋诗','song-poetry','','[]','憶昔絃歌盛，臨歸送以詩。',48,'全唐诗/poet.song.177000.json','["憶昔絃歌盛，臨歸送以詩。", "恰如前日事，又作百年悲。", "蒼嶺新阡遠，靈溪舊治思。", "悼亡猶未殯，丹旐忍參差。"]'),
('e3418147-063e-4b5b-bd64-fb6a1fdedf59','何信州挽詩  其二','韓淲','宋','宋诗','song-poetry','','[]','家族開王社，婣親滿帝京。',48,'全唐诗/poet.song.177000.json','["家族開王社，婣親滿帝京。", "紫樞推玉友，青瑣本冰清。", "勳業持荷近，才名折桂榮。", "從茲纔得路，胡獨止專城。"]'),
('08a0f909-314f-4d50-953e-a3f9d8b76a47','趙吏部挽詩','韓淲','宋','宋诗','song-poetry','','[]','克保家聲大，脩明國論難。',48,'全唐诗/poet.song.177000.json','["克保家聲大，脩明國論難。", "退閑聊激懦，辭召豈圖安。", "入館纔郎省，高科合世官。", "同門名士筆，留狀後人看。"]'),
('b4576db4-dd14-46f6-939f-b84c9fc7856d','潘太博端叔挽詩','韓淲','宋','宋诗','song-poetry','','[]','歎息詞場舊，凄其三十年。',48,'全唐诗/poet.song.177000.json','["歎息詞場舊，凄其三十年。", "訓言猶在耳，輩行敢隨肩。", "師友真凋落，交親僅接聯。", "何因置芻束，東望只潸然。"]'),
('8890c0d4-8a8b-4f63-be12-d02aba7f2140','竹院晁學士挽詩  其一','韓淲','宋','宋诗','song-poetry','','[]','主客文風在，家仍竹院名。',48,'全唐诗/poet.song.177000.json','["主客文風在，家仍竹院名。", "有孫宜世祿，迺父今公卿。", "事至不如意，人應爲失聲。", "傷哉蒿里去，書劍竟何成。"]'),
('e419c784-6acf-4623-8e3a-d0d89bf37d65','竹院晁學士挽詩  其二','韓淲','宋','宋诗','song-poetry','','[]','歎息通家舊，姻連豈異鄉。',48,'全唐诗/poet.song.177000.json','["歎息通家舊，姻連豈異鄉。", "江南流寓久，濟北老成亡。", "健筆餘牋翰，高歌付酒觴。", "鵝湖玉溪路，無復見徜徉。"]'),
('6706e25d-2267-4d9b-99f0-d9019e0d76ff','挽吳九伯豐縣丞詩  其一','韓淲','宋','宋诗','song-poetry','','[]','往者靈溪路，君嘗過我廬。',48,'全唐诗/poet.song.177000.json','["往者靈溪路，君嘗過我廬。", "相期千載事，竟欠一行書。", "論定終何有，生平合自如。", "九原不可作，宰木夜臺虛。"]'),
('914f89f9-f117-4c28-8b2b-902e2a0b895f','挽吳九伯豐縣丞詩  其二','韓淲','宋','宋诗','song-poetry','','[]','養志年方盛，持身德已明。',48,'全唐诗/poet.song.177000.json','["養志年方盛，持身德已明。", "一官雖未達，百歲豈銷聲。", "師友嗟零落，賓親自送迎。", "翩翩丹旐遠，老泪亦須傾。"]'),
('248900ed-68b6-4a4c-a532-9b208e5ee911','挽江浦縣丞鄭公詩  其一','韓淲','宋','宋诗','song-poetry','','[]','寂寞同州守，衣冠葬玉山。',48,'全唐诗/poet.song.177000.json','["寂寞同州守，衣冠葬玉山。", "國家遭禍變，臣子不生還。", "異域城應在，中原路尚艱。", "有孫纔九品，本擬上朝班。"]'),
('23339783-a40e-4b6c-8c74-73ed4d46fd7c','挽江浦縣丞鄭公詩  其二','韓淲','宋','宋诗','song-poetry','','[]','卹典勸天下，諸公譽更多。',48,'全唐诗/poet.song.177000.json','["卹典勸天下，諸公譽更多。", "傷心立門戶，遺恨滿山阿。", "猶記交情舊，時將詩句哦。", "浮生如意少，薤露忍成歌。"]'),
('47fedbed-f52d-43d8-832e-f425899b1c95','魏知府挽詩  其一','韓淲','宋','宋诗','song-poetry','','[]','先正聲猷在，諸賢競挽推。',48,'全唐诗/poet.song.177000.json','["先正聲猷在，諸賢競挽推。", "蚤年知振厲，中道惜裴回。", "論建何老識，文詞豈小才。", "近來耆舊盡，徒與士生哀。"]'),
('55dcaad8-d1c9-450d-9427-187d0cf26058','魏知府挽詩  其二','韓淲','宋','宋诗','song-poetry','','[]','歷歷親言話，長懷逸老堂。',48,'全唐诗/poet.song.177000.json','["歷歷親言話，長懷逸老堂。", "典刑杯酒外，氣象簡編旁。", "有子真源委，何人更發揚。", "宣風覺庵地，霜露鬰乎蒼。"]'),
('aa4bb27c-71f7-45cb-ae9f-4261c1e61379','都漕陳侍郎挽詩  其一','韓淲','宋','宋诗','song-poetry','','[]','赫赫相門舊，龜峰照玉溪。',48,'全唐诗/poet.song.177000.json','["赫赫相門舊，龜峰照玉溪。", "豈云名宦達，殆欲古人齊。", "文物禁林上，光華使節西。", "黄金橫带處，新築乃幽棲。"]'),
('1ec7cf32-8d02-4dcd-af96-0dce70fdbe0c','都漕陳侍郎挽詩  其二','韓淲','宋','宋诗','song-poetry','','[]','尊酒游行地，凄凉僅隔年。',48,'全唐诗/poet.song.177000.json','["尊酒游行地，凄凉僅隔年。", "傳聞當勿藥，却報卜新阡。", "哀挽嗟無及，忠言孰爲宣。", "彼何兵弗戢，去國記翻然。"]'),
('b68ba1eb-d265-49a5-933f-d1b6643ad935','吳德夫侍郎挽詩  其一','韓淲','宋','宋诗','song-poetry','','[]','葵軒鑪韛大，成鑄幾英才。',48,'全唐诗/poet.song.177000.json','["葵軒鑪韛大，成鑄幾英才。", "絕歎長沙久，常欽蜀道回。", "豸冠千仗聳，鳬舄九關開。", "持漕西江日，深慙過我來。"]'),
('38a8e033-e7ec-49aa-b7a9-bc165b978e9d','吳德夫侍郎挽詩  其二','韓淲','宋','宋诗','song-poetry','','[]','不爲盆盎淺，直欲挽狂瀾。',48,'全唐诗/poet.song.177000.json','["不爲盆盎淺，直欲挽狂瀾。", "下士謙何假，崇師歉未安。", "只今那復有，從昔信爲難。", "見說清閑甚，無錢可蓋棺。"]'),
('dd67d230-3a77-4537-bc87-0239d66c4d4a','徐文子侍郎挽詩  其一','韓淲','宋','宋诗','song-poetry','','[]','分教隨爲大，公能過我廬。',48,'全唐诗/poet.song.177000.json','["分教隨爲大，公能過我廬。", "縉雲嘗和句，湓浦近收書。", "天府人間仰，甘泉帝所除。", "無高情復見，官路竟何如。"]'),
('40a70dcf-ccda-4963-ba88-3a84a7ce689a','徐文子侍郎挽詩  其二','韓淲','宋','宋诗','song-poetry','','[]','承華推舊學，鴻翼本高飛。',48,'全唐诗/poet.song.177000.json','["承華推舊學，鴻翼本高飛。", "次對恩空在，還官事已違。", "雙元今孰並，高士古猶稀。", "應有交朋老，泉溪泪濕衣。"]'),
('573685ca-bbd3-468f-8ea5-a624d290e04a','挽胡團王先生詩  其一','韓淲','宋','宋诗','song-poetry','','[]','在昔從諸老，于今失此翁。',48,'全唐诗/poet.song.177000.json','["在昔從諸老，于今失此翁。", "貌莊知德性，身退仰高風。", "制宅規何遠，藏書意轉隆。", "雖非官可貴，自與道無窮。"]'),
('e894bb0c-c0bf-4124-a5a7-c17402b70e3c','挽胡團王先生詩  其二','韓淲','宋','宋诗','song-poetry','','[]','著述欽成說，叮嚀憶緒言。',48,'全唐诗/poet.song.177000.json','["著述欽成說，叮嚀憶緒言。", "不期捐几杖，無復賁邱園。", "行旐村前路，豐碑屋外原。", "形容慙識淺，相挽只馨吞。"]'),
('7081b264-360d-4046-a998-af42c8dbe4b2','舒彥升監簿挽詩  其一','韓淲','宋','宋诗','song-poetry','','[]','不作驕浮態，還同謹厚爲。',48,'全唐诗/poet.song.177000.json','["不作驕浮態，還同謹厚爲。", "决科將顯大，脫選復逶遲。", "漕幕雖論薦，朝班僅取知。", "相看豸冠聳，忽聽薤歌悲。"]'),
('5214ceed-07a0-4560-92cc-d983c86fb5c3','舒彥升監簿挽詩  其二','韓淲','宋','宋诗','song-poetry','','[]','起家榮宦路，紀墓重鄉閭。',48,'全唐诗/poet.song.177000.json','["起家榮宦路，紀墓重鄉閭。", "忍見交親語，應求耆彥書。", "成名常自美，遺範久何如。", "東阜田園在，西山縣郭虛。"]'),
('29ea6643-a574-4dc1-b28d-a6079b37a741','陳宣撫待制挽詩  其一','韓淲','宋','宋诗','song-poetry','','[]','百尺樓高卧，宜乎造物遊。',48,'全唐诗/poet.song.177000.json','["百尺樓高卧，宜乎造物遊。", "衛青開幕府，李廣不封侯。", "世界乾坤在，邦家歲月流。", "遥知水心老，歷歷志諸幽。"]'),
('be7dc9e1-fc7e-4cf0-ac2a-f3155328d5a6','陳宣撫待制挽詩  其二','韓淲','宋','宋诗','song-poetry','','[]','到眼交朋少，前頭師友多。',48,'全唐诗/poet.song.177000.json','["到眼交朋少，前頭師友多。", "膠庠一騰達，臺閣合婆娑。", "混迹談諧爾，成名字畫何。", "隆興乾道舊，零落幾山阿。"]'),
('79eaead4-fb0d-410d-bd00-ea8bbc0654f4','李正之丈提刑挽詞  其一','韓淲','宋','宋诗','song-poetry','','[]','猶記登龍日，分明捉月仙。',48,'全唐诗/poet.song.177000.json','["猶記登龍日，分明捉月仙。", "精神超物表，才術本天然。", "符節多遺愛，璽書行九遷。", "豈期歸蜀道，乃爾閟重泉。"]'),
('36fe1976-74bb-4065-891b-0b3a5b1b7dd1','李正之丈提刑挽詞  其二','韓淲','宋','宋诗','song-poetry','','[]','耆舊今零落，風流近所無。',48,'全唐诗/poet.song.177000.json','["耆舊今零落，風流近所無。", "歌詩到元白，字畫逼歐虞。", "爲約言猶在，收書德不孤。", "階庭知有子，慶澤自相符。"]'),
('907e30e9-e3f8-42d2-bc88-813f2047ae2c','余寺丞挽詩  其一','韓淲','宋','宋诗','song-poetry','','[]','仁宅居郊秀，儒科載世清。',48,'全唐诗/poet.song.177000.json','["仁宅居郊秀，儒科載世清。", "致君纔列寺，教子亦專城。", "寵數垂車佚，恩封進秩榮。", "逢辰俱動色，厚夜失吞聲。"]'),
('697ca429-ba9a-471d-9b6f-eeccf014148b','余寺丞挽詩  其二','韓淲','宋','宋诗','song-poetry','','[]','恪素安時論，謙洪陟宦塗。',48,'全唐诗/poet.song.177000.json','["恪素安時論，謙洪陟宦塗。", "飛鳬應縹緲，峩豸乃踟躕。", "玉水流深派，靈山擁壯圖。", "豐碑看隴首，大隧錫龜趺。"]'),
('9601e2c9-229d-4a50-904f-8dbeeb949635','俞麻溪挽詩','韓淲','宋','宋诗','song-poetry','','[]','哀挽麻溪上，人皆說此翁。',48,'全唐诗/poet.song.177000.json','["哀挽麻溪上，人皆說此翁。", "平生多義事，終古盛儒風。", "湍石推名族，清湖想舊功。", "瑞雲松桂滿，寒露濕碑豐。"]'),
('ac2b3cca-2ae2-4cac-9b3f-27813c8ebe16','黄都幹挽詩','韓淲','宋','宋诗','song-poetry','','[]','歎息凋零舊，江城北客稀。',48,'全唐诗/poet.song.177000.json','["歎息凋零舊，江城北客稀。", "宦塗誰衮衮，里社獨依依。", "曾決文闈勝，纔從將幕歸。", "清霜吹夾路，老涕亦須揮。"]'),
('97094ba6-f5a5-4ea6-bfa3-bb411e250ff7','東陽郭德誼挽詞  其一','韓淲','宋','宋诗','song-poetry','','[]','赫奕汾陽後，才華冠里中。',48,'全唐诗/poet.song.177000.json','["赫奕汾陽後，才華冠里中。", "一官難未偶，五福合無窮。", "賓接師儒意，興揚禮義風。", "不亡知有子，嘉譽發諸公。"]'),
('23a30d44-0431-43d9-9bd0-32a3416fc6fe','東陽郭德誼挽詞  其二','韓淲','宋','宋诗','song-poetry','','[]','閭里應哀挽，佳城閟九泉。',48,'全唐诗/poet.song.177000.json','["閭里應哀挽，佳城閟九泉。", "素車行靡靡，丹旐去翩翩。", "腸斷西沉日，淚流東逝川。", "空餘書劍在，石洞貯風煙。"]'),
('b4ca4c8b-6e13-4e9f-a7f3-a1a5cdca8bd2','哭趙子夷縣丞二首  其一','韓淲','宋','宋诗','song-poetry','','[]','海內宗盟盛，振振乃好修。',48,'全唐诗/poet.song.177000.json','["海內宗盟盛，振振乃好修。", "傷心終契闊，回首近從遊。", "才學年方壯，聲猷志未休。", "人琴遽如許，歌罷玉溪流。"]'),
('bcd27561-941f-4956-96d2-e74911240f65','哭趙子夷縣丞二首  其二','韓淲','宋','宋诗','song-poetry','','[]','病阻躬臨穴，慇懃寄此哀。',48,'全唐诗/poet.song.177000.json','["病阻躬臨穴，慇懃寄此哀。", "嚴霜著松柏，寒日轉蒿萊。", "千雨應俱集，一詩慙匪才。", "致芻徐趙在，亦足慰泉臺。"]'),
('65463bda-8527-402d-9313-96ac0160e996','宋和仲挽詩','韓淲','宋','宋诗','song-poetry','','[]','舊話無人說，南遊事益暌。',48,'全唐诗/poet.song.177000.json','["舊話無人說，南遊事益暌。", "田園落吳楚，鄉社失青齊。", "道院松風在，佳城薤露悽。", "衣冠典刑地，遺恨滿霅溪。"]'),
('56163d3d-ea09-427a-a437-af53f2174dc2','宋柳州挽詩','韓淲','宋','宋诗','song-poetry','','[]','清德鄉閭冠，嘗思宋柳州。',48,'全唐诗/poet.song.177000.json','["清德鄉閭冠，嘗思宋柳州。", "故家猶有後，季子更無求。", "世業終能守，生涯僅足收。", "傷心往來地，翩旐土岡頭。"]'),
('f327048a-680f-443c-bf11-33220f3db557','余四一隠君挽詩','韓淲','宋','宋诗','song-poetry','','[]','季蛻竟觀化，忘機豈馮生。',48,'全唐诗/poet.song.177000.json','["季蛻竟觀化，忘機豈馮生。", "閑亭非故步，佳敘是修名。", "有子庶緜遠，無官底重輕。", "遥憐小水寺，松路鬰深清。"]'),
('50a10bc7-bfa2-43ea-acd3-0c502dfb879b','哭方伯謨','韓淲','宋','宋诗','song-poetry','','[]','平昔意翛然，閑吟肯自賢。',48,'全唐诗/poet.song.177000.json','["平昔意翛然，閑吟肯自賢。", "貧應聞苦節，學亦得心傳。", "路滑籍溪上，草深雲谷前。", "何時奠鷄酒，爲滴到重泉。"]'),
('923395a5-e4dc-4bdd-8fc5-70c708bae78f','哭潘恭叔宣幹','韓淲','宋','宋诗','song-poetry','','[]','憐我山之澗，高軒昔再過。',48,'全唐诗/poet.song.177000.json','["憐我山之澗，高軒昔再過。", "人生倏長往，天意竟如何。", "德學知能紹，儒言信不磨。", "春風青宿草，宰上想坡陀。"]'),
('3553bbc9-d668-4b7e-b056-497dd9455930','哭呂三','韓淲','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','東南駐驆地，近歲少狂言。',48,'全唐诗/poet.song.177000.json','["東南駐驆地，近歲少狂言。", "誰謂長江上，又招遷客魂。", "歸由徐穉舍，莽附阮孚墦。", "寒日松風起，妻兒獨泪痕。"]'),
('50daaa47-2c8e-419b-9ae4-905d2a9c8ea4','哭斯遠','韓淲','宋','宋诗','song-poetry','','[]','彤庭將賜第，疾病已纏之。',48,'全唐诗/poet.song.177000.json','["彤庭將賜第，疾病已纏之。", "藥裹自無及，朝衣誰爲披。", "識高空宛轉，意廣竟參差。", "只有章泉叟，與渠收舊詩。"]'),
('6c49fde1-5d33-4b59-8260-c6abe2b203f8','南豐宋郎中夫人曾氏挽詩','韓淲','宋','宋诗','song-poetry','','[]','奕奕南豐氏，新碑見母儀。',48,'全唐诗/poet.song.177000.json','["奕奕南豐氏，新碑見母儀。", "相夫郎省日，從子法曹時。", "懿美人皆仰，隆恩世所推。", "流芳當益大，雙鳳印纍纍。"]'),
('a1c49a79-3b6a-4293-8c55-5e541687d3dc','俞夫人楊氏挽詩','韓淲','宋','宋诗','song-poetry','','[]','往歲登門日，庭闈見淑稱。',48,'全唐诗/poet.song.177000.json','["往歲登門日，庭闈見淑稱。", "從夫期鼎貴，有子定登瀛。", "鸞誥恩榮在，魚軒夢幻驚。", "誰歌蒿里挽，寒雨和松聲。"]'),
('9b2f3b71-6e64-41ad-8f62-af63889e1814','江尉挽詩','韓淲','宋','宋诗','song-poetry','','[]','有子承家美，能書已薦賢。',48,'全唐诗/poet.song.177000.json','["有子承家美，能書已薦賢。", "葛塘成別墅，嚴瀨亦同川。", "意本功名遠，身猶爵命遷。", "臨終言不亂，雲繞寶華天。"]'),
('190cae90-94c1-48c1-9326-09711744a68c','陳太平挽詩  其一','韓淲','宋','宋诗','song-poetry','','[]','相業冰溪望，明公實妙年。',48,'全唐诗/poet.song.177000.json','["相業冰溪望，明公實妙年。", "方看回舊觀，乃復閟新阡。", "才學時爭美，聲華士更傳。", "發揚文正謚，尤動九重天。"]'),
('00cb1ec9-6dc7-49e1-8fa2-55337a4a2758','陳太平挽詩  其二','韓淲','宋','宋诗','song-poetry','','[]','歌酒追隨地，名園記昔游。',48,'全唐诗/poet.song.177000.json','["歌酒追隨地，名園記昔游。", "升沉嗟潦倒，哀挽爲悲愁。", "自出推王社，友于纔郡侯。", "聯翩期禁近，何意遽浮休。"]'),
('da546493-6296-4978-83b4-63e72cea1d16','德源訪乳泉問呂紫薇墓','韓淲','宋','宋诗','song-poetry','','[]','我記乳泉路，古橋歸德源。',48,'全唐诗/poet.song.177000.json','["我記乳泉路，古橋歸德源。", "寺何知雅俗，僧僅可寒溫。", "砌斷蘚痕澀，崖枯塵迹昏。", "紫薇青嶂合，秋樹葉初翻。"]'),
('ca4e1c38-2946-4f45-b153-07524922ae71','監倉趙十忠訓挽詩  其一','韓淲','宋','宋诗','song-poetry','','[]','先契俄三世，新交僅七年。',48,'全唐诗/poet.song.177000.json','["先契俄三世，新交僅七年。", "於中雖斷落，方始要周旋。", "志勇科名換，身勞疾病纏。", "壽藏留石窆，耆彥定銘鎸。"]'),
('3c2778c7-d46a-4e66-bd5d-425483c6b4f0','監倉趙十忠訓挽詩  其二','韓淲','宋','宋诗','song-poetry','','[]','經史閒常說，詩文喜或編。',48,'全唐诗/poet.song.177000.json','["經史閒常說，詩文喜或編。", "見賢知尚友，憂國問籌邊。", "宗室多名世，莊家喜有年。", "崇公元盛大，郡從已騰騫。"]'),
('6304d7a5-cd51-4390-b122-81bb7a5ee724','尋詩按酒','韓淲','宋','宋诗','song-poetry','','[]','拔卒尋詩將，同朋按酒兵。',72,'全唐诗/poet.song.177000.json','["拔卒尋詩將，同朋按酒兵。", "巢由空自洗，沮溺向誰耕。", "城市時來往，鄉村日送迎。", "任之多論秀，分矣只編甿。", "上郭如拳大，南溪指掌平。", "醉隨吟力去，歸隠紫雲生。"]'),
('6f7a1822-e40b-4140-a379-4a4b9d855611','贈趙倅','韓淲','宋','宋诗','song-poetry','','[]','老去懷玄英，冠塵已滿纓。',96,'全唐诗/poet.song.177000.json','["老去懷玄英，冠塵已滿纓。", "宦遊雖降志，棲遯實留情。", "幸以此身在，何由得眼明。", "相家逢別駕，仕路合專城。", "敢謂融尊滿，而同孔蓋傾。", "不嫌林竹迥，却愛石泉清。", "舉扇風襟豁，停杯月面輕。", "銀潢瀉天派，詩就玉繩橫。"]'),
('13a0db50-835d-4c20-98b9-eb6194b80cdc','送鄭盱眙','韓淲','宋','宋诗','song-poetry','','[]','羊陸規模遠，龔黄政事多。',120,'全唐诗/poet.song.177000.json','["羊陸規模遠，龔黄政事多。", "剖符欣委寄，視篆欲如何。", "秋入江湖道，寒生淮泗波。", "提封新保障，對境舊山河。", "吏蠹應銓擇，民窮藉撫摩。", "蕃宣歸俎豆，盟好戢干戈。", "才大知誰識，詩成想自哦。", "風雲嘗負劍，雨露憶鳴珂。", "緩带從簪履，凝香接綺羅。", "雅懷今鄭谷，壯畧古廉頗。"]'),
('8bde4c14-6cc5-4802-b1a6-2ab9c6e02f88','張禮書帥隆興','韓淲','宋','宋诗','song-poetry','','[]','國是古難定，公胡亦帥藩。',240,'全唐诗/poet.song.177000.json','["國是古難定，公胡亦帥藩。", "榮懷雖禁路，雅志已邱園。", "在昔從諸老，于今盛一門。", "便藩方異渥，勇退復明恩。", "家學資經緯，儒科得本原。", "等閒爲出處，何必較騰騫。", "致主丹心在，憂時素髮繁。", "紛紜誠蟣虱，變化任鵬鵾。", "華閣猶前席，洪都漫左轓。", "建牙儀甚偉，分屏望還尊。", "持橐嘉謀略，橫經妙討論。", "皂囊懷直節，青瑣務忠言。", "紬史知無隠，明刑信不冤。", "治纔和上下，力可正乾坤。", "收斂當侯閫，迢遥遠帝閽。", "九遷由簡拔，三入匪趨奔。", "落落終難合，悠悠實易昏。", "歸應思賀監，到日記陳蕃。", "自歎驅馳困，誰能顧盼溫。", "春風動行李，只有夢隨軒。"]'),
('37a0da9b-b9c9-4d73-8709-22c069659f0b','西山道院立春日','韓淲','宋','宋诗','song-poetry','','[]','春風吹我上箯輿，山路梅花已雪如。',64,'全唐诗/poet.song.177000.json','["春風吹我上箯輿，山路梅花已雪如。", "道院閑尋舊題句，故人不寄一行書。", "物華滿眼知春至，世事裝懷逼歲除。", "猶喜重來有佳伴，何妨相送入樵漁。"]'),
('97bd2209-45b0-4a07-9259-51d800a0aa67','晚春','韓淲','宋','宋诗','song-poetry','','[]','幽砌疎畦送晚春，水流山靜見閑身。',64,'全唐诗/poet.song.177000.json','["幽砌疎畦送晚春，水流山靜見閑身。", "行吟散去風光好，熟睡醒來雨氣新。", "木筆豈非濃意態，石楠終是淡精神。", "鶑聲圓處鵑聲急，景物要之不負人。"]'),
('18293da0-99c5-4cd7-a5d9-0456508e9931','春日','韓淲','宋','宋诗','song-poetry','','[]','紛如殘雪墮梅梢，門外春光入柳條。',64,'全唐诗/poet.song.177000.json','["紛如殘雪墮梅梢，門外春光入柳條。", "歲事肯隨人意改，時情空使客魂銷。", "山圍古屋地還僻，水拍孤城灘復高。", "鷗汎鳥鳴聲自好，一巾華髮任蕭蕭。"]'),
('40adbe20-fb44-4572-af96-a1f4e0ab5be8','惜春','韓淲','宋','宋诗','song-poetry','','[]','惜春惟付酒杯深，不特年齡老鬢侵。',64,'全唐诗/poet.song.177000.json','["惜春惟付酒杯深，不特年齡老鬢侵。", "花柳共隨人酩酊，軒裳祇覺我𡼭嶔。", "數家突兀迷深谷，一澗連橫出茂林。", "行遍東鄰與西舍，弄雲初日見啼禽。"]'),
('b363c7a7-2359-4b74-8251-7a92874a3a50','八月','韓淲','宋','宋诗','song-poetry','','[]','山林風雨便清涼，待把鄰家社甕嘗。',64,'全唐诗/poet.song.177000.json','["山林風雨便清涼，待把鄰家社甕嘗。", "到手自應無美惡，回頭誰解別斟量。", "深居但覺秋聲起，熟睡焉知夜漏長。", "未老得閑今又老，牀頭書冊漸相忘。"]'),
('3736642e-3c7b-4e39-8339-647302ef45d1','人日','韓淲','宋','宋诗','song-poetry','','[]','人日春來又兩宵，梅花開盡已飄摇。',64,'全唐诗/poet.song.177000.json','["人日春來又兩宵，梅花開盡已飄摇。", "愛閑多病有誰問，偶景獨遊無自焦。", "門外溪山猶淺淺，床頭書冊謾昭昭。", "細看榮辱雲翻雨，未抵幽棲水一瓢。"]'),
('26b7486d-a0da-4d1f-93cc-56689cfabcd8','熟食日','韓淲','宋','宋诗','song-poetry','','[]','清明寒食牡丹紅，江右無人記洛中。',64,'全唐诗/poet.song.177000.json','["清明寒食牡丹紅，江右無人記洛中。", "隨分曲欄皆一種，任他荒徑亦成叢。", "百年流落推遷景，一代興隆造化功。", "誰識名花有姚魏，數枝單葉倚晴風。"]'),
('b57d3273-1cf7-4d50-aee5-6b7b3b1ae1c7','二十九日寒食','韓淲','宋','宋诗','song-poetry','','[]','曉色濛濛淡淡烟，花間行過小溪邊。',64,'全唐诗/poet.song.177000.json','["曉色濛濛淡淡烟，花間行過小溪邊。", "人家寒食當晴日，野老春遊近午天。", "吹盡海棠無步障，開來山柳有堆綿。", "呼兒覓友尋鄰伴，即看村農又下田。"]'),
('a477cdc0-b6c1-4d5c-8221-2be1b91f92fe','清明  其一','韓淲','宋','宋诗','song-poetry','','[]','欲賦春華狀不成，微風微雨又清明。',64,'全唐诗/poet.song.177000.json','["欲賦春華狀不成，微風微雨又清明。", "殘花滿地偏饒笑，高柳插天如有情。", "百歲光陰誠鼎鼎，一生懷抱强營營。", "相思真隠山前路，寒食酒杯終日晴。"]'),
('4f46396f-4837-4f6b-9764-d05eaaa14ddf','清明  其二','韓淲','宋','宋诗','song-poetry','','[]','小院春陰滿檻花，淡紅微綠自芳華。',64,'全唐诗/poet.song.177000.json','["小院春陰滿檻花，淡紅微綠自芳華。", "簷前落日蜂兒聚，簾外東風燕子斜。", "修禊人尋詩事業，清明天與醉生涯。", "一樽莫負流觴意，夢到蘭亭興亦嘉。"]'),
('5c014e84-0497-4279-843e-a72a0c7eea6e','重午乏酒戲成','韓淲','宋','宋诗','song-poetry','','[]','小樓清坐意何如，休沐雖閑歎索居。',64,'全唐诗/poet.song.177000.json','["小樓清坐意何如，休沐雖閑歎索居。", "解粽未忘良夜飲，研朱猶作午時書。", "風生暝色天橫幕，雲捲晴光月吐梳。", "朗誦離騷撫空案，獨醒笑殺楚三閭。"]'),
('979a860b-33d1-410a-a6e1-0823f7453d80','重午','韓淲','宋','宋诗','song-poetry','','[]','年年重午泛菖蒲，兒女搔頭亦篆符。',64,'全唐诗/poet.song.177000.json','["年年重午泛菖蒲，兒女搔頭亦篆符。", "忍復研朱如羽客，懶能切玉醉狂夫。", "長歌楚些冤何有，却憶山人諷已無。", "田里蕭蕭方渴雨，小軒清望老懷孤。"]'),
('d016e9d3-3315-42d4-b45d-46428dffbbf1','七夕次韵仲至','韓淲','宋','宋诗','song-poetry','','[]','鈎月迷雲殢柳梢，雷聲收雨轉晴宵。',64,'全唐诗/poet.song.177000.json','["鈎月迷雲殢柳梢，雷聲收雨轉晴宵。", "從教冠蓋填京國，得似兒童遶市橋。", "玉漏沈沈傳底恨，銀河耿耿瀉無聊。", "政須百巧從天乞，嬾和閑吟聽夜潮。"]'),
('95d2fa5b-2bae-4187-ae65-be889fb864ca','七夕','韓淲','宋','宋诗','song-poetry','','[]','今年七夕最淒涼，謾埽天階試炷香。',64,'全唐诗/poet.song.177000.json','["今年七夕最淒涼，謾埽天階試炷香。", "猶使兒童覓瓜果，懶隨風俗曬衣裳。", "緱山何在歸寥廓，河鼓傳聞墮渺茫。", "百拙已成那得巧，年豐只欲更時康。"]'),
('8aa6eaab-d260-4c83-9808-6f95f6568d92','九日  其一','韓淲','宋','宋诗','song-poetry','','[]','老眼當今萬景隨，登臺殢酒不關詩。',64,'全唐诗/poet.song.177000.json','["老眼當今萬景隨，登臺殢酒不關詩。", "從教四野風烟合，未必荒園草木知。", "玉岫插天開岳頂，水波流月照江湄。", "一巾華髮吾何醉，故舊携壺汎菊時。"]'),
('6bdc647d-5103-44a0-83ed-531195230384','九日  其二','韓淲','宋','宋诗','song-poetry','','[]','酒不沾唇菊又華，荒苔何處落烏紗。',64,'全唐诗/poet.song.177000.json','["酒不沾唇菊又華，荒苔何處落烏紗。", "微官汩沒其誰問，多病尪羸只自嗟。", "山遶層城明落木，江連孤嶼漲平沙。", "空餘能賦登高意，一笑西窗日未斜。"]'),
('10910491-154b-4d96-8af3-5d69e8e1f6e4','九日列岫','韓淲','宋','宋诗','song-poetry','','[]','試傾濁酒汎黄華，節物於人自可嘉。',64,'全唐诗/poet.song.177000.json','["試傾濁酒汎黄華，節物於人自可嘉。", "一上荒臺供遠目，更邀閑客墮烏紗。", "蕭蕭霜樹明晴晝，隠隠烟汀入暮霞。", "醉裏只多今古意，要知秋色在山家。"]'),
('a285fd50-6149-4703-8e90-3638a7bccf68','九日不飲','韓淲','宋','宋诗','song-poetry','','[]','風光流轉又重陽，午夢初回意愈傷。',64,'全唐诗/poet.song.177000.json','["風光流轉又重陽，午夢初回意愈傷。", "時序肯隨人境異，江山空對晚天長。", "年華冉冉秋將老，物色班班菊自香。", "雖少一觴還一咏，恍然身世立蒼茫。"]'),
('72051800-729e-4335-980d-15ded89bfc49','九日破曉携兒姪上前山佇立佳甚','韓淲','宋','宋诗','song-poetry','','[]','懷玉鏡臺開遠晴，靈溪葛水去無聲。',64,'全唐诗/poet.song.177000.json','["懷玉鏡臺開遠晴，靈溪葛水去無聲。", "園荒不礙憑高立，徑側何須委曲行。", "露氣已濃清可掬，日華初上畫難成。", "閑居九日依辰至，舉俗胡爲亦愛名。"]'),
('45d2609f-a801-4173-a9d8-84f1498f5b17','次韵昌甫九日','韓淲','宋','宋诗','song-poetry','','[]','薄寒中人秋氣清，山能高絕水能平。',64,'全唐诗/poet.song.177000.json','["薄寒中人秋氣清，山能高絕水能平。", "獨憐佳節迫吹帽，誰可東籬嗅落英。", "盡道詩家有昌甫，每逢勝處說淵明。", "鬢毛垂領蕭蕭白，應任雨風陰復晴。"]'),
('d97c4f31-275d-4bb4-9f01-3f6ba7834a72','除夕呈仲至','韓淲','宋','宋诗','song-poetry','','[]','小至才看語夜深，歲除寒雪復關心。',64,'全唐诗/poet.song.177000.json','["小至才看語夜深，歲除寒雪復關心。", "交遊每歎難同話，親舊相逢且自尋。", "爆竹儘教鄰巷響，屠酥先付小兒斟。", "崇朝又是春風起，急景何由不緩吟。"]'),
('a7aca0b4-2610-4659-b48f-e82edde63537','正月初六日','韓淲','宋','宋诗','song-poetry','','[]','開年逐夜聞山雨，陣陣聲催一樣春。',64,'全唐诗/poet.song.177000.json','["開年逐夜聞山雨，陣陣聲催一樣春。", "孤枕自聽元不惡，虛簷誰謂便能新。", "門前有客尤全美，園裏無梅益固珍。", "水活正添幽澗淥，草生纖嫩亦初勻。"]'),
('2094885e-5b28-4401-ad69-9207b1c502e9','正月十三日','韓淲','宋','宋诗','song-poetry','','[]','南山春雪未全消，路並浮梁步石橋。',64,'全唐诗/poet.song.177000.json','["南山春雪未全消，路並浮梁步石橋。", "深綠漸歸高柳葉，淺紅初上小梅梢。", "峭寒寺院鐘聲起，昏暮人家燭影摇。", "一夜東風吹酒醒，夢回花月是元宵。"]'),
('186af6ee-da5b-4ab6-a9ae-25ee1accc99b','十五日晴窗','韓淲','宋','宋诗','song-poetry','','[]','絳霄誰復記宣和，燈市錢塘未覺多。',64,'全唐诗/poet.song.177000.json','["絳霄誰復記宣和，燈市錢塘未覺多。", "香動軟紅迷錦繡，醉扶嬌翠入笙歌。", "南來漸向百年久，北望其如前日何。", "門外兒童正呼笑，小窗晴色且吟哦。"]'),
('ef880667-ef83-434c-bc8c-775e3c0037c3','二月一日','韓淲','宋','宋诗','song-poetry','','[]','一山春雪見梅花，淥漲溝流浸草芽。',64,'全唐诗/poet.song.177000.json','["一山春雪見梅花，淥漲溝流浸草芽。", "縱著峭寒雖較冷，不禁暄日便爭華。", "遊蜂未放迷深樹，回雁初歸泊淺沙。", "步轉橫橋已孤絕，奈吹香處隔鄰家。"]'),
('a86f5653-86ee-4417-a8f5-e4540bea8951','二十二日','韓淲','宋','宋诗','song-poetry','','[]','年過半百身何用，猶有春來不世情。',64,'全唐诗/poet.song.177000.json','["年過半百身何用，猶有春來不世情。", "夾岸桃紅仍柳綠，漫山月白與風清。", "狂朋怪侶難收拾，騃女癡兒易長成。", "老把一杯生日酒，待呼沮溺耦而耕。"]'),
('6374845f-7a4c-45ea-b38f-5e9ddbeff5cf','二十六日','韓淲','宋','宋诗','song-poetry','','[]','雨雪綿綿春欲深，鵝湖石井舊登臨。',64,'全唐诗/poet.song.177000.json','["雨雪綿綿春欲深，鵝湖石井舊登臨。", "經行爲我躊躇立，俛仰知誰放曠吟。", "高爽山川無起滅，卑喧人物有升沈。", "青鞋布襪茅柴酒，花柳中邊惜此心。"]'),
('e89c0fe2-1a7c-4ffa-8627-5a8b1b2c8509','三月初二日','韓淲','宋','宋诗','song-poetry','','[]','楊柳陰陰上小樓，窗中遠岫夕陽浮。',64,'全唐诗/poet.song.177000.json','["楊柳陰陰上小樓，窗中遠岫夕陽浮。", "棋聲競處偏饒笑，酒味醺時未肯休。", "多病故應驚獨老，一閒消得許多愁。", "清和莫放春歸去，好事人須惜此遊。"]'),
('d08f6e85-68ee-4ec3-aa57-7a3f6ead317e','三月四日','韓淲','宋','宋诗','song-poetry','','[]','三年寒食在山中，柳自青青花自紅。',64,'全唐诗/poet.song.177000.json','["三年寒食在山中，柳自青青花自紅。", "寓意本期詩得策，推愁殊覺酒無功。", "消磨故態全然別，冷落新交轉不同。", "原上子推將隠矣，且呼餳粥對春風。"]'),
('45b68a4c-e1b9-4371-8153-ba7d626ae11f','初八日','韓淲','宋','宋诗','song-poetry','','[]','轉覺春風滿鬢華，冷烟寒食動梨花。',64,'全唐诗/poet.song.177000.json','["轉覺春風滿鬢華，冷烟寒食動梨花。", "年年縱有心情在，處處寧無語笑譁。", "澗水細翻晴浪急，園林微轉午陰斜。", "數聲紫燕芹泥濕，又入前村八九家。"]'),
('b2747876-9629-43ce-8bbe-6df599ce7b0d','十八日','韓淲','宋','宋诗','song-poetry','','[]','一年難得是芳時，花柳暄明易滿枝。',64,'全唐诗/poet.song.177000.json','["一年難得是芳時，花柳暄明易滿枝。", "人處其間無不有，事思以往總何宜。", "清和天氣雨頻斂，冷澹風光日緩移。", "交道從前要申固，惜春固可共尋詩。"]'),
('37d556c0-1b60-469f-899f-27b27d0170c3','十一日','韓淲','宋','宋诗','song-poetry','','[]','八年山澗送春歸，流轉風光欲告誰。',64,'全唐诗/poet.song.177000.json','["八年山澗送春歸，流轉風光欲告誰。", "草野其間無別種，芳華之外有殘枝。", "燕鶑蜂蝶偏他好，雞犬牛羊不自持。", "溪北溪南交舊在，輕雷吹動雨成絲。"]'),
('e007368c-a05a-4f58-acd0-36a11081886b','七月旦','韓淲','宋','宋诗','song-poetry','','[]','才鼓南薰又得秋，中林清雨洗還幽。',64,'全唐诗/poet.song.177000.json','["才鼓南薰又得秋，中林清雨洗還幽。", "舊交到了終餘味，新話從來不奈愁。", "末利潔香花未減，芙蕖酣豔葉方浮。", "棋盤酒斝從容地，風物滿軒能會不。"]'),
('8aa46970-d32c-4921-bfd1-0b7a026b6ba1','晚來  其一','韓淲','宋','宋诗','song-poetry','','[]','晚來無處不西風，散入千巖萬壑中。',64,'全唐诗/poet.song.177000.json','["晚來無處不西風，散入千巖萬壑中。", "叢桂香邊烟羃䍥，疎桐影裏月朦朣。", "等閒散步情何限，隨分微吟苦未工。", "秋色秋聲已如許，更憑高處目飛鴻。"]'),
('7fa5b3c4-79d7-47b7-8d83-347bd438febe','晚來  其二','韓淲','宋','宋诗','song-poetry','','[]','天乃揫歛作深秋，斷港回溪水亦收。',64,'全唐诗/poet.song.177000.json','["天乃揫歛作深秋，斷港回溪水亦收。", "明月已圓雲淡薄，西風初老雨霏浮。", "青鞋布襪隨宜過，白酒黄雞有底愁。", "北客登臨多話舊，只今楚尾是吳頭。"]'),
('792a5866-ba46-4361-b8f4-3bb4bc88332e','二十九日','韓淲','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','中秋過了重陽近，不是騷人愛楚詞。',64,'全唐诗/poet.song.177000.json','["中秋過了重陽近，不是騷人愛楚詞。", "鐘鼎山林元自若，精神心術復誰知。", "長江湛湛吹楓葉，三徑皇皇把菊枝。", "宋玉謾悲陶令醉，我何杯酒嘯歌時。"]'),
('2aa6b042-19e2-41c1-be49-74a0f14480d9','閏九月旦','韓淲','宋','宋诗','song-poetry','','[]','春山無伴怨傷神，故作幽期一兩人。',64,'全唐诗/poet.song.177000.json','["春山無伴怨傷神，故作幽期一兩人。", "花外水田看白鷺，松根高冢問麒麟。", "初非此叟其遊淡，終是諸賢所趣真。", "雨氣忽生歸去晚，新詩改罷滿壺春。"]'),
('69cf458e-65b6-4e0a-967d-7308abd7c2f3','十二月六日','韓淲','宋','宋诗','song-poetry','','[]','小園梅樹已吹花，山映疎林水映沙。',64,'全唐诗/poet.song.177000.json','["小園梅樹已吹花，山映疎林水映沙。", "風信不禁時動蕩，雨絲維見日交加。", "雖無清影爲吟筆，猶有繁香在物華。", "我老一杯隨意飲，數聲歸雁落天涯。"]'),
('5c8c7288-ddfd-4010-85bb-fa64af7d8b55','十六日','韓淲','宋','宋诗','song-poetry','','[]','雪飛三日暗烟霧，雪住三日埋冰霜。',64,'全唐诗/poet.song.177000.json','["雪飛三日暗烟霧，雪住三日埋冰霜。", "盡道春來須解凍，不疑臘盡未回陽。", "樓臺矚望猶如積，城市驅馳殆欲僵。", "辛苦農家應擊壤，遺蝗入地麥青長。"]'),
('50460786-00cb-4333-b1a2-ca5afa4d373c','連日暖甚','韓淲','宋','宋诗','song-poetry','','[]','日暖既愁添疾病，霜寒將恐壞收成。',64,'全唐诗/poet.song.177000.json','["日暖既愁添疾病，霜寒將恐壞收成。", "石田未必倉箱足，人境還須氣體平。", "薄晚閉窗危膝坐，崇朝開戶放身行。", "一冬饑飽渾閒事，安得淮南草木生。"]'),
('ba1e3570-a88d-4523-87e3-eb89f2c07a61','晴景','韓淲','宋','宋诗','song-poetry','','[]','曉烟初凈雨晴時，膩日偎風不自持。',64,'全唐诗/poet.song.177000.json','["曉烟初凈雨晴時，膩日偎風不自持。", "溫厚便饒多著蘂，輕肥全藉畧開枝。", "其間小院桃遮戶，此外孤村柳隔籬。", "香撲酒旗吟莫盡，艷明歌管醉方知。"]'),
('8922bca4-b12a-415f-ab14-afc27b077906','十四日竹居翫月','韓淲','宋','宋诗','song-poetry','','[]','柳垂田水浸籬橋，月上蒼茫影動摇。',64,'全唐诗/poet.song.177000.json','["柳垂田水浸籬橋，月上蒼茫影動摇。", "秋不爲他人事改，時間徒自客魂銷。", "歌聲感耳如何夕，酒力熏心匪一朝。", "推枕覺來風四起，凉侵雙鬢髮蕭蕭。"]'),
('928487ac-214d-4a86-a673-b9fc30a7422f','同鄭一過方齋又往山堂初夜微風雨作步至城外','韓淲','宋','宋诗','song-poetry','','[]','得雨逢秋一醉同，老身隨處爲從容。',64,'全唐诗/poet.song.177000.json','["得雨逢秋一醉同，老身隨處爲從容。", "笑花齋外言談久，桂樹門邊步武通。", "漫挾兩兒常兀兀，既來三友莫怱怱。", "夜凉共踏朦朧月，贏取歸橋滿袖風。"]'),
('252fdcd5-85c0-46e9-8cfc-5f256fde6e43','經月少雨無雷連日方聞之','韓淲','宋','宋诗','song-poetry','','[]','雨陰經月未聞雷，風駕濃雲電倏開。',64,'全唐诗/poet.song.177000.json','["雨陰經月未聞雷，風駕濃雲電倏開。", "天盡熒熒橫屋去，地高殷殷下簷來。", "浪明潮海瓊瑶碎，聲撼山林翠碧堆。", "暑氣便回梅氣潤，老農無復慮田萊。"]'),
('845387ae-8415-4b71-b976-e383b46895e4','喜雨呈三衢蘇大使君  其一','韓淲','宋','宋诗','song-poetry','','[]','震雷飛電起雲霓，想見鈴齋閔雨時。',64,'全唐诗/poet.song.177000.json','["震雷飛電起雲霓，想見鈴齋閔雨時。", "十里頌聲傳道路，萬家和氣舞童兒。", "眷隆芝檢聞歸詔，恩浹棠陰有去思。", "行客爲公停桂棹，坐看豐稔喜成詩。"]'),
('ecba488d-e970-4d4a-b18d-7585ab7ff836','喜雨呈三衢蘇大使君  其二','韓淲','宋','宋诗','song-poetry','','[]','黄門事業到公傳，待月軒中世有賢。',64,'全唐诗/poet.song.177000.json','["黄門事業到公傳，待月軒中世有賢。", "剖竹少勞麾戟外，持荷今在冕旒前。", "文華自足窮三古，政力誰知即九遷。", "潁上通家今幾許，喚回舊觀屬蘇仙。"]'),
('73c58930-e2b7-468d-a058-437538829c0c','苦雨','韓淲','宋','宋诗','song-poetry','','[]','陰陰天氣恰如秋，雨密還稀不斷頭。',64,'全唐诗/poet.song.177000.json','["陰陰天氣恰如秋，雨密還稀不斷頭。", "積土縱橫聚蚯蚓，敗牆零落上蝸牛。", "支頤習靜猶成趣，搔首尋思只伴愁。", "安得雄風埽雌霓，滿湖晴日弄扁舟。"]'),
('fe343250-56eb-442f-bec1-6881121c5e44','留連三宿將出山社雨甚至二十一日','韓淲','宋','宋诗','song-poetry','','[]','社甕同傾酒易深，留連風雨爲沈吟。',64,'全唐诗/poet.song.177000.json','["社甕同傾酒易深，留連風雨爲沈吟。", "興言大抵多懷舊，何事如斯直至今。", "下榻新窗還抵掌，扶輿舊隠只關心。", "歸尋來路村村柳，餘靄春空日半陰。"]'),
('2fd70f3f-7450-4c84-bbc4-56950adf4db4','十六日終夜雨','韓淲','宋','宋诗','song-poetry','','[]','雨簷經月不通流，一夜垂垂得滿溝。',64,'全唐诗/poet.song.177000.json','["雨簷經月不通流，一夜垂垂得滿溝。", "塵斂小園應菜甲，地甦長畝見禾頭。", "暑消未足添吾詠，歲熟當能解國憂。", "少待甘霖遍江海，老夫亦欲具扁舟。"]'),
('4abacf45-4b85-4c8b-a3e1-42919e335409','初十夜雨十一日大雨呈趙守','韓淲','宋','宋诗','song-poetry','','[]','醮事初嚴雨已傾，神車西上百川盈。',64,'全唐诗/poet.song.177000.json','["醮事初嚴雨已傾，神車西上百川盈。", "坐令田里三農喜，身見邦侯一念誠。", "歡動追鋒歸禁近，福迴眉壽奉親榮。", "鬰攸洗凈餘氛後，開士畫傳禪月清。"]'),
('fe2e30c8-e906-40f4-85b1-29acfe7e4a01','夜坐雨聲','韓淲','宋','宋诗','song-poetry','','[]','山靜蕭蕭吹雨聲，葉爐無火有燈檠。',64,'全唐诗/poet.song.177000.json','["山靜蕭蕭吹雨聲，葉爐無火有燈檠。", "潛神試數出入息，專氣不聞長短更。", "坐定布衾疑地煖，起遲紙帳失天明。", "年來白髮身爲老，齊物篇成亦强名。"]'),
('14c3aa40-eaac-4669-8a76-962b20d5e393','夜半聞雨聲清甚','韓淲','宋','宋诗','song-poetry','','[]','雨聲催我夢華胥，清氣於人便有餘。',64,'全唐诗/poet.song.177000.json','["雨聲催我夢華胥，清氣於人便有餘。", "惟適之安非素隠，不容何病是閒居。", "茶烟未了歸真覺，香霧初橫切太虛。", "却憶華山陳處士，惘然推枕聽階除。"]'),
('582543e3-e312-4f4b-83e5-fb5a9d018fd9','雨思','韓淲','宋','宋诗','song-poetry','','[]','寂寂無人倍覺秋，雨聲風色驟還收。',64,'全唐诗/poet.song.177000.json','["寂寂無人倍覺秋，雨聲風色驟還收。", "高林背日孤城脚，細草堆烟古渡頭。", "中夜荒雞劉石舞，上林飛雁子卿愁。", "相看籬菊巖花後，華髮清尊可罷休。"]'),
('77def04d-2807-47ae-8f1d-15e70305da46','閏月八日雨','韓淲','宋','宋诗','song-poetry','','[]','一雨山林方始秋，世間休待我回頭。',64,'全唐诗/poet.song.177000.json','["一雨山林方始秋，世間休待我回頭。", "心雖未老何須壯，身自長貧不用愁。", "滿地烟雲終淡淡，數家雞犬也悠悠。", "木犀開後菊花發，隨分杖藜尋酒篘。"]'),
('d6471363-d328-4310-a12c-d067ab11a24f','二十七日雨意如秋','韓淲','宋','宋诗','song-poetry','','[]','一雨山林又近秋，亂鴉鳴處已飂飂。',64,'全唐诗/poet.song.177000.json','["一雨山林又近秋，亂鴉鳴處已飂飂。", "聲連簷溜更初滴，氣撲庭陰曉未收。", "爍石炎威真可畏，著人涼意却生愁。", "西疇想見芃芃矣，且問今年早熟不。"]'),
('53285509-45cd-4399-ab97-d8732fd88e1f','立秋後一日聞雨','韓淲','宋','宋诗','song-poetry','','[]','秋來便覺雨蕭蕭，涼入西風百慮銷。',64,'全唐诗/poet.song.177000.json','["秋來便覺雨蕭蕭，涼入西風百慮銷。", "夜靜竹窗聲自起，晝閒松院影長摇。", "苦無車馬能來往，却有樵漁破寂寥。", "澗水已添流漸遠，市塵渾不過浮橋。"]'),
('9e000000-caf6-40c9-be04-c28ac746fb4a','連日大雨秋已如許','韓淲','宋','宋诗','song-poetry','','[]','連朝秋雨起秋風，夢覺吳山第一峰。',64,'全唐诗/poet.song.177000.json','["連朝秋雨起秋風，夢覺吳山第一峰。", "離合亂雲思過雁，去來斜月聽吟蛩。", "寂寥髣髴天容澹，摇落相看野色濃。", "寄語騷人模寫取，登臨佳處更從容。"]'),
('92ee44ba-2ab8-48cc-8637-f8a1ed3d1675','二十六夜大雨達旦','韓淲','宋','宋诗','song-poetry','','[]','熟睡俄驚簟未收，披衣側坐且搔頭。',64,'全唐诗/poet.song.177000.json','["熟睡俄驚簟未收，披衣側坐且搔頭。", "颼飂隔屋聽吹瓦，滂沛連牀定滿溝。", "曉起見山全带霧，午晴沿澗尚周流。", "新涼秔稻農歌處，共喜開禧第一秋。"]'),
('3a0abc80-9f71-4e02-8cbf-e1b32d8c0396','十八日小暑大雨','韓淲','宋','宋诗','song-poetry','','[]','申禱山川便作霖，耘苗時候想田深。',64,'全唐诗/poet.song.177000.json','["申禱山川便作霖，耘苗時候想田深。", "且欣小暑能如此，更願新秋得似今。", "早稻欲花將就實，晚禾成葉未抽心。", "天應不忍焦勞意，直自初栽已望陰。"]'),
('cc356139-7818-48a5-9a57-7ca0eb74e475','苦旱  其一','韓淲','宋','宋诗','song-poetry','','[]','望雲渴雨驗朝霞，不但田家更國家。',64,'全唐诗/poet.song.177000.json','["望雲渴雨驗朝霞，不但田家更國家。", "兵食固難資寶貨，民饑豈爲用泥沙。", "一邱一壑自棲遯，百巧百窮誰富奢。", "水旱是天祈是我，山川靈響本無差。"]'),
('0546ec1e-9d75-4762-904e-5089ea346efe','苦旱  其二','韓淲','宋','宋诗','song-poetry','','[]','林熱江渾其奈何，冷菰寒玉漫詩歌。',64,'全唐诗/poet.song.177000.json','["林熱江渾其奈何，冷菰寒玉漫詩歌。", "南遊禹穴古能幾，北望神州兵又多。", "畎畝乏財愁折帛，倉場儲粟仰秋禾。", "幽泉坎井徒爭汲，盡日驕陽過碧蘿。"]'),
('1f00e8be-bdfc-478a-a566-dabfb976b50b','苦旱  其三','韓淲','宋','宋诗','song-poetry','','[]','孤坐焦心氣不甦，炎風畏景逼頭顱。',64,'全唐诗/poet.song.177000.json','["孤坐焦心氣不甦，炎風畏景逼頭顱。", "澗流已斷無萍實，園圃俱荒失芋區。", "絺綌縱施衣復汗，簡編雖近墨難濡。", "人嘲褦襶交遊絕，頭白昏昏髮懶梳。"]'),
('1d677d36-e75e-495f-b44c-8e214aca53f3','苦旱  其四','韓淲','宋','宋诗','song-poetry','','[]','歲晚霜天雪夜時，地爐無火亦頻吹。',64,'全唐诗/poet.song.177000.json','["歲晚霜天雪夜時，地爐無火亦頻吹。", "如今旱殺熱難過，以昔窮忙寒不知。", "歲月只隨時變換，乾坤徒使氣推移。", "馮生衆庶真何謂，翻手爲雲雨亦奇。"]'),
('3995f273-eca7-460a-871b-4f47852a920d','苦旱  其五','韓淲','宋','宋诗','song-poetry','','[]','去年水溢愁無地，今歲旱乾唯告天。',64,'全唐诗/poet.song.177000.json','["去年水溢愁無地，今歲旱乾唯告天。", "潤澤且爲南畝計，清涼終作北窗眠。", "師興而雨春秋傳，星有好風洪範篇。", "上郭橋頭看競禱，大霞宮頂記曾遷。"]'),
('60e226b9-6705-4eb4-90fa-a2adaba8b2aa','正月十日雪','韓淲','宋','宋诗','song-poetry','','[]','雪花飛我讀書林，松葉梅梢自賞音。',64,'全唐诗/poet.song.177000.json','["雪花飛我讀書林，松葉梅梢自賞音。", "莫問侵尋春事近，肯教容易歲寒駸。", "擁裘鶴帳眠方熟，抱膝雞窗興愈深。", "更啟柴門喚鄰曲，伴題冰柱共清斟。"]'),
('fe67a7c8-9d75-4b9f-b729-a989bd304a57','雪氣','韓淲','宋','宋诗','song-poetry','','[]','連山烟霧起層陰，混混沄沄雪氣深。',64,'全唐诗/poet.song.177000.json','["連山烟霧起層陰，混混沄沄雪氣深。", "直面樓臺開遠寺，驚心人物話平林。", "花街車馬何曾少，茅屋塵埃轉不侵。", "吠怪從渠走羣犬，鴻冥初不礙遺音。"]'),
('638dd041-fc24-48a9-a7ae-5c593fd39a5e','探雪','韓淲','宋','宋诗','song-poetry','','[]','芟削蒿萊見綠苔，扶疎竹影待梅開。',64,'全唐诗/poet.song.177000.json','["芟削蒿萊見綠苔，扶疎竹影待梅開。", "風生野色蒼蒼合，日轉寒光冉冉來。", "高步芒鞋時躑躅，橫拖藜杖且徘徊。", "斷鴻飛過霜禽下，清絕山根與澗隈。"]'),
('33fd55e4-8f5e-4c14-b19e-19f815bca99f','和仲達雪詩','韓淲','宋','宋诗','song-poetry','','[]','屋上未融寒尚力，山頭微積凍難開。',64,'全唐诗/poet.song.177000.json','["屋上未融寒尚力，山頭微積凍難開。", "照窗渾似月侵夜，落酒只疑酥滿杯。", "䔩䔩剡溪粘短棹，重重庾嶺壓疎梅。", "新詩韵度慰岑寂，仰歎吾人殊有才。"]'),
('7975c573-fe40-44b7-a7f4-3f97886640f9','下簾兀坐詠雪','韓淲','宋','宋诗','song-poetry','','[]','紙簾垂下竹爐深，火白燈青窗氣侵。',64,'全唐诗/poet.song.177000.json','["紙簾垂下竹爐深，火白燈青窗氣侵。", "但可吟哦經我手，不須斟酌問它心。", "天寒頻歲無飛雪，地煖連朝有積陰。", "萬逕千山蹤跡外，躊躇足力詠投簪。"]'),
('98092e00-05ef-41e2-b51a-33a267223acc','雪','韓淲','宋','宋诗','song-poetry','','[]','常時小至多無雪，今歲纔先七日飛。',64,'全唐诗/poet.song.177000.json','["常時小至多無雪，今歲纔先七日飛。", "不待禱祠知帝力，要爲豐稔發天機。", "包羅草樹孤城近，彈壓谿山小市稀。", "本自倦吟仍止酒，漁樵何事破寒歸。"]'),
('a8d321a6-121d-4188-8d86-95e9b53761cd','雪作次邱簿韵','韓淲','宋','宋诗','song-poetry','','[]','萬里江天雪意濃，艤篷覓句愧諸公。',64,'全唐诗/poet.song.177000.json','["萬里江天雪意濃，艤篷覓句愧諸公。", "相逢不數山陰夜，酬唱難追正始風。", "一飯已形雲子白，舉杯更瀉真珠紅。", "片帆西上君須記，興在遠村丹樹楓。"]'),
('3ca1772f-7a69-456c-8dbd-05c63b94e4d1','次韵仲至雪','韓淲','宋','宋诗','song-poetry','','[]','寒力噓雲積漸生，倚梅偎柳大多情。',64,'全唐诗/poet.song.177000.json','["寒力噓雲積漸生，倚梅偎柳大多情。", "望迷鳷鵲光先起，戲就狻猊勢亦獰。", "字字添酥驚怕晚，絲絲弄粉惡差明。", "謫仙簷下人誰畫，更著飛花舞落英。"]'),
('fb43dd95-df9c-4141-8db1-b252fe0e6332','雪天','韓淲','宋','宋诗','song-poetry','','[]','雲意昏明欲雪天，冷風吹葉滿流泉。',64,'全唐诗/poet.song.177000.json','["雲意昏明欲雪天，冷風吹葉滿流泉。", "短簷半影荒荒日，曲逕微籠冉冉烟。", "山色不嫌靈運屐，溪光先上子猷船。", "林邊喜有春消息，梅點長梢已粲然。"]'),
('78fe040e-5d90-4800-a1d4-c6ad6b544e8a','喜雪上丁使君','韓淲','宋','宋诗','song-poetry','','[]','臘前三白數年無，田里歡呼聽我徒。',64,'全唐诗/poet.song.177000.json','["臘前三白數年無，田里歡呼聽我徒。", "顧歎閒身何用矣，瞻言老手盍知乎。", "茅柴縱熱慵杯煖，鉛槧雖荒忍硯枯。", "袁巷灞橋空廣譬，只宜煎水對茶爐。"]'),
('4f458c55-8e5f-4236-a0b0-93ff9283e8a1','次韵教授喜雪  其一','韓淲','宋','宋诗','song-poetry','','[]','臘前郊後豐年瑞，和氣祥風帝所祈。',64,'全唐诗/poet.song.177000.json','["臘前郊後豐年瑞，和氣祥風帝所祈。", "吹作六花殊未已，釀成三白更何思。", "列城黎庶窮無告，幽谷畸人飽可期。", "眼底玉谿真樂土，坐銷愁歎合吟詩。"]'),
('7571b545-740a-4ea6-a7df-ee218541f8e4','次韵教授喜雪  其二','韓淲','宋','宋诗','song-poetry','','[]','在昔君家信不癡，剡中高興尚何之。',64,'全唐诗/poet.song.177000.json','["在昔君家信不癡，剡中高興尚何之。", "一時雪月寧須我，萬古溪山更屬誰。", "歡動梁園雖共樂，困安袁巷本相宜。", "衝寒應見前村笑，冷蘂疎梅又幾枝。"]'),
('e1bcf132-1734-4d46-8ece-d4539daaf235','雪消','韓淲','宋','宋诗','song-poetry','','[]','雪晴如雨滴茅簷，近濺橫飛遠復霑。',64,'全唐诗/poet.song.177000.json','["雪晴如雨滴茅簷，近濺橫飛遠復霑。", "風定漸和歸几研，日斜微透入書籤。", "也知坐久須還起，便覺爐深不用添。", "麥隴高低應更潤，青青整整動纖纖。"]'),
('b197b716-8ab4-4e22-9e2c-9764f282a125','日雪','韓淲','宋','宋诗','song-poetry','','[]','閉門忍作袁安卧，一笑山陰訪戴行。',64,'全唐诗/poet.song.177000.json','["閉門忍作袁安卧，一笑山陰訪戴行。", "溪汎小舟吾亦懶，履穿東郭孰忘情。", "飯炊因酒瞢騰去，睡覺思詩宛轉成。", "莫道農田喜三白，皚皚何地不爭明。"]'),
('fa1001db-0ece-44bf-a398-69a5dd403447','雪晴可喜','韓淲','宋','宋诗','song-poetry','','[]','雪後春生日氣晴，梅根蘭葉喜駸駸。',64,'全唐诗/poet.song.177000.json','["雪後春生日氣晴，梅根蘭葉喜駸駸。", "亟圖賸賞那無興，轉覺倦遊非有心。", "高卧袁安嗟往事，生擒元濟報佳音。", "明年脫綬乘潮去，舟過釣臺尤要吟。"]'),
('5cdfb430-f24d-4793-b8b2-f7ee8b927440','徑山','韓淲','宋','宋诗','song-poetry','','[]','明月池頭國一禪，殘僧依舊占三椽。',64,'全唐诗/poet.song.177000.json','["明月池頭國一禪，殘僧依舊占三椽。", "薰風正綠門前樹，積水都清澗下川。", "坐斷千峰因底事，身輕百劫本何緣。", "箯輿有客登臨久，齋罷茗盂香散烟。"]'),
('3c44c84f-e5c5-48cc-9f0e-9e66440f6707','平山','韓淲','宋','宋诗','song-poetry','','[]','章泉粥罷上松關，野逕田塍直復彎。',64,'全唐诗/poet.song.177000.json','["章泉粥罷上松關，野逕田塍直復彎。", "迫晚詩翁來款曲，同時坐客亦躋攀。", "誰云身外無窮事，自是人間有許閑。", "夢兀箯輿忘遠近，午風晴日已平山。"]'),
('1a4a4d65-1b98-4ba1-9dbf-b458bf184482','山靜','韓淲','宋','宋诗','song-poetry','','[]','山靜不嫌雞犬聲，閒身隨意了陰晴。',64,'全唐诗/poet.song.177000.json','["山靜不嫌雞犬聲，閒身隨意了陰晴。", "柴扉終日其誰問，梅逕有時還自行。", "一曲澗流雖淺澹，數株花蘂甚分明。", "牀頭周易初無恙，酒困茶醒底用情。"]'),
('0966b335-3d95-4ec3-a77f-6562a8f09d2f','山林','韓淲','宋','宋诗','song-poetry','','[]','山林終日掩柴門，近聽風聲遠對雲。',64,'全唐诗/poet.song.177000.json','["山林終日掩柴門，近聽風聲遠對雲。", "粗有稻粱供伏臘，尚憑雞犬報朝曛。", "氣非身外無存想，書在眼前多見聞。", "客至不勞閑酒食，一甌茶炷一爐熏。"]'),
('57b95b5a-b94b-4e96-a90e-13db81092e49','葛洪川','韓淲','宋','宋诗','song-poetry','','[]','葛洪川畔試尋詩，圓澤精魂世孰知。',64,'全唐诗/poet.song.177000.json','["葛洪川畔試尋詩，圓澤精魂世孰知。", "但見野僧相指點，獨憐游子轉傷悲。", "湍流澗水侵苔蘚，磊落山巖拂樹枝。", "我亦賞吟風月爾，人間今古信如斯。"]'),
('6e4b20c7-4bf3-443e-96f4-b377eab554fd','二十八日宋家泉頭','韓淲','宋','宋诗','song-poetry','','[]','每逢泉石必從容，閒過吾廬絕澗東。',64,'全唐诗/poet.song.177000.json','["每逢泉石必從容，閒過吾廬絕澗東。", "簸弄泓澄看硌确，盤旋窈窕喜蒙籠。", "近村欲雨無斜日，遠岫歸雲有陣風。", "白酒釀成誰酌我，濯纓洗耳不須同。"]'),
('fae5d2f5-dd9e-4418-b35b-25995d6f4e39','春泉','韓淲','宋','宋诗','song-poetry','','[]','幽伴無人話采樵，老身何處可逍遥。',64,'全唐诗/poet.song.177000.json','["幽伴無人話采樵，老身何處可逍遥。", "閒當曉徑誰爭席，間或春泉自一瓢。", "煖靄欲銷遲日在，輕風徐起亂雲飄。", "才情今古能多少，未必巢由不見堯。"]'),
('47f373c2-aaa9-41a8-9d79-8f0bf97c6605','山行','韓淲','宋','宋诗','song-poetry','','[]','家住疎疎短短籬，並山支徑自登躋。',64,'全唐诗/poet.song.177000.json','["家住疎疎短短籬，並山支徑自登躋。", "寒雲四垂天慘慘，老木環鎖風凄凄。", "身從荒園叩古寺，眼暗孤城带清溪。", "尋僧與客少談勝，興罷歸來烏夜啼。"]'),
('722ad13b-0fca-44ab-9dde-21744677d2e5','初八日登前山獨坐久之','韓淲','宋','宋诗','song-poetry','','[]','陰陰秋與白雲浮，山近林深上上頭。',64,'全唐诗/poet.song.177000.json','["陰陰秋與白雲浮，山近林深上上頭。", "千里纔成萬家邑，百川分繞一方州。", "其間雞犬微茫處，此外鵾鵬莽曠遊。", "明日黄花是重九，更尋橋月看溪流。"]'),
('b7069c29-c51d-4b8d-b6d4-280e0e272400','夜同處晦霞山','韓淲','宋','宋诗','song-poetry','','[]','春來不道梅花好，古觀荒林並晚晴。',64,'全唐诗/poet.song.177000.json','["春來不道梅花好，古觀荒林並晚晴。", "一一枝間見生意，重重影外落寒聲。", "酒因人勝舒徐飲，詩待客吟蕭散成。", "扶盡墟煙橫野水，暗涵深綠起疎明。"]'),
('22598209-2af1-41ca-81ee-bd7cb04b43e9','次韵晁仲二同倉使遊靈巖','韓淲','宋','宋诗','song-poetry','','[]','使華春入梵王宮，仿彿工顰在眼中。',64,'全唐诗/poet.song.177000.json','["使華春入梵王宮，仿彿工顰在眼中。", "邂逅五湖應自適，縱橫七國漫爭雄。", "一時賓從歡無極，千古興亡恨莫窮。", "空鎖靈巖舊蹤跡，畫船贏得滿篙風。"]'),
('9943c945-f4bb-4965-be8c-b5f252fc8330','同昌甫遊瑞應峰一宿次韵','韓淲','宋','宋诗','song-poetry','','[]','十載嘗同望此山，雅懷幽意頗相關。',64,'全唐诗/poet.song.177000.json','["十載嘗同望此山，雅懷幽意頗相關。", "豈期苔竹隨公去，應笑錢塘見我還。", "洗夢唐人詩句裏，驚霄前哲石碑間。", "秋風古寺一盃酒，老覺心情只欲閒。"]'),
('71c12607-faa5-4a13-834b-10ddf291b672','過南豅','韓淲','宋','宋诗','song-poetry','','[]','艤舟溪岸入山居，步穩秋原木影疎。',64,'全唐诗/poet.song.177000.json','["艤舟溪岸入山居，步穩秋原木影疎。", "盡日極知無市井，此身終是樂樵漁。", "鳥聲自占庭前樹，嵐氣時侵案上書。", "尊酒故人情味別，留連應喜到門初。"]'),
('664c1235-19e8-43a6-9f66-5ae2c771b323','自永豐玉山回宿南豅','韓淲','宋','宋诗','song-poetry','','[]','章泉風日來時路，烟雨南豅歸去時。',64,'全唐诗/poet.song.177000.json','["章泉風日來時路，烟雨南豅歸去時。", "已過重陽猶菊蘂，又將十月忽梅枝。", "周遊放浪家家酒，展轉流連處處詩。", "信道山間深更好，儘閒尤與老相宜。"]'),
('1ef1e752-12ed-4046-b48a-56de05d271c7','初六日歸汎南豅已三鼓矣','韓淲','宋','宋诗','song-poetry','','[]','乍凉天氣翠煙霏，多少林花露未晞。',64,'全唐诗/poet.song.177000.json','["乍凉天氣翠煙霏，多少林花露未晞。", "十里幽香秋醉去，一溪新月夜吟歸。", "豈無僧舍居高遠，定有人家在隠微。", "夜半鶴鳴猿嘯冷，灘聲鳴遶釣魚磯。"]'),
('5763b99d-1682-40b7-81d7-3d3a06177d39','二十六日送曾守遇伯輝於南豅','韓淲','宋','宋诗','song-poetry','','[]','周瑜隠地春曾住，秋以爲期玉斗遊。',64,'全唐诗/poet.song.177000.json','["周瑜隠地春曾住，秋以爲期玉斗遊。", "只道參差無此適，要知拓落有何謀。", "經行二姓忽相聚，輾轉一身終自由。", "四樹木樨花正發，幽香隨處且忘憂。"]'),
('a9563eea-e950-4ada-96de-040447148a81','晦日衝雨過同官趙大小樓眺望江山','韓淲','宋','宋诗','song-poetry','','[]','一樓煙雨更橫江，吳越蒼山入混茫。',64,'全唐诗/poet.song.177000.json','["一樓煙雨更橫江，吳越蒼山入混茫。", "霽色未分無遠樹，潮聲初過有歸艎。", "檐楹高處閒登眺，市井中間任迫忙。", "日日癡兒了官事，暫時相賞試持觴。"]'),
('7d17c19e-7377-4a16-af7b-84fb9b38f577','登一杯亭  其一','韓淲','宋','宋诗','song-poetry','','[]','當年丞相一登臨，酒畔崢嶸萬古心。',64,'全唐诗/poet.song.177000.json','["當年丞相一登臨，酒畔崢嶸萬古心。", "重整乾坤歸廟社，却留歲月在山林。", "荒尋野閣甘棠蔽，名占高臺峴首深。", "見說治中新築就，肯堂三歎有遺音。"]'),
('8c149a23-6d0d-4ba3-9771-9a9113b262ab','登一杯亭  其二','韓淲','宋','宋诗','song-poetry','','[]','旄麾誰不典方州，何事邦人記昔遊。',64,'全唐诗/poet.song.177000.json','["旄麾誰不典方州，何事邦人記昔遊。", "時令縱非名轉盛，靈山如畫水西流。", "吾儕只得詩模倣，爾輩焉知酒拍浮。", "却憶環滁最佳處，醉翁亭子至今留。"]'),
('6793d2c5-72d6-43f4-b237-3fc088eecc6d','飯後乘日過東家','韓淲','宋','宋诗','song-poetry','','[]','霜晴已是探梅時，野趣軒茶更合詩。',64,'全唐诗/poet.song.177000.json','["霜晴已是探梅時，野趣軒茶更合詩。", "才出門來唯獨往，不看山去亦何知。", "試聽石瀨無塵滓，如覺林梢有好枝。", "心與眼明知興熟，朗吟惟老轉相宜。"]'),
('21f5bf3c-900e-4d21-9d83-6a583297773c','十三夜携杯浮橋看月','韓淲','宋','宋诗','song-poetry','','[]','一輪秋月到天心，此夜全無雲片侵。',64,'全唐诗/poet.song.177000.json','["一輪秋月到天心，此夜全無雲片侵。", "雅靜每於閒後見，孤高難向閙中尋。", "漸圓漸好形神正，愈大愈明精氣深。", "最是溪間波影裏，金光摇動玉沉沉。"]'),
('13513d18-dda0-42f9-a770-47bd5559db0f','十一日郡守飯靈山閣夜坐新浮橋月中','韓淲','宋','宋诗','song-poetry','','[]','使君襟抱中秋月，閒飲賓僚醉野人。',64,'全唐诗/poet.song.177000.json','["使君襟抱中秋月，閒飲賓僚醉野人。", "倒載去尋高閣古，落成未試一橋新。", "山城明歲當回首，雲路茲時好發身。", "喚起嫦娥駕輪玉，不知何處著纖塵。"]'),
('77e47b60-d3dd-4b86-9201-4bcee55f5ed7','十三日方齋  其一','韓淲','宋','宋诗','song-poetry','','[]','麥秋蠶月雨收晴，城郭山林到處行。',64,'全唐诗/poet.song.177000.json','["麥秋蠶月雨收晴，城郭山林到處行。", "不是惜春尋小醉，忍教投老轉多情。", "啼鵑渺渺翻梁燕，夢蝶蘧蘧出谷鶑。", "記取招邀一杯酒，與君宜戲也宜驚。"]'),
('bbda7027-7e8a-4a34-adfa-a907ab9b87c2','十三日方齋  其二','韓淲','宋','宋诗','song-poetry','','[]','捉得春風住三日，明年依舊百花香。',64,'全唐诗/poet.song.177000.json','["捉得春風住三日，明年依舊百花香。", "酒盃滿後同誰飲，詩句成時只自狂。", "金縷聲銷非幻景，玉華煙散任仙鄉。", "靈山翠滴冰溪水，只這閒情話更長。"]'),
('9e829bd6-4fba-464b-8177-f4ea635e9551','上乘寺','韓淲','宋','宋诗','song-poetry','','[]','禾黍登場秋已深，暮天寒日起層陰。',64,'全唐诗/poet.song.177000.json','["禾黍登場秋已深，暮天寒日起層陰。", "不論世路有夷險，但覺此心無古今。", "黄帽青鞋聊自適，高山流水付知音。", "解鞍野寺黄昏後，犬吠疎籬鴉滿林。"]'),
('4f343f5d-96c1-4da8-8c21-5028270bb265','上富春灘','韓淲','宋','宋诗','song-poetry','','[]','喚得扁舟一葉輕，釣臺波上夕陽明。',64,'全唐诗/poet.song.177000.json','["喚得扁舟一葉輕，釣臺波上夕陽明。", "固宜煙鳥知人意，只爲雲山識我情。", "篷日午前雖較熱，帆風晚後却尤清。", "吾廬更在楚溪口，歸卧北窗聽竹聲。"]'),
('453f0838-6709-4aaf-be11-49c86922a12c','十六日至章泉水','韓淲','宋','宋诗','song-poetry','','[]','山愈深時地愈高，春尋積李散崇桃。',64,'全唐诗/poet.song.177000.json','["山愈深時地愈高，春尋積李散崇桃。", "林廬但覺無塵話，田里那知有載醪。", "華髮蒼顔俱老大，清泉白石更周遭。", "常年每厭居城郭，時復從翁敢憚勞。"]'),
('d7f3eeef-daba-4a45-a30a-bf2501bdef03','溪行','韓淲','宋','宋诗','song-poetry','','[]','突兀荒荒漫挈瓶，泓澄窈窈且揚舲。',64,'全唐诗/poet.song.177000.json','["突兀荒荒漫挈瓶，泓澄窈窈且揚舲。", "隔山鷄犬三家聚，近水魚蝦一岸腥。", "說夢休誇巫峽賦，移文何愧草堂靈。", "交遊少得親相識，臨眺多爲舊所經。"]'),
('6a197286-2f87-4ddc-b428-a46299f6be48','携秉垓千散步','韓淲','宋','宋诗','song-poetry','','[]','濕雲收動碧山空，松葉桐花日影中。',64,'全唐诗/poet.song.177000.json','["濕雲收動碧山空，松葉桐花日影中。", "開盡一軒無曲折，掃除三徑有幽通。", "耘耔不厭農田雨，流憇居多野水風。", "解斷浮航塵跡少，葦間何地覓漁翁。"]'),
('b2ba73ba-bb92-4945-a5ca-4c7f5b437f62','月夜間自東樓溪遊甚適寄吳推趙將','韓淲','宋','宋诗','song-poetry','','[]','滿船載得高溪月，吹落東樓萬里風。',64,'全唐诗/poet.song.177000.json','["滿船載得高溪月，吹落東樓萬里風。", "岸上未收燈火處，城頭初動角聲中。", "撫懷定自閒相覓，抵掌還知醉亦同。", "三百年來無此作，謫仙飛過水晶宮。"]'),
('199a550e-952f-46de-8dcb-0f9705a609ba','過冠秋','韓淲','宋','宋诗','song-poetry','','[]','來年要作冠秋詩，今日花時合自知。',64,'全唐诗/poet.song.177000.json','["來年要作冠秋詩，今日花時合自知。", "我覺爲吟真老醜，人疑取酒若兒嬉。", "收香宿雨初浮蘂，弄色晴風定滿枝。", "莫道空山漫遺句，傳家垂後有深規。"]'),
('17be59e4-10ec-4fac-8c2d-32c214d4ea50','同世昌尋春','韓淲','宋','宋诗','song-poetry','','[]','春風清曉尚微霜，近午寒收日漸長。',64,'全唐诗/poet.song.177000.json','["春風清曉尚微霜，近午寒收日漸長。", "步穩路平山滌靄，眼明溪淨水生光。", "珍禽啼鳥猶能樂，野草閑花亦自香。", "回首紅塵是城市，林間詩酒試平章。"]'),
('c20c4f47-7892-427a-a035-f532b79b1333','晚寒散步澗上','韓淲','宋','宋诗','song-poetry','','[]','支吾老態懶成言，勃窣蹣跚試出門。',64,'全唐诗/poet.song.177000.json','["支吾老態懶成言，勃窣蹣跚試出門。", "脚底路回籬外屋，眼前梅發澗邊村。", "雪霜欲下天回互，煙霧不收山吐吞。", "歸到寒窗卷書坐，地爐深火過黄昏。"]'),
('c312c03f-02e2-4a99-a3b1-c1deecb2706f','晚立澗旁','韓淲','宋','宋诗','song-poetry','','[]','水邊獨立看黄昏，梅蘂能銷客子魂。',64,'全唐诗/poet.song.177000.json','["水邊獨立看黄昏，梅蘂能銷客子魂。", "淡靄清鐘知隔寺，微風幽笛是前村。", "牛羊徑路生寒色，鵝鴨陂池裂凍痕。", "一種清懷幾多景，鴉棲密木更翩翻。"]'),
('864a365d-95ea-470e-9590-5f3e48a2ac39','溪上行至傅庵蹊間崩石險澀幾踣','韓淲','宋','宋诗','song-poetry','','[]','無酒無詩只意行，水邊林下偶然晴。',64,'全唐诗/poet.song.177000.json','["無酒無詩只意行，水邊林下偶然晴。", "緩移野步微欹側，細比凡心儘曠平。", "白髮去來同遯跡，青春交往定蜚英。", "小庵供佛安禪地，只合僧家一味清。"]'),
('182b3b98-81a4-493d-af5f-acf3fa56831a','納凉濠上','韓淲','宋','宋诗','song-poetry','','[]','夕陽偏占綠荷風，夏氣浮凉酒滿鍾。',64,'全唐诗/poet.song.177000.json','["夕陽偏占綠荷風，夏氣浮凉酒滿鍾。", "人勝不譏吾拓落，身閒何恨爾從容。", "喚回今古風騷體，消得乾坤運化功。", "只是靈山照冰水，莫教憂樂係窮通。"]'),
('b53c316a-85c6-4af9-b617-2e94f08b8642','同吳永伯行田宿小寺','韓淲','宋','宋诗','song-poetry','','[]','冉冉春煙山半昏，遠林荒草際斜曛。',64,'全唐诗/poet.song.177000.json','["冉冉春煙山半昏，遠林荒草際斜曛。", "人家幾點望中見，雞犬數聲何處聞。", "不奈客愁驚晚歲，空餘詩思入行雲。", "青松影下歸來路，野寺對牀還醉醺。"]'),
('af37516b-fda8-426c-ad46-433434a5cc63','昌甫同汎舟歸宿澗房','韓淲','宋','宋诗','song-poetry','','[]','山陰溪曲古何年，今日南豅棹復旋。',64,'全唐诗/poet.song.177000.json','["山陰溪曲古何年，今日南豅棹復旋。", "夾岸暖風吹麥秀，釣竿清浪出魚鮮。", "諸兒挈飲能迎勞，耆舊談圍信解懸。", "放溜歸來月初夜，林間應獨與翁便。"]'),
('206bf8b0-4aa0-4979-910d-7907a8947f38','九日登跨鶴臺有懷  其一','韓淲','宋','宋诗','song-poetry','','[]','山頭跨鶴舊登臺，今日那知我獨來。',64,'全唐诗/poet.song.177000.json','["山頭跨鶴舊登臺，今日那知我獨來。", "憶昨儒先追杖屨，因嘗鄉老共尊罍。", "呼兒且伴閑身健，好客何由笑口開。", "落魄使君王道甫，幾回和月醉崔嵬。"]'),
('28a465d4-0893-472a-9bd4-e3ddebe78170','九日登跨鶴臺有懷  其二','韓淲','宋','宋诗','song-poetry','','[]','西風吹我上危臺，鶴駕仙人跨海來。',64,'全唐诗/poet.song.177000.json','["西風吹我上危臺，鶴駕仙人跨海來。", "雖少菊花猶破帽，既多楓落合傾罍。", "玉溪凈瀉秋容淡，靈岫森羅夕照開。", "老去悲傷易如許，人心何苦自崔嵬。"]'),
('99f72963-4540-4dc9-b951-e7702aa79758','倚樓','韓淲','宋','宋诗','song-poetry','','[]','湖山咫尺懶追遊，獨倚危樓已白頭。',64,'全唐诗/poet.song.177000.json','["湖山咫尺懶追遊，獨倚危樓已白頭。", "初夏風光還荏苒，乍晴雲物正飛浮。", "長吟自可千篇在，小醉誰能萬事休。", "轂擊肩摩爭輦路，不知虛度幾春秋。"]'),
('c2790f6d-c399-4847-b292-a3795bdfdd2c','鋤治山椒可置胡牀遠覽','韓淲','宋','宋诗','song-poetry','','[]','荒穢誅鋤山徑開，更於高爽敞平臺。',64,'全唐诗/poet.song.177000.json','["荒穢誅鋤山徑開，更於高爽敞平臺。", "眼明庶以閑登眺，步穩因之數往來。", "載斸坡陀曾樹蕙，緣通茂密待移梅。", "城南自是多幽處，一曲今藏古澗隈。"]');
